diffs.replacement:
import React, { useState, useMemo, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Staff, StaffAttendance, WageType, Transaction } from '../types';

const StaffManager: React.FC = () => {
  const { state, addStaff, updateStaff, deleteStaff, logStaffAttendance, addTransaction } = useFinance();
  const [showAddStaff, setShowAddStaff] = useState(false);
  const [editingStaffId, setEditingStaffId] = useState<string | null>(null);
  const [selectedStaffId, setSelectedStaffId] = useState<string | null>(null);
  const [viewDate, setViewDate] = useState(new Date());
  const [showSettleModal, setShowSettleModal] = useState<Staff | null>(null);
  const [swapOverride, setSwapOverride] = useState<{ day: number, dateStr: string } | null>(null);
  const [selectedDay, setSelectedDay] = useState<number>(new Date().getDate());

  const [settlementMode, setSettlementMode] = useState<{ id: string, type: 'bank' | 'card' | 'wallet' | 'liability' } | null>(null);
  const [isRecordingSuccess, setIsRecordingSuccess] = useState(false);

  const [staffFormData, setStaffFormData] = useState({ 
    name: '', role: 'Maid', customRole: '', baseRate: '500', wageType: 'Daily' as WageType,
    joiningDate: new Date().toISOString().split('T')[0], exitDate: ''
  });

  const [swapType, setSwapType] = useState<'OWN' | 'PROXY' | 'BOTH' | 'REMOVE'>('OWN');
  const [proxyRate, setProxyRate] = useState<string>('0');

  const currency = state.profile.currency;
  const staffList = state.staff || [];
  const selectedStaff = staffList.find(s => s.id === selectedStaffId);

  useEffect(() => {
    if (!selectedStaffId && staffList.length > 0) {
      setSelectedStaffId(staffList[0].id);
    }
  }, [staffList, selectedStaffId]);

  const availableAccounts = useMemo(() => {
    const list: { id: string, name: string, type: 'bank' | 'card' | 'wallet' | 'liability' }[] = [];
    state.banks.forEach(b => list.push({ id: b.id, name: b.name, type: 'bank' }));
    state.wallets.forEach(w => list.push({ id: w.id, name: w.name, type: 'wallet' }));
    state.cards.forEach(c => list.push({ id: c.id, name: c.lenderName, type: 'card' }));
    return list;
  }, [state]);

  const daysInMonth = useMemo(() => {
    return new Date(viewDate.getFullYear(), viewDate.getMonth() + 1, 0).getDate();
  }, [viewDate]);

  const monthName = viewDate.toLocaleString('default', { month: 'long', year: 'numeric' });

  const resetForm = () => {
    setStaffFormData({
      name: '', role: 'Maid', customRole: '', baseRate: '500', wageType: 'Daily',
      joiningDate: new Date().toISOString().split('T')[0], exitDate: ''
    });
    setEditingStaffId(null);
  };

  const getAttendanceStatusForDay = (staff: Staff, dateStr: string) => {
    const manualLog = staff.attendance?.find(a => a.date === dateStr);
    if (manualLog) return manualLog;

    const today = new Date().toISOString().split('T')[0];
    const joining = staff.joiningDate;
    const exit = staff.exitDate;

    // Automatic default for past dates within tenure
    if (dateStr >= joining && (!exit || dateStr <= exit) && dateStr <= today) {
       let rate = staff.baseRate;
       if (staff.wageType === 'Monthly') {
          const d = new Date(dateStr);
          rate = staff.baseRate / new Date(d.getFullYear(), d.getMonth() + 1, 0).getDate();
       }
       return { status: 'Present', rate: rate, isSubstitute: false, isDefault: true };
    }
    return { status: 'None', rate: 0, isSubstitute: false, isDefault: true };
  };

  const openSwapModal = (day: number) => {
    const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSwapOverride({ day, dateStr });
  };

  const handleCommitSwap = () => {
    if (!selectedStaff || !swapOverride) return;
    if (swapType === 'REMOVE') {
      logStaffAttendance(selectedStaff.id, { date: swapOverride.dateStr, status: 'None' });
    } else {
      let finalRate = swapType === 'OWN' ? Number(selectedStaff.baseRate) : (swapType === 'PROXY' ? Number(proxyRate) : Number(selectedStaff.baseRate) + Number(proxyRate));
      logStaffAttendance(selectedStaff.id, {
        date: swapOverride.dateStr, status: 'Present', rate: finalRate, isSubstitute: swapType !== 'OWN'
      });
    }
    setSwapOverride(null);
  };

  const calculateMonthlyTotal = (staff: Staff) => {
    let total = 0;
    for (let i = 1; i <= daysInMonth; i++) {
      const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(i).padStart(2, '0')}`;
      const log = getAttendanceStatusForDay(staff, dateStr);
      if (log.status === 'Present') total += log.rate;
    }
    return total;
  };

  const handleSettle = (staff: Staff) => {
    if (!settlementMode) return alert("Select target account first.");
    const amount = calculateMonthlyTotal(staff);
    if (amount <= 0) return alert("No dues to settle.");

    const tx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'Expense',
      amount: amount,
      nature: staff.name,
      description: `Wages payout for ${monthName}`,
      accountId: settlementMode.id,
      accountType: settlementMode.type,
      date: new Date().toISOString().split('T')[0],
      status: 'active'
    };

    addTransaction(tx);
    setIsRecordingSuccess(true);
    setSettlementMode(null);
  };

  const handleAttendanceToggle = (targetStatus: 'Present' | 'Absent') => {
    if (!selectedStaff) return;
    const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(selectedDay).padStart(2, '0')}`;
    const currentLog = getAttendanceStatusForDay(selectedStaff, dateStr);

    // Toggle logic: If manually set and user clicks same status, clear it to return to default
    if (!(currentLog as any).isDefault && currentLog.status === targetStatus) {
      logStaffAttendance(selectedStaff.id, { date: dateStr, status: 'None' });
      return;
    }

    let rate = targetStatus === 'Present' ? selectedStaff.baseRate : 0;
    if (targetStatus === 'Present' && selectedStaff.wageType === 'Monthly') {
      const d = new Date(dateStr);
      rate = selectedStaff.baseRate / new Date(d.getFullYear(), d.getMonth() + 1, 0).getDate();
    }

    logStaffAttendance(selectedStaff.id, { 
      date: dateStr, 
      status: targetStatus, 
      rate: rate, 
      isSubstitute: false 
    });
  };

  const selectedDateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(selectedDay).padStart(2, '0')}`;
  const selectedLog = selectedStaff ? getAttendanceStatusForDay(selectedStaff, selectedDateStr) : null;

  return (
    <div className="h-[calc(100dvh-120px)] flex flex-col md:flex-row gap-6 animate-in fade-in duration-500 overflow-hidden">
      {/* LEFT: PERSONNEL REGISTRY */}
      <div className="w-full md:w-80 flex flex-col bg-white border border-slate-200 rounded-[2.5rem] overflow-hidden shadow-sm">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Personnel Registry</h3>
          <button onClick={() => { resetForm(); setShowAddStaff(true); }} className="w-8 h-8 flex items-center justify-center bg-indigo-600 text-white rounded-xl text-sm shadow-lg shadow-indigo-100 hover:scale-110 transition-transform">+</button>
        </div>
        <div className="flex-1 overflow-y-auto no-scrollbar">
          {staffList.map(s => (
            <div 
              key={s.id} 
              onClick={() => setSelectedStaffId(s.id)} 
              className={`p-5 flex items-center gap-4 cursor-pointer transition-all border-l-4 ${selectedStaffId === s.id ? 'bg-indigo-50 border-l-indigo-600' : 'hover:bg-slate-50 border-l-transparent'}`}
            >
              <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-xl ${selectedStaffId === s.id ? 'bg-white text-indigo-600 shadow-sm' : 'bg-slate-100 text-slate-400'}`}>👤</div>
              <div className="flex-1 min-w-0">
                <p className="text-sm font-black text-slate-800 uppercase truncate tracking-tight">{s.name}</p>
                <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mt-0.5">{s.role}</p>
              </div>
            </div>
          ))}
          {staffList.length === 0 && (
            <div className="p-12 text-center flex flex-col items-center gap-4">
               <div className="text-4xl opacity-20">👥</div>
               <p className="text-[10px] font-black text-slate-300 uppercase tracking-widest italic">Registry Standing By</p>
            </div>
          )}
        </div>
      </div>

      {/* RIGHT: WORKSPACE - STAFF MANAGEMENT SECTION */}
      <div className="flex-1 flex flex-col bg-white border border-slate-200 rounded-[2.5rem] overflow-hidden shadow-sm">
        {selectedStaff ? (
          <>
            {/* WORKSPACE HEADER */}
            <div className="p-6 md:p-8 border-b border-slate-100 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 bg-white shrink-0">
              <div className="flex items-center gap-5">
                <div className="w-16 h-16 bg-slate-900 text-white rounded-3xl flex items-center justify-center text-2xl font-black shadow-xl">
                  {selectedStaff.name.charAt(0)}
                </div>
                <div>
                   <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tighter leading-none mb-1">Staff Management</h2>
                   <div className="flex items-center gap-3">
                      <p className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.15em]">{selectedStaff.name} • {selectedStaff.role}</p>
                      <button onClick={() => { 
                        setEditingStaffId(selectedStaff.id); 
                        setStaffFormData({ 
                          ...staffFormData, 
                          name: selectedStaff.name, 
                          role: selectedStaff.role,
                          baseRate: String(selectedStaff.baseRate),
                          wageType: selectedStaff.wageType
                        }); 
                        setShowAddStaff(true); 
                      }} className="w-6 h-6 rounded-lg bg-slate-100 flex items-center justify-center text-[10px] hover:bg-indigo-50 hover:text-indigo-600 transition-colors">✎</button>
                   </div>
                </div>
              </div>

              <div className="flex items-center gap-2 bg-slate-50 p-1.5 rounded-[1.5rem] border border-slate-100 shadow-inner">
                 <button onClick={() => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() - 1))} className="w-10 h-10 flex items-center justify-center hover:bg-white rounded-xl text-slate-400 transition-all active:scale-90 shadow-sm border border-transparent hover:border-slate-100">←</button>
                 <span className="px-5 text-[10px] font-black uppercase tracking-[0.25em] text-slate-800">{monthName}</span>
                 <button onClick={() => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() + 1))} className="w-10 h-10 flex items-center justify-center hover:bg-white rounded-xl text-slate-400 transition-all active:scale-90 shadow-sm border border-transparent hover:border-slate-100">→</button>
              </div>
            </div>

            {/* CALENDAR VIEW GRID */}
            <div className="flex-1 overflow-hidden p-4 md:p-6 bg-slate-50/40">
              <div className="h-full border border-slate-200 rounded-[2rem] bg-white shadow-xl overflow-hidden flex flex-col">
                <div className="grid grid-cols-7 border-b border-slate-100 shrink-0 bg-slate-50/50">
                  {['Sun','Mon','Tue','Wed','Thu','Fri','Sat'].map(d => (
                    <div key={d} className="py-4 text-center text-[8px] font-black text-slate-400 uppercase tracking-widest">{d}</div>
                  ))}
                </div>
                <div className="flex-1 grid grid-cols-7 auto-rows-fr">
                  {Array.from({ length: new Date(viewDate.getFullYear(), viewDate.getMonth(), 1).getDay() }).map((_, i) => (
                    <div key={`empty-${i}`} className="border-r border-b border-slate-50 bg-slate-50/10"></div>
                  ))}
                  {Array.from({ length: daysInMonth }).map((_, i) => {
                    const day = i + 1;
                    const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
                    const log = getAttendanceStatusForDay(selectedStaff, dateStr);
                    const isActive = selectedDay === day;

                    return (
                      <div 
                        key={day} 
                        onClick={() => setSelectedDay(day)}
                        className={`group flex flex-col items-center justify-center border-r border-b border-slate-50 cursor-pointer transition-all relative ${isActive ? 'bg-indigo-50/40 ring-4 ring-indigo-600 ring-inset z-10' : 'hover:bg-slate-50/60'}`}
                      >
                        <span className={`text-sm font-black mb-1 transition-transform group-hover:scale-110 ${isActive ? 'text-indigo-600' : 'text-slate-400'}`}>{day}</span>

                        <div className="h-4 flex items-center">
                          {log.status === 'Present' ? (
                            <div className="flex items-center gap-1">
                               <div className={`w-1.5 h-1.5 rounded-full ${log.isSubstitute ? 'bg-amber-400' : 'bg-emerald-500'}`}></div>
                               <span className={`text-[7px] font-black uppercase tracking-tight ${log.isSubstitute ? 'text-amber-500' : 'text-emerald-500'}`}>{log.isSubstitute ? 'Swap' : 'Present'}</span>
                            </div>
                          ) : log.status === 'Absent' ? (
                            <div className="flex items-center gap-1">
                               <div className="w-1.5 h-1.5 rounded-full bg-rose-400"></div>
                               <span className="text-[7px] font-black text-rose-400 uppercase tracking-tight">Absent</span>
                            </div>
                          ) : null}
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>

            {/* INTERACTIVE ACTION CENTER */}
            <div className="p-6 md:p-8 border-t border-slate-100 bg-white shrink-0">
               <div className="flex flex-col lg:flex-row items-center gap-8">
                  {/* Status Selection Buttons */}
                  <div className="flex-1 grid grid-cols-3 gap-4 w-full">
                     <button 
                       onClick={() => handleAttendanceToggle('Present')}
                       className={`p-5 rounded-[1.5rem] border-2 flex flex-col items-center justify-center gap-1.5 transition-all active:scale-95 ${selectedLog?.status === 'Present' && !selectedLog.isSubstitute ? 'bg-emerald-500 border-emerald-600 text-white shadow-xl' : 'bg-slate-50 border-slate-100 text-slate-400 hover:bg-emerald-50 hover:text-emerald-600 hover:border-emerald-200'}`}
                     >
                        <span className="text-xl">✅</span>
                        <span className="text-[10px] font-black uppercase tracking-[0.2em]">Mark Present</span>
                     </button>
                     <button 
                       onClick={() => handleAttendanceToggle('Absent')}
                       className={`p-5 rounded-[1.5rem] border-2 flex flex-col items-center justify-center gap-1.5 transition-all active:scale-95 ${selectedLog?.status === 'Absent' ? 'bg-rose-500 border-rose-600 text-white shadow-xl' : 'bg-slate-50 border-slate-100 text-slate-400 hover:bg-rose-50 hover:text-rose-600 hover:border-rose-200'}`}
                     >
                        <span className="text-xl">❌</span>
                        <span className="text-[10px] font-black uppercase tracking-[0.2em]">Mark Absent</span>
                     </button>
                     <button 
                       onClick={() => openSwapModal(selectedDay)}
                       className={`p-5 rounded-[1.5rem] border-2 flex flex-col items-center justify-center gap-1.5 transition-all active:scale-95 ${selectedLog?.isSubstitute ? 'bg-amber-500 border-amber-600 text-white shadow-xl' : 'bg-slate-50 border-slate-100 text-slate-400 hover:bg-amber-50 hover:text-amber-600 hover:border-amber-200'}`}
                     >
                        <span className="text-xl">🔄</span>
                        <span className="text-[10px] font-black uppercase tracking-[0.2em]">Mark Swap</span>
                     </button>
                  </div>

                  {/* Financial Settlement Overview */}
                  <div className="lg:w-80 p-6 bg-slate-900 rounded-[2.5rem] text-white flex items-center justify-between gap-6 shadow-2xl relative overflow-hidden group">
                     <div className="absolute top-0 right-0 p-4 text-4xl opacity-5 font-black group-hover:rotate-12 transition-transform">PAY</div>
                     <div className="relative z-10 min-w-0">
                        <p className="text-[9px] font-black text-indigo-400 uppercase tracking-widest mb-1.5">Monthly Liability</p>
                        <p className="text-3xl font-black tracking-tighter truncate">{formatCurrency(calculateMonthlyTotal(selectedStaff), currency).split('.')[0]}</p>
                     </div>
                     <button onClick={() => setShowSettleModal(selectedStaff)} className="px-6 py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-700 transition-all active:scale-95 shadow-lg shadow-indigo-500/20 relative z-10">Settle Dues</button>
                  </div>
               </div>
            </div>
          </>
        ) : (
          <div className="h-full flex flex-col items-center justify-center p-20 text-center bg-slate-50/30">
             <div className="w-24 h-24 bg-white rounded-[2rem] flex items-center justify-center text-5xl mb-8 shadow-xl border border-slate-100 animate-float">📊</div>
             <h4 className="text-2xl font-black text-slate-800 uppercase tracking-tighter">Staff Management Hub</h4>
             <p className="text-[11px] font-black text-slate-400 uppercase mt-4 tracking-widest leading-loose max-w-sm">
               Initialize the registry to start logging attendance and managing monthly settlements.
             </p>
             <button onClick={() => { resetForm(); setShowAddStaff(true); }} className="mt-10 px-8 py-4 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-[0.25em] shadow-xl hover:bg-black transition-all active:scale-95"> Onboard New Personnel </button>
          </div>
        )}
      </div>

      {/* MODALS: SWAP, ADD STAFF, SETTLEMENT */}
      {swapOverride && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/70 backdrop-blur-xl p-4">
           <div className="bg-white w-full max-w-md rounded-[3rem] p-10 shadow-2xl animate-in zoom-in-95 duration-200 border border-slate-200">
              <div className="flex justify-between items-center mb-10">
                 <div>
                   <h3 className="text-2xl font-black text-slate-800 uppercase tracking-tighter">Personnel Swap</h3>
                   <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Configure duty replacement logic</p>
                 </div>
                 <button onClick={() => setSwapOverride(null)} className="text-slate-300 hover:text-slate-800 text-2xl font-black">✕</button>
              </div>

              <div className="space-y-3">
                 {[
                   { id: 'OWN', label: 'Self Duty Override', desc: 'Standard personnel attendance', icon: '👤' },
                   { id: 'PROXY', label: 'Proxy Replacement', desc: 'Substitute personnel only', icon: '🔄' },
                   { id: 'BOTH', label: 'Double Shift Log', desc: 'Both primary and substitute', icon: '⭐' },
                   { id: 'REMOVE', label: 'Void Audit Log', desc: 'Clear all entries for this day', icon: '🧹' }
                 ].map(t => (
                   <button key={t.id} onClick={() => setSwapType(t.id as any)} className={`w-full p-5 text-left rounded-2xl border-2 transition-all flex items-center gap-5 group ${swapType === t.id ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-slate-50 border-transparent hover:border-slate-200'}`}>
                      <span className={`text-2xl transition-transform group-hover:scale-110 ${swapType === t.id ? 'grayscale-0' : 'grayscale opacity-50'}`}>{t.icon}</span>
                      <div className="flex-1">
                        <p className={`text-[11px] font-black uppercase tracking-tight ${swapType === t.id ? 'text-white' : 'text-slate-800'}`}>{t.label}</p>
                        <p className={`text-[9px] font-bold uppercase mt-0.5 ${swapType === t.id ? 'text-white/60' : 'text-slate-400'}`}>{t.desc}</p>
                      </div>
                   </button>
                 ))}
              </div>

              <div className="flex gap-4 mt-12">
                 <button onClick={() => setSwapOverride(null)} className="flex-1 py-5 bg-slate-100 text-slate-400 font-black text-[10px] uppercase rounded-2xl">Cancel</button>
                 <button onClick={handleCommitSwap} className="flex-[2] py-5 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl shadow-indigo-200 active:scale-95 transition-all">Establish Swap</button>
              </div>
           </div>
        </div>
      )}

      {showAddStaff && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/70 backdrop-blur-xl p-4">
           <div className="bg-white w-full max-w-md rounded-[3rem] p-10 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200">
              <h3 className="text-2xl font-black text-slate-800 uppercase tracking-tighter mb-10">{editingStaffId ? 'Refine Registry' : 'Onboard Personnel'}</h3>
              <div className="space-y-8">
                 <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-3">Full Legal Identity</label>
                    <input autoFocus className="w-full p-5 bg-slate-50 border border-slate-200 rounded-2xl font-black text-sm uppercase outline-none focus:ring-8 focus:ring-indigo-600/5 transition-all" value={staffFormData.name} onChange={e => setStaffFormData({...staffFormData, name: e.target.value})} placeholder="e.g. RAJU KUMAR" />
                 </div>
                 <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-3">Wage Type</label><select className="w-full p-5 bg-slate-50 border border-slate-200 rounded-2xl font-black text-xs outline-none cursor-pointer appearance-none" value={staffFormData.wageType} onChange={e => setStaffFormData({...staffFormData, wageType: e.target.value as WageType})}><option value="Monthly">Monthly Basis</option><option value="Daily">Daily Basis</option></select></div>
                    <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-3">Personnel Role</label><select className="w-full p-5 bg-slate-50 border border-slate-200 rounded-2xl font-black text-xs outline-none cursor-pointer appearance-none" value={staffFormData.role} onChange={e => setStaffFormData({...staffFormData, role: e.target.value})}><option>Maid</option><option>Cook</option><option>Driver</option><option>House Help</option></select></div>
                 </div>
                 <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-3">Wage Benchmark ({currency})</label><input type="number" className="w-full p-8 bg-slate-900 text-white border border-slate-800 rounded-[2.5rem] font-black text-4xl text-center outline-none focus:ring-8 focus:ring-indigo-600/10 transition-all" value={staffFormData.baseRate} onChange={e => setStaffFormData({...staffFormData, baseRate: e.target.value})} /></div>
                 <div className="flex gap-4 pt-4">
                    <button onClick={() => { setShowAddStaff(false); resetForm(); }} className="flex-1 py-5 bg-slate-100 text-slate-400 font-black text-[10px] uppercase rounded-2xl">Abort</button>
                    <button onClick={() => {
                      if (!staffFormData.name.trim()) return alert("Identity required.");
                      const staffData: Staff = {
                        id: editingStaffId || Math.random().toString(36).substr(2, 9),
                        name: staffFormData.name, role: staffFormData.role,
                        baseRate: Number(staffFormData.baseRate), wageType: staffFormData.wageType,
                        attendance: editingStaffId ? (staffList.find(s => s.id === editingStaffId)?.attendance || []) : [],
                        joiningDate: staffFormData.joiningDate
                      };
                      if (editingStaffId) updateStaff(staffData); else addStaff(staffData);
                      setShowAddStaff(false); resetForm();
                    }} className="flex-[2] py-5 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Verify & Commit</button>
                 </div>
              </div>
           </div>
        </div>
      )}

      {showSettleModal && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/80 backdrop-blur-xl p-4">
           <div className="bg-white w-full max-w-md rounded-[4rem] p-12 shadow-2xl text-center animate-in zoom-in-95 border border-slate-200">
              {!isRecordingSuccess ? (
                <>
                  <div className="w-24 h-24 bg-emerald-50 text-emerald-600 rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner border border-emerald-100">💸</div>
                  <h3 className="text-3xl font-black text-slate-900 uppercase tracking-tighter mb-2">Wage Payout</h3>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-10">Verification of Dues for {monthName}</p>

                  <div className="p-10 bg-slate-50 rounded-[3rem] mb-10 shadow-inner border border-slate-100 relative group overflow-hidden">
                    <div className="absolute top-0 right-0 p-4 text-4xl opacity-5 font-black text-emerald-600">DUE</div>
                    <p className="text-6xl font-black text-emerald-600 tracking-tighter relative z-10">{formatCurrency(calculateMonthlyTotal(showSettleModal), currency).split('.')[0]}</p>
                    <p className="text-[10px] font-black text-slate-400 uppercase mt-4 tracking-widest relative z-10">Consolidated Audit Amount</p>
                  </div>

                  <div className="space-y-6">
                    <div className="space-y-2">
                       <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block text-left ml-4">Source Fund Vault</label>
                       <select className="w-full p-5 bg-slate-100 border border-slate-200 rounded-[1.5rem] font-black text-xs outline-none cursor-pointer appearance-none shadow-sm" value={settlementMode?.id || ''} onChange={(e) => {
                           const acc = availableAccounts.find(a => a.id === e.target.value);
                           if (acc) setSettlementMode(acc);
                         }}>
                         <option value="">Choose Payout Account</option>
                         {availableAccounts.map(acc => (<option key={acc.id} value={acc.id}>{acc.name} ({acc.type})</option>))}
                       </select>
                    </div>

                    <div className="flex flex-col gap-4">
                      <button onClick={() => handleSettle(showSettleModal)} className="w-full py-6 bg-indigo-600 text-white font-black text-xs uppercase rounded-[1.5rem] shadow-2xl shadow-indigo-100 hover:bg-indigo-700 transition-all active:scale-95">Execute Settlement</button>
                      <button onClick={() => { setShowSettleModal(null); setSettlementMode(null); }} className="w-full py-4 bg-slate-100 text-slate-400 font-black text-[10px] uppercase rounded-[1.5rem]">Abort Operation</button>
                    </div>
                  </div>
                </>
              ) : (
                <div className="animate-in zoom-in-95 duration-500 py-10">
                  <div className="w-28 h-28 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center text-6xl mx-auto mb-10 shadow-xl border border-emerald-200 animate-bounce">✅</div>
                  <h3 className="text-4xl font-black text-slate-900 uppercase tracking-tighter mb-4">Payout Posted</h3>
                  <p className="text-[11px] font-black text-slate-400 uppercase mb-16 tracking-widest">Transaction Verified & Logged in Ledger</p>
                  <button onClick={() => { setShowSettleModal(null); setIsRecordingSuccess(false); }} className="w-full py-6 bg-slate-900 text-white font-black text-xs uppercase rounded-[1.5rem] shadow-2xl hover:bg-black transition-all">Close Workspace</button>
                </div>
              )}
           </div>
        </div>
      )}
    </div>
  );
};

export default StaffManager;

import React, { useState, useMemo, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Staff, StaffAttendance, WageType, Transaction } from '../types';

const StaffManager: React.FC = () => {
  const { state, addStaff, updateStaff, deleteStaff, logStaffAttendance, addTransaction } = useFinance();
  const [showAddStaff, setShowAddStaff] = useState(false);
  const [editingStaffId, setEditingStaffId] = useState<string | null>(null);
  const [selectedStaffId, setSelectedStaffId] = useState<string | null>(null);
  const [viewDate, setViewDate] = useState(new Date());
  const [showSettleModal, setShowSettleModal] = useState<Staff | null>(null);
  const [swapOverride, setSwapOverride] = useState<{ day: number, dateStr: string } | null>(null);
  const [selectedDay, setSelectedDay] = useState<number>(new Date().getDate());

  const [settlementMode, setSettlementMode] = useState<{ id: string, name: string, type: 'bank' | 'card' | 'wallet' | 'liability' } | null>(null);
  const [isRecordingSuccess, setIsRecordingSuccess] = useState(false);

  const [staffFormData, setStaffFormData] = useState({ 
    name: '', role: 'Maid', customRole: '', baseRate: '500', wageType: 'Daily' as WageType,
    joiningDate: new Date().toISOString().split('T')[0], exitDate: ''
  });

  const [swapType, setSwapType] = useState<'OWN' | 'PROXY' | 'BOTH' | 'REMOVE'>('OWN');
  const [proxyRate, setProxyRate] = useState<string>('0');

  const currency = state.profile.currency;
  const staffList = state.staff || [];
  const selectedStaff = staffList.find(s => s.id === selectedStaffId);

  // Initialize selected staff if none selected
  useEffect(() => {
    if (!selectedStaffId && staffList.length > 0) {
      setSelectedStaffId(staffList[0].id);
    }
  }, [staffList, selectedStaffId]);

  const availableAccounts = useMemo(() => {
    const list: { id: string, name: string, type: 'bank' | 'card' | 'wallet' | 'liability' }[] = [];
    state.banks.forEach(b => list.push({ id: b.id, name: b.name, type: 'bank' }));
    state.wallets.forEach(w => list.push({ id: w.id, name: w.name, type: 'wallet' }));
    state.cards.forEach(c => list.push({ id: c.id, name: c.lenderName, type: 'card' }));
    return list;
  }, [state]);

  const daysInMonth = useMemo(() => {
    return new Date(viewDate.getFullYear(), viewDate.getMonth() + 1, 0).getDate();
  }, [viewDate]);

  const monthName = viewDate.toLocaleString('default', { month: 'long', year: 'numeric' });

  const resetForm = () => {
    setStaffFormData({
      name: '', role: 'Maid', customRole: '', baseRate: '500', wageType: 'Daily',
      joiningDate: new Date().toISOString().split('T')[0], exitDate: ''
    });
    setEditingStaffId(null);
  };

  const getAttendanceStatusForDay = (staff: Staff, dateStr: string) => {
    const manualLog = staff.attendance?.find(a => a.date === dateStr);
    if (manualLog) return manualLog;

    const today = new Date().toISOString().split('T')[0];
    const joining = staff.joiningDate;
    const exit = staff.exitDate;

    // Automatic default for past dates within tenure (Treat as present by default)
    if (dateStr >= joining && (!exit || dateStr <= exit) && dateStr <= today) {
       let rate = staff.baseRate;
       if (staff.wageType === 'Monthly') {
          const d = new Date(dateStr);
          rate = staff.baseRate / new Date(d.getFullYear(), d.getMonth() + 1, 0).getDate();
       }
       return { status: 'Present', rate: rate, isSubstitute: false, isDefault: true };
    }
    return { status: 'None', rate: 0, isSubstitute: false, isDefault: true };
  };

  const openSwapModal = (day: number) => {
    const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSwapOverride({ day, dateStr });
  };

  const handleCommitSwap = () => {
    if (!selectedStaff || !swapOverride) return;
    if (swapType === 'REMOVE') {
      logStaffAttendance(selectedStaff.id, { date: swapOverride.dateStr, status: 'None' });
    } else {
      let finalRate = swapType === 'OWN' ? Number(selectedStaff.baseRate) : (swapType === 'PROXY' ? Number(proxyRate) : Number(selectedStaff.baseRate) + Number(proxyRate));
      logStaffAttendance(selectedStaff.id, {
        date: swapOverride.dateStr, status: 'Present', rate: finalRate, isSubstitute: swapType !== 'OWN'
      });
    }
    setSwapOverride(null);
  };

  const calculateMonthlyTotal = (staff: Staff) => {
    let total = 0;
    for (let i = 1; i <= daysInMonth; i++) {
      const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(i).padStart(2, '0')}`;
      const log = getAttendanceStatusForDay(staff, dateStr);
      if (log.status === 'Present') total += log.rate;
    }
    return total;
  };

  const handleSettle = (staff: Staff) => {
    if (!settlementMode) return alert("Select target account first.");
    const amount = calculateMonthlyTotal(staff);
    if (amount <= 0) return alert("No dues to settle.");

    const tx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'Expense',
      amount: amount,
      nature: staff.name,
      description: `Wages payout for ${monthName}`,
      accountId: settlementMode.id,
      accountType: settlementMode.type,
      date: new Date().toISOString().split('T')[0],
      status: 'active'
    };

    addTransaction(tx);
    setIsRecordingSuccess(true);
    setSettlementMode(null);
  };

  const handleAttendanceToggle = (targetStatus: 'Present' | 'Absent') => {
    if (!selectedStaff) return;
    const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(selectedDay).padStart(2, '0')}`;
    const currentLog = getAttendanceStatusForDay(selectedStaff, dateStr);

    // Toggle logic: If user clicks the same status, clear manual log
    if (!(currentLog as any).isDefault && currentLog.status === targetStatus) {
      logStaffAttendance(selectedStaff.id, { date: dateStr, status: 'None' });
      return;
    }

    let rate = targetStatus === 'Present' ? selectedStaff.baseRate : 0;
    if (targetStatus === 'Present' && selectedStaff.wageType === 'Monthly') {
      const d = new Date(dateStr);
      rate = selectedStaff.baseRate / new Date(d.getFullYear(), d.getMonth() + 1, 0).getDate();
    }

    logStaffAttendance(selectedStaff.id, { 
      date: dateStr, 
      status: targetStatus, 
      rate: rate, 
      isSubstitute: false 
    });
  };

  const selectedDateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(selectedDay).padStart(2, '0')}`;
  const selectedLog = selectedStaff ? getAttendanceStatusForDay(selectedStaff, selectedDateStr) : null;

  return (
    <div className="h-[calc(100dvh-120px)] flex flex-col md:flex-row gap-6 animate-in fade-in duration-500 overflow-hidden font-sans">
      {/* LEFT SIDEBAR: PERSONNEL LIST */}
      <div className="w-full md:w-80 flex flex-col bg-white border border-slate-200 rounded-[2.5rem] overflow-hidden shadow-sm shrink-0">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Personnel Registry</h3>
          <button 
            onClick={() => { resetForm(); setShowAddStaff(true); }} 
            className="w-8 h-8 flex items-center justify-center bg-indigo-600 text-white rounded-xl text-sm shadow-lg shadow-indigo-100 hover:scale-110 transition-transform active:scale-95"
          >
            +
          </button>
        </div>
        <div className="flex-1 overflow-y-auto no-scrollbar py-2">
          {staffList.map(s => (
            <div 
              key={s.id} 
              onClick={() => setSelectedStaffId(s.id)} 
              className={`p-5 mx-3 mb-2 rounded-[1.5rem] flex items-center gap-4 cursor-pointer transition-all border ${selectedStaffId === s.id ? 'bg-indigo-600 border-indigo-700 text-white shadow-xl shadow-indigo-100' : 'bg-white border-slate-100 text-slate-800 hover:bg-slate-50'}`}
            >
              <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-xl shadow-sm ${selectedStaffId === s.id ? 'bg-white/20' : 'bg-slate-100'}`}>👤</div>
              <div className="flex-1 min-w-0">
                <p className={`text-[11px] font-black uppercase truncate tracking-tight ${selectedStaffId === s.id ? 'text-white' : 'text-slate-800'}`}>{s.name}</p>
                <p className={`text-[9px] font-black uppercase tracking-widest mt-0.5 ${selectedStaffId === s.id ? 'text-white/60' : 'text-slate-400'}`}>{s.role}</p>
              </div>
            </div>
          ))}
          {staffList.length === 0 && (
            <div className="p-12 text-center flex flex-col items-center gap-4">
               <div className="text-4xl opacity-20 grayscale">👥</div>
               <p className="text-[10px] font-black text-slate-300 uppercase tracking-widest italic leading-relaxed">Registry Standing By.<br/>Onboard Personnel to Begin Audit.</p>
            </div>
          )}
        </div>
      </div>

      {/* RIGHT WORKSPACE: CALENDAR & ATTENDANCE ACTIONS */}
      <div className="flex-1 flex flex-col bg-white border border-slate-200 rounded-[2.5rem] overflow-hidden shadow-sm">
        {selectedStaff ? (
          <>
            {/* WORKSPACE HEADER */}
            <div className="p-6 md:p-10 border-b border-slate-100 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 bg-white shrink-0">
              <div className="flex items-center gap-5">
                <div className="w-16 h-16 bg-slate-900 text-white rounded-3xl flex items-center justify-center text-2xl font-black shadow-2xl relative">
                  {selectedStaff.name.charAt(0)}
                  <div className="absolute -bottom-1 -right-1 w-6 h-6 bg-indigo-600 border-4 border-white rounded-full"></div>
                </div>
                <div>
                   <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tighter leading-none mb-1">Staff Management</h2>
                   <div className="flex items-center gap-3">
                      <p className="text-[11px] font-black text-indigo-600 uppercase tracking-[0.15em]">{selectedStaff.name} • {selectedStaff.role}</p>
                      <button onClick={() => { 
                        setEditingStaffId(selectedStaff.id); 
                        setStaffFormData({ 
                          ...staffFormData, 
                          name: selectedStaff.name, 
                          role: selectedStaff.role,
                          baseRate: String(selectedStaff.baseRate),
                          wageType: selectedStaff.wageType
                        }); 
                        setShowAddStaff(true); 
                      }} className="w-6 h-6 rounded-lg bg-slate-100 flex items-center justify-center text-[10px] hover:bg-indigo-50 hover:text-indigo-600 transition-colors">✎</button>
                   </div>
                </div>
              </div>

              <div className="flex items-center gap-2 bg-slate-50 p-1.5 rounded-full border border-slate-100 shadow-inner">
                 <button onClick={() => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() - 1))} className="w-10 h-10 flex items-center justify-center hover:bg-white rounded-full text-slate-400 transition-all active:scale-90 shadow-sm border border-transparent hover:border-slate-100">←</button>
                 <span className="px-6 text-[10px] font-black uppercase tracking-[0.25em] text-slate-800">{monthName}</span>
                 <button onClick={() => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() + 1))} className="w-10 h-10 flex items-center justify-center hover:bg-white rounded-full text-slate-400 transition-all active:scale-90 shadow-sm border border-transparent hover:border-slate-100">→</button>
              </div>
            </div>

            {/* MAIN CALENDAR GRID */}
            <div className="flex-1 overflow-hidden p-6 md:p-10 bg-slate-50/40">
              <div className="h-full border border-slate-200 rounded-[3rem] bg-white shadow-2xl overflow-hidden flex flex-col">
                <div className="grid grid-cols-7 border-b border-slate-100 shrink-0 bg-slate-50/50">
                  {['Sun','Mon','Tue','Wed','Thu','Fri','Sat'].map(d => (
                    <div key={d} className="py-5 text-center text-[9px] font-black text-slate-400 uppercase tracking-[0.2em]">{d}</div>
                  ))}
                </div>
                <div className="flex-1 grid grid-cols-7 auto-rows-fr">
                  {Array.from({ length: new Date(viewDate.getFullYear(), viewDate.getMonth(), 1).getDay() }).map((_, i) => (
                    <div key={`empty-${i}`} className="border-r border-b border-slate-50 bg-slate-50/20"></div>
                  ))}
                  {Array.from({ length: daysInMonth }).map((_, i) => {
                    const day = i + 1;
                    const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
                    const log = getAttendanceStatusForDay(selectedStaff, dateStr);
                    const isActive = selectedDay === day;

                    return (
                      <div 
                        key={day} 
                        onClick={() => setSelectedDay(day)}
                        className={`group flex flex-col items-center justify-center border-r border-b border-slate-50 cursor-pointer transition-all relative ${isActive ? 'bg-indigo-50 ring-4 ring-indigo-600/10 ring-inset z-10' : 'hover:bg-slate-50/60'}`}
                      >
                        <span className={`text-base font-black mb-1.5 transition-all ${isActive ? 'text-indigo-600 scale-125' : 'text-slate-400 group-hover:text-slate-800'}`}>{day}</span>

                        <div className="h-5 flex items-center justify-center">
                          {log.status === 'Present' ? (
                            <div className="flex items-center gap-1.5">
                               <div className={`w-2 h-2 rounded-full ${log.isSubstitute ? 'bg-amber-400 shadow-[0_0_8px_rgba(251,191,36,0.6)]' : 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.6)]'}`}></div>
                               <span className={`text-[8px] font-black uppercase tracking-tight hidden sm:block ${log.isSubstitute ? 'text-amber-500' : 'text-emerald-500'}`}>{log.isSubstitute ? 'Swap' : 'Active'}</span>
                            </div>
                          ) : log.status === 'Absent' ? (
                            <div className="flex items-center gap-1.5">
                               <div className="w-2 h-2 rounded-full bg-rose-400 shadow-[0_0_8px_rgba(244,63,94,0.6)]"></div>
                               <span className="text-[8px] font-black text-rose-400 uppercase tracking-tight hidden sm:block">Absent</span>
                            </div>
                          ) : null}
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>

            {/* ACTION CENTER STRIP */}
            <div className="p-8 md:p-10 border-t border-slate-100 bg-white shrink-0">
               <div className="flex flex-col lg:flex-row items-center gap-10">
                  {/* Status Selection Buttons */}
                  <div className="flex-1 grid grid-cols-3 gap-6 w-full">
                     <button 
                       onClick={() => handleAttendanceToggle('Present')}
                       className={`p-6 rounded-[2rem] border-2 flex flex-col items-center justify-center gap-2 transition-all active:scale-95 ${selectedLog?.status === 'Present' && !selectedLog.isSubstitute ? 'bg-emerald-500 border-emerald-600 text-white shadow-xl shadow-emerald-100' : 'bg-slate-50 border-slate-100 text-slate-400 hover:bg-emerald-50 hover:text-emerald-600 hover:border-emerald-200'}`}
                     >
                        <span className="text-2xl">✅</span>
                        <span className="text-[10px] font-black uppercase tracking-[0.25em]">Present</span>
                     </button>
                     <button 
                       onClick={() => handleAttendanceToggle('Absent')}
                       className={`p-6 rounded-[2rem] border-2 flex flex-col items-center justify-center gap-2 transition-all active:scale-95 ${selectedLog?.status === 'Absent' ? 'bg-rose-500 border-rose-600 text-white shadow-xl shadow-rose-100' : 'bg-slate-50 border-slate-100 text-slate-400 hover:bg-rose-50 hover:text-rose-600 hover:border-rose-200'}`}
                     >
                        <span className="text-2xl">❌</span>
                        <span className="text-[10px] font-black uppercase tracking-[0.25em]">Absent</span>
                     </button>
                     <button 
                       onClick={() => openSwapModal(selectedDay)}
                       className={`p-6 rounded-[2rem] border-2 flex flex-col items-center justify-center gap-2 transition-all active:scale-95 ${selectedLog?.isSubstitute ? 'bg-amber-500 border-amber-600 text-white shadow-xl shadow-amber-100' : 'bg-slate-50 border-slate-100 text-slate-400 hover:bg-amber-50 hover:text-amber-600 hover:border-amber-200'}`}
                     >
                        <span className="text-2xl">🔄</span>
                        <span className="text-[10px] font-black uppercase tracking-[0.25em]">Swap Duty</span>
                     </button>
                  </div>

                  {/* Financial Settlement Strip */}
                  <div className="lg:w-96 p-8 bg-slate-900 rounded-[3rem] text-white flex items-center justify-between gap-8 shadow-[0_30px_60px_-15px_rgba(15,23,42,0.5)] relative overflow-hidden group">
                     <div className="absolute top-0 right-0 p-4 text-6xl opacity-5 font-black group-hover:scale-110 transition-transform tracking-tighter">PAY</div>
                     <div className="relative z-10 min-w-0">
                        <p className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.2em] mb-2">Liability Balance</p>
                        <p className="text-4xl font-black tracking-tighter truncate">{formatCurrency(calculateMonthlyTotal(selectedStaff), currency).split('.')[0]}</p>
                     </div>
                     <button onClick={() => setShowSettleModal(selectedStaff)} className="px-8 py-5 bg-indigo-600 text-white rounded-[1.5rem] text-[10px] font-black uppercase tracking-widest hover:bg-indigo-700 transition-all active:scale-95 shadow-xl shadow-indigo-500/20 relative z-10 shrink-0">Settle Dues</button>
                  </div>
               </div>
            </div>
          </>
        ) : (
          <div className="h-full flex flex-col items-center justify-center p-20 text-center bg-slate-50/20">
             <div className="w-28 h-28 bg-white rounded-[3rem] flex items-center justify-center text-6xl mb-10 shadow-xl border border-slate-100 animate-float">📊</div>
             <h4 className="text-3xl font-black text-slate-800 uppercase tracking-tighter">Staff Management Hub</h4>
             <p className="text-[11px] font-black text-slate-400 uppercase mt-5 tracking-[0.2em] leading-loose max-w-sm">
               Centralized portal for attendance logging and wage settlement protocols.
             </p>
             <button onClick={() => { resetForm(); setShowAddStaff(true); }} className="mt-12 px-10 py-5 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-[0.25em] shadow-2xl hover:bg-black transition-all active:scale-95"> Onboard New Personnel </button>
          </div>
        )}
      </div>

      {/* SWAP MODAL */}
      {swapOverride && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/80 backdrop-blur-xl p-4">
           <div className="bg-white w-full max-w-md rounded-[4rem] p-12 shadow-2xl animate-in zoom-in-95 duration-200 border border-slate-200">
              <div className="flex justify-between items-center mb-10">
                 <div>
                   <h3 className="text-3xl font-black text-slate-800 uppercase tracking-tighter">Duty Swap</h3>
                   <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Configure duty replacement logic</p>
                 </div>
                 <button onClick={() => setSwapOverride(null)} className="text-slate-300 hover:text-slate-800 text-3xl font-black">✕</button>
              </div>

              <div className="space-y-4">
                 {[
                   { id: 'OWN', label: 'Primary Personnel', desc: 'Standard service logged', icon: '👤' },
                   { id: 'PROXY', label: 'Proxy Substitute', desc: 'Replacement duty only', icon: '🔄' },
                   { id: 'BOTH', label: 'Double Log', desc: 'Primary and Proxy combined', icon: '⭐' },
                   { id: 'REMOVE', label: 'Audit Reset', desc: 'Clear records for this day', icon: '🧹' }
                 ].map(t => (
                   <button key={t.id} onClick={() => setSwapType(t.id as any)} className={`w-full p-6 text-left rounded-[1.5rem] border-2 transition-all flex items-center gap-6 group ${swapType === t.id ? 'bg-indigo-600 border-indigo-700 text-white shadow-xl shadow-indigo-100' : 'bg-slate-50 border-transparent hover:border-slate-200'}`}>
                      <span className={`text-3xl transition-transform group-hover:scale-110 ${swapType === t.id ? 'grayscale-0' : 'grayscale opacity-50'}`}>{t.icon}</span>
                      <div className="flex-1">
                        <p className={`text-[12px] font-black uppercase tracking-tight ${swapType === t.id ? 'text-white' : 'text-slate-800'}`}>{t.label}</p>
                        <p className={`text-[10px] font-bold uppercase mt-1 ${swapType === t.id ? 'text-white/60' : 'text-slate-400'}`}>{t.desc}</p>
                      </div>
                   </button>
                 ))}
              </div>

              <div className="flex gap-4 mt-12">
                 <button onClick={() => setSwapOverride(null)} className="flex-1 py-6 bg-slate-100 text-slate-400 font-black text-[11px] uppercase rounded-2xl">Abort</button>
                 <button onClick={handleCommitSwap} className="flex-[2] py-6 bg-indigo-600 text-white font-black text-[11px] uppercase rounded-2xl shadow-xl shadow-indigo-500/20 active:scale-95 transition-all">Establish Log</button>
              </div>
           </div>
        </div>
      )}

      {/* ONBOARDING MODAL */}
      {showAddStaff && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/80 backdrop-blur-xl p-4">
           <div className="bg-white w-full max-w-md rounded-[4rem] p-12 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200">
              <h3 className="text-3xl font-black text-slate-800 uppercase tracking-tighter mb-12">{editingStaffId ? 'Registry Refinement' : 'Personnel Onboarding'}</h3>
              <div className="space-y-10">
                 <div className="space-y-3">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-5">Personnel Identity</label>
                    <input autoFocus className="w-full p-6 bg-slate-50 border border-slate-200 rounded-[2rem] font-black text-sm uppercase outline-none focus:ring-8 focus:ring-indigo-600/5 transition-all" value={staffFormData.name} onChange={e => setStaffFormData({...staffFormData, name: e.target.value})} placeholder="e.g. RAJU SHARMA" />
                 </div>
                 <div className="grid grid-cols-2 gap-6">
                    <div className="space-y-3">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-5">Wage Type</label>
                       <select className="w-full p-6 bg-slate-50 border border-slate-200 rounded-[2rem] font-black text-xs outline-none cursor-pointer appearance-none shadow-sm" value={staffFormData.wageType} onChange={e => setStaffFormData({...staffFormData, wageType: e.target.value as WageType})}>
                          <option value="Monthly">Monthly Basis</option>
                          <option value="Daily">Daily Basis</option>
                       </select>
                    </div>
                    <div className="space-y-3">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-5">Role</label>
                       <select className="w-full p-6 bg-slate-50 border border-slate-200 rounded-[2rem] font-black text-xs outline-none cursor-pointer appearance-none shadow-sm" value={staffFormData.role} onChange={e => setStaffFormData({...staffFormData, role: e.target.value})}>
                          <option>Maid</option><option>Cook</option><option>Driver</option><option>Gardener</option><option>House Help</option>
                       </select>
                    </div>
                 </div>
                 <div className="space-y-3">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-5">Wage Benchmark ({currency})</label>
                    <input type="number" className="w-full p-10 bg-slate-900 text-white border border-slate-800 rounded-[3rem] font-black text-5xl text-center outline-none focus:ring-8 focus:ring-indigo-600/10 transition-all" value={staffFormData.baseRate} onChange={e => setStaffFormData({...staffFormData, baseRate: e.target.value})} />
                 </div>
                 <div className="flex gap-4 pt-6">
                    <button onClick={() => { setShowAddStaff(false); resetForm(); }} className="flex-1 py-6 bg-slate-100 text-slate-400 font-black text-[11px] uppercase rounded-2xl">Abort</button>
                    <button onClick={() => {
                      if (!staffFormData.name.trim()) return alert("Identity missing.");
                      const staffData: Staff = {
                        id: editingStaffId || Math.random().toString(36).substr(2, 9),
                        name: staffFormData.name, role: staffFormData.role,
                        baseRate: Number(staffFormData.baseRate), wageType: staffFormData.wageType,
                        attendance: editingStaffId ? (staffList.find(s => s.id === editingStaffId)?.attendance || []) : [],
                        joiningDate: staffFormData.joiningDate
                      };
                      if (editingStaffId) updateStaff(staffData); else addStaff(staffData);
                      setShowAddStaff(false); resetForm();
                    }} className="flex-[2] py-6 bg-indigo-600 text-white font-black text-[11px] uppercase rounded-2xl shadow-xl shadow-indigo-500/20 active:scale-95 transition-all">Verify & Commit</button>
                 </div>
              </div>
           </div>
        </div>
      )}

      {/* SETTLEMENT MODAL */}
      {showSettleModal && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/90 backdrop-blur-2xl p-4">
           <div className="bg-white w-full max-w-md rounded-[5rem] p-16 shadow-2xl text-center animate-in zoom-in-95 border border-slate-200">
              {!isRecordingSuccess ? (
                <>
                  <div className="w-24 h-24 bg-emerald-50 text-emerald-600 rounded-full flex items-center justify-center text-5xl mx-auto mb-10 shadow-inner border border-emerald-100">💸</div>
                  <h3 className="text-4xl font-black text-slate-900 uppercase tracking-tighter mb-2">Wage Payout</h3>
                  <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest mb-12">Consolidated Verification for {monthName}</p>

                  <div className="p-12 bg-slate-50 rounded-[4rem] mb-12 shadow-inner border border-slate-100 relative group overflow-hidden">
                    <div className="absolute top-0 right-0 p-4 text-5xl opacity-5 font-black text-emerald-600 uppercase">DUE</div>
                    <p className="text-7xl font-black text-emerald-600 tracking-tighter relative z-10">{formatCurrency(calculateMonthlyTotal(showSettleModal), currency).split('.')[0]}</p>
                    <p className="text-[11px] font-black text-slate-400 uppercase mt-5 tracking-widest relative z-10">Calculated Fiscal Liability</p>
                  </div>

                  <div className="space-y-8">
                    <div className="space-y-3">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block text-left ml-6">Source Vault</label>
                       <select className="w-full p-6 bg-slate-100 border border-slate-200 rounded-[2rem] font-black text-xs outline-none cursor-pointer appearance-none shadow-sm" value={settlementMode?.id || ''} onChange={(e) => {
                           const acc = availableAccounts.find(a => a.id === e.target.value);
                           if (acc) setSettlementMode(acc);
                         }}>
                         <option value="">Choose Payout Account</option>
                         {availableAccounts.map(acc => (<option key={acc.id} value={acc.id}>{acc.name} ({acc.type})</option>))}
                       </select>
                    </div>

                    <div className="flex flex-col gap-4">
                      <button onClick={() => handleSettle(showSettleModal)} className="w-full py-8 bg-indigo-600 text-white font-black text-sm uppercase rounded-[2rem] shadow-2xl shadow-indigo-500/40 hover:bg-indigo-700 transition-all active:scale-95">Post Settlement</button>
                      <button onClick={() => { setShowSettleModal(null); setSettlementMode(null); }} className="w-full py-5 bg-slate-100 text-slate-400 font-black text-[11px] uppercase rounded-[2rem]">Abort Operation</button>
                    </div>
                  </div>
                </>
              ) : (
                <div className="animate-in zoom-in-95 duration-700 py-10">
                  <div className="w-32 h-32 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center text-7xl mx-auto mb-12 shadow-2xl border border-emerald-200 animate-bounce">✅</div>
                  <h3 className="text-4xl font-black text-slate-900 uppercase tracking-tighter mb-4">Payout Verified</h3>
                  <p className="text-[12px] font-black text-slate-400 uppercase mb-16 tracking-widest">Entry successfully posted to ledger.</p>
                  <button onClick={() => { setShowSettleModal(null); setIsRecordingSuccess(false); }} className="w-full py-8 bg-slate-900 text-white font-black text-xs uppercase rounded-[2.5rem] shadow-2xl hover:bg-black transition-all active:scale-95">Close Session</button>
                </div>
              )}
           </div>
        </div>
      )}
    </div>
  );
};

export default StaffManager;

import React, { useState, useMemo, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Staff, StaffAttendance, WageType, Transaction } from '../types';

const StaffManager: React.FC = () => {
  const { state, addStaff, updateStaff, deleteStaff, logStaffAttendance, addTransaction } = useFinance();
  const [showAddStaff, setShowAddStaff] = useState(false);
  const [editingStaffId, setEditingStaffId] = useState<string | null>(null);
  const [selectedStaffId, setSelectedStaffId] = useState<string | null>(null);
  const [viewDate, setViewDate] = useState(new Date());
  const [showSettleModal, setShowSettleModal] = useState<Staff | null>(null);
  const [swapOverride, setSwapOverride] = useState<{ day: number, dateStr: string } | null>(null);
  const [selectedDay, setSelectedDay] = useState<number>(new Date().getDate());

  const [settlementMode, setSettlementMode] = useState<{ id: string, name: string, type: 'bank' | 'card' | 'wallet' | 'liability' } | null>(null);
  const [isRecordingSuccess, setIsRecordingSuccess] = useState(false);

  const [staffFormData, setStaffFormData] = useState({ 
    name: '', role: 'Maid', customRole: '', baseRate: '500', wageType: 'Daily' as WageType,
    joiningDate: new Date().toISOString().split('T')[0], exitDate: ''
  });

  const [swapType, setSwapType] = useState<'OWN' | 'PROXY' | 'BOTH' | 'REMOVE'>('OWN');
  const [proxyRate, setProxyRate] = useState<string>('0');

  const currency = state.profile.currency;
  const staffList = state.staff || [];
  const selectedStaff = staffList.find(s => s.id === selectedStaffId);

  useEffect(() => {
    if (!selectedStaffId && staffList.length > 0) {
      setSelectedStaffId(staffList[0].id);
    }
  }, [staffList, selectedStaffId]);

  const availableAccounts = useMemo(() => {
    const list: { id: string, name: string, type: 'bank' | 'card' | 'wallet' | 'liability' }[] = [];
    state.banks.forEach(b => list.push({ id: b.id, name: b.name, type: 'bank' }));
    state.wallets.forEach(w => list.push({ id: w.id, name: w.name, type: 'wallet' }));
    state.cards.forEach(c => list.push({ id: c.id, name: c.lenderName, type: 'card' }));
    return list;
  }, [state]);

  const daysInMonth = useMemo(() => {
    return new Date(viewDate.getFullYear(), viewDate.getMonth() + 1, 0).getDate();
  }, [viewDate]);

  const monthName = viewDate.toLocaleString('default', { month: 'long', year: 'numeric' });

  const resetForm = () => {
    setStaffFormData({
      name: '', role: 'Maid', customRole: '', baseRate: '500', wageType: 'Daily',
      joiningDate: new Date().toISOString().split('T')[0], exitDate: ''
    });
    setEditingStaffId(null);
  };

  const getAttendanceStatusForDay = (staff: Staff, dateStr: string) => {
    const manualLog = staff.attendance?.find(a => a.date === dateStr);
    if (manualLog) return manualLog;

    const today = new Date().toISOString().split('T')[0];
    const joining = staff.joiningDate;
    const exit = staff.exitDate;

    if (dateStr >= joining && (!exit || dateStr <= exit) && dateStr <= today) {
       let rate = staff.baseRate;
       if (staff.wageType === 'Monthly') {
          const d = new Date(dateStr);
          rate = staff.baseRate / new Date(d.getFullYear(), d.getMonth() + 1, 0).getDate();
       }
       return { status: 'Present', rate: rate, isSubstitute: false, isDefault: true };
    }
    return { status: 'None', rate: 0, isSubstitute: false, isDefault: true };
  };

  const openSwapModal = (day: number) => {
    const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSwapOverride({ day, dateStr });
  };

  const handleCommitSwap = () => {
    if (!selectedStaff || !swapOverride) return;
    if (swapType === 'REMOVE') {
      logStaffAttendance(selectedStaff.id, { date: swapOverride.dateStr, status: 'None' });
    } else {
      let finalRate = swapType === 'OWN' ? Number(selectedStaff.baseRate) : (swapType === 'PROXY' ? Number(proxyRate) : Number(selectedStaff.baseRate) + Number(proxyRate));
      logStaffAttendance(selectedStaff.id, {
        date: swapOverride.dateStr, status: 'Present', rate: finalRate, isSubstitute: swapType !== 'OWN'
      });
    }
    setSwapOverride(null);
  };

  const calculateMonthlyTotal = (staff: Staff) => {
    let total = 0;
    for (let i = 1; i <= daysInMonth; i++) {
      const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(i).padStart(2, '0')}`;
      const log = getAttendanceStatusForDay(staff, dateStr);
      if (log.status === 'Present') total += log.rate;
    }
    return total;
  };

  const handleSettle = (staff: Staff) => {
    if (!settlementMode) return alert("Select target account first.");
    const amount = calculateMonthlyTotal(staff);
    if (amount <= 0) return alert("No dues to settle.");

    const tx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'Expense',
      amount: amount,
      nature: staff.name,
      description: `Wages payout for ${monthName}`,
      accountId: settlementMode.id,
      accountType: settlementMode.type,
      date: new Date().toISOString().split('T')[0],
      status: 'active'
    };

    addTransaction(tx);
    setIsRecordingSuccess(true);
    setSettlementMode(null);
  };

  const handleAttendanceToggle = (targetStatus: 'Present' | 'Absent') => {
    if (!selectedStaff) return;
    const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(selectedDay).padStart(2, '0')}`;
    const currentLog = getAttendanceStatusForDay(selectedStaff, dateStr);

    if (!(currentLog as any).isDefault && currentLog.status === targetStatus) {
      logStaffAttendance(selectedStaff.id, { date: dateStr, status: 'None' });
      return;
    }

    let rate = targetStatus === 'Present' ? selectedStaff.baseRate : 0;
    if (targetStatus === 'Present' && selectedStaff.wageType === 'Monthly') {
      const d = new Date(dateStr);
      rate = selectedStaff.baseRate / new Date(d.getFullYear(), d.getMonth() + 1, 0).getDate();
    }

    logStaffAttendance(selectedStaff.id, { 
      date: dateStr, 
      status: targetStatus, 
      rate: rate, 
      isSubstitute: false 
    });
  };

  const selectedDateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(selectedDay).padStart(2, '0')}`;
  const selectedLog = selectedStaff ? getAttendanceStatusForDay(selectedStaff, selectedDateStr) : null;

  return (
    <div className="h-[calc(100dvh-120px)] flex flex-col md:flex-row gap-4 md:gap-6 animate-in fade-in duration-500 overflow-hidden font-sans bg-slate-50/30 p-2 md:p-4">

      {/* PERSONNEL REGISTRY - MOBILE RESPONSIVE DRAWER/SIDEBAR */}
      <div className="w-full md:w-80 flex flex-col bg-white border border-slate-200 rounded-[2.5rem] overflow-hidden shadow-sm shrink-0">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Personnel Registry</h3>
          <button 
            onClick={() => { resetForm(); setShowAddStaff(true); }} 
            className="w-10 h-10 flex items-center justify-center bg-indigo-600 text-white rounded-2xl text-lg shadow-lg shadow-indigo-100 hover:scale-110 transition-transform active:scale-95"
          >
            +
          </button>
        </div>

        {/* Horizontal scroll for mobile registry, vertical for desktop */}
        <div className="flex md:flex-col overflow-x-auto md:overflow-y-auto no-scrollbar py-4 px-2 md:px-0 gap-3">
          {staffList.map(s => (
            <div 
              key={s.id} 
              onClick={() => setSelectedStaffId(s.id)} 
              className={`p-4 md:p-5 mx-2 md:mx-3 md:mb-2 rounded-[2rem] flex items-center gap-4 cursor-pointer transition-all border shrink-0 min-w-[200px] md:min-w-0 ${selectedStaffId === s.id ? 'bg-indigo-600 border-indigo-700 text-white shadow-xl shadow-indigo-100' : 'bg-white border-slate-100 text-slate-800 hover:bg-slate-50'}`}
            >
              <div className={`w-12 h-12 rounded-[1.25rem] flex items-center justify-center text-xl shadow-sm ${selectedStaffId === s.id ? 'bg-white/20' : 'bg-slate-100'}`}>👤</div>
              <div className="flex-1 min-w-0">
                <p className={`text-[11px] font-black uppercase truncate tracking-tight ${selectedStaffId === s.id ? 'text-white' : 'text-slate-800'}`}>{s.name}</p>
                <p className={`text-[9px] font-black uppercase tracking-widest mt-0.5 ${selectedStaffId === s.id ? 'text-white/60' : 'text-slate-400'}`}>{s.role}</p>
              </div>
            </div>
          ))}
          {staffList.length === 0 && (
            <div className="p-12 text-center flex flex-col items-center gap-4 w-full">
               <div className="text-4xl opacity-20 grayscale">👥</div>
               <p className="text-[10px] font-black text-slate-300 uppercase tracking-widest italic leading-relaxed">Registry Empty</p>
            </div>
          )}
        </div>
      </div>

      {/* MAIN WORKSPACE: OPTIMIZED CALENDAR FLOW */}
      <div className="flex-1 flex flex-col bg-white border border-slate-200 rounded-[3rem] overflow-hidden shadow-sm relative">
        {selectedStaff ? (
          <>
            {/* COMPACT DASHBOARD HEADER */}
            <div className="p-6 md:p-8 border-b border-slate-100 flex flex-col sm:flex-row justify-between items-center gap-6 bg-white shrink-0">
              <div className="flex items-center gap-4 w-full sm:w-auto">
                <div className="w-14 h-14 bg-slate-900 text-white rounded-[1.5rem] flex items-center justify-center text-xl font-black shadow-xl shrink-0">
                  {selectedStaff.name.charAt(0)}
                </div>
                <div className="min-w-0 flex-1">
                   <h2 className="text-xl font-black text-slate-900 uppercase tracking-tighter truncate leading-none mb-1">{selectedStaff.name}</h2>
                   <div className="flex items-center gap-2">
                      <p className="text-[9px] font-black text-indigo-600 uppercase tracking-widest">{selectedStaff.role}</p>
                      <button onClick={() => { 
                        setEditingStaffId(selectedStaff.id); 
                        setStaffFormData({ 
                          ...staffFormData, 
                          name: selectedStaff.name, 
                          role: selectedStaff.role,
                          baseRate: String(selectedStaff.baseRate),
                          wageType: selectedStaff.wageType
                        }); 
                        setShowAddStaff(true); 
                      }} className="w-5 h-5 rounded-md bg-slate-100 flex items-center justify-center text-[8px] hover:bg-indigo-50 hover:text-indigo-600 transition-colors">✎</button>
                   </div>
                </div>
              </div>

              <div className="flex items-center gap-1 bg-slate-50 p-1 rounded-full border border-slate-100 shadow-inner w-full sm:w-auto justify-between sm:justify-start">
                 <button onClick={() => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() - 1))} className="w-10 h-10 flex items-center justify-center hover:bg-white rounded-full text-slate-400 transition-all active:scale-90 shadow-sm border border-transparent">←</button>
                 <span className="px-4 text-[9px] font-black uppercase tracking-[0.2em] text-slate-800">{monthName}</span>
                 <button onClick={() => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() + 1))} className="w-10 h-10 flex items-center justify-center hover:bg-white rounded-full text-slate-400 transition-all active:scale-90 shadow-sm border border-transparent">→</button>
              </div>
            </div>

            {/* FOCUS-MODE CALENDAR GRID */}
            <div className="flex-1 overflow-hidden p-4 md:p-8 bg-slate-50/40">
              <div className="h-full border border-slate-200 rounded-[2.5rem] bg-white shadow-xl overflow-hidden flex flex-col">
                <div className="grid grid-cols-7 border-b border-slate-100 shrink-0 bg-slate-50/50">
                  {['S','M','T','W','T','F','S'].map((d, i) => (
                    <div key={i} className="py-4 text-center text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">{d}</div>
                  ))}
                </div>
                <div className="flex-1 grid grid-cols-7 auto-rows-fr overflow-y-auto no-scrollbar">
                  {Array.from({ length: new Date(viewDate.getFullYear(), viewDate.getMonth(), 1).getDay() }).map((_, i) => (
                    <div key={`empty-${i}`} className="border-r border-b border-slate-50 bg-slate-50/10"></div>
                  ))}
                  {Array.from({ length: daysInMonth }).map((_, i) => {
                    const day = i + 1;
                    const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
                    const log = getAttendanceStatusForDay(selectedStaff, dateStr);
                    const isActive = selectedDay === day;

                    return (
                      <div 
                        key={day} 
                        onClick={() => setSelectedDay(day)}
                        className={`group flex flex-col items-center justify-center border-r border-b border-slate-50 cursor-pointer transition-all relative ${isActive ? 'bg-indigo-600 text-white z-10' : 'hover:bg-slate-50/60'}`}
                      >
                        <span className={`text-base font-black transition-all ${isActive ? 'scale-125' : 'text-slate-400 group-hover:text-slate-800'}`}>{day}</span>

                        <div className="mt-1 h-3 flex items-center justify-center">
                          {log.status === 'Present' ? (
                            <div className={`w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white' : (log.isSubstitute ? 'bg-amber-400' : 'bg-emerald-500')}`}></div>
                          ) : log.status === 'Absent' ? (
                            <div className={`w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white/40' : 'bg-rose-400'}`}></div>
                          ) : null}
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>

            {/* ACTION STICKY BAR: MODERN MOBILE-FIRST CONTROLS */}
            <div className="p-6 md:p-8 border-t border-slate-100 bg-white shadow-[0_-20px_40px_-10px_rgba(0,0,0,0.05)]">
               <div className="flex flex-col lg:flex-row items-stretch lg:items-center gap-6">
                  {/* Status Selection Buttons */}
                  <div className="flex-1 flex gap-3">
                     <button 
                       onClick={() => handleAttendanceToggle('Present')}
                       className={`flex-1 py-5 rounded-[1.5rem] border-2 flex items-center justify-center gap-2 transition-all active:scale-95 ${selectedLog?.status === 'Present' && !selectedLog.isSubstitute ? 'bg-emerald-500 border-emerald-600 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-400 hover:bg-emerald-50 hover:text-emerald-600'}`}
                     >
                        <span className="text-xl">✅</span>
                        <span className="text-[10px] font-black uppercase tracking-[0.1em] hidden sm:inline">Present</span>
                     </button>
                     <button 
                       onClick={() => handleAttendanceToggle('Absent')}
                       className={`flex-1 py-5 rounded-[1.5rem] border-2 flex items-center justify-center gap-2 transition-all active:scale-95 ${selectedLog?.status === 'Absent' ? 'bg-rose-500 border-rose-600 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-400 hover:bg-rose-50 hover:text-rose-600'}`}
                     >
                        <span className="text-xl">❌</span>
                        <span className="text-[10px] font-black uppercase tracking-[0.1em] hidden sm:inline">Absent</span>
                     </button>
                     <button 
                       onClick={() => openSwapModal(selectedDay)}
                       className={`flex-1 py-5 rounded-[1.5rem] border-2 flex items-center justify-center gap-2 transition-all active:scale-95 ${selectedLog?.isSubstitute ? 'bg-amber-500 border-amber-600 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-400 hover:bg-amber-50 hover:text-amber-600'}`}
                     >
                        <span className="text-xl">🔄</span>
                        <span className="text-[10px] font-black uppercase tracking-[0.1em] hidden sm:inline">Swap</span>
                     </button>
                  </div>

                  {/* Financial Settlement Strip */}
                  <div className="lg:w-72 p-6 bg-slate-900 rounded-[2rem] text-white flex items-center justify-between gap-4 shadow-2xl relative overflow-hidden group">
                     <div className="relative z-10 min-w-0">
                        <p className="text-[9px] font-black text-indigo-400 uppercase tracking-[0.15em] mb-1">Total Dues</p>
                        <p className="text-2xl font-black tracking-tighter truncate leading-none">{formatCurrency(calculateMonthlyTotal(selectedStaff), currency).split('.')[0]}</p>
                     </div>
                     <button onClick={() => setShowSettleModal(selectedStaff)} className="px-5 py-3 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-700 transition-all active:scale-95 shadow-xl shadow-indigo-500/20 relative z-10 shrink-0">Pay Now</button>
                  </div>
               </div>
            </div>
          </>
        ) : (
          <div className="h-full flex flex-col items-center justify-center p-12 text-center bg-slate-50/20">
             <div className="w-24 h-24 bg-white rounded-[2.5rem] flex items-center justify-center text-5xl mb-8 shadow-xl border border-slate-100 animate-float">📈</div>
             <h4 className="text-2xl font-black text-slate-800 uppercase tracking-tighter">Staff Portal</h4>
             <p className="text-[11px] font-black text-slate-400 uppercase mt-4 tracking-[0.2em] leading-loose max-w-xs">
               Select personnel to manage attendance and execute payouts.
             </p>
          </div>
        )}
      </div>

      {/* MODALS: SWAP, ONBOARDING, SETTLEMENT */}
      {swapOverride && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/90 backdrop-blur-xl p-6">
           <div className="bg-white w-full max-w-sm rounded-[3rem] p-8 md:p-10 shadow-2xl animate-in zoom-in-95 duration-200 border border-slate-200">
              <div className="flex justify-between items-center mb-10">
                 <div>
                   <h3 className="text-2xl font-black text-slate-800 uppercase tracking-tighter">Duty Swap</h3>
                   <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mt-1">Configure duty replacement</p>
                 </div>
                 <button onClick={() => setSwapOverride(null)} className="text-slate-300 hover:text-slate-800 text-2xl font-black">✕</button>
              </div>

              <div className="space-y-3">
                 {[
                   { id: 'OWN', label: 'Primary Personnel', icon: '👤' },
                   { id: 'PROXY', label: 'Proxy Substitute', icon: '🔄' },
                   { id: 'BOTH', label: 'Double Log', icon: '⭐' },
                   { id: 'REMOVE', label: 'Clear Log', icon: '🧹' }
                 ].map(t => (
                   <button key={t.id} onClick={() => setSwapType(t.id as any)} className={`w-full p-5 text-left rounded-[1.5rem] border-2 transition-all flex items-center gap-4 group ${swapType === t.id ? 'bg-indigo-600 border-indigo-700 text-white shadow-xl' : 'bg-slate-50 border-transparent hover:border-slate-200'}`}>
                      <span className={`text-2xl transition-transform group-hover:scale-110 ${swapType === t.id ? 'grayscale-0' : 'grayscale opacity-50'}`}>{t.icon}</span>
                      <p className={`text-[11px] font-black uppercase tracking-tight ${swapType === t.id ? 'text-white' : 'text-slate-800'}`}>{t.label}</p>
                   </button>
                 ))}
              </div>

              <div className="flex gap-3 mt-10">
                 <button onClick={() => setSwapOverride(null)} className="flex-1 py-5 bg-slate-100 text-slate-400 font-black text-[10px] uppercase rounded-2xl">Cancel</button>
                 <button onClick={handleCommitSwap} className="flex-[2] py-5 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl shadow-indigo-500/20 active:scale-95 transition-all">Verify Swap</button>
              </div>
           </div>
        </div>
      )}

      {showAddStaff && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/90 backdrop-blur-xl p-6">
           <div className="bg-white w-full max-w-sm rounded-[3rem] p-10 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200">
              <h3 className="text-2xl font-black text-slate-800 uppercase tracking-tighter mb-10">{editingStaffId ? 'Refine Registry' : 'Onboard Help'}</h3>
              <div className="space-y-8">
                 <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-4">Full Identity</label>
                    <input autoFocus className="w-full p-5 bg-slate-50 border border-slate-200 rounded-[1.5rem] font-black text-sm uppercase outline-none focus:ring-4 focus:ring-indigo-600/5 transition-all" value={staffFormData.name} onChange={e => setStaffFormData({...staffFormData, name: e.target.value})} placeholder="e.g. RAJU SHARMA" />
                 </div>
                 <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                       <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-4">Wage Basis</label>
                       <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-[1.5rem] font-black text-xs outline-none cursor-pointer appearance-none shadow-sm" value={staffFormData.wageType} onChange={e => setStaffFormData({...staffFormData, wageType: e.target.value as WageType})}>
                          <option value="Monthly">Monthly</option>
                          <option value="Daily">Daily</option>
                       </select>
                    </div>
                    <div className="space-y-2">
                       <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-4">Role</label>
                       <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-[1.5rem] font-black text-xs outline-none cursor-pointer appearance-none shadow-sm" value={staffFormData.role} onChange={e => setStaffFormData({...staffFormData, role: e.target.value})}>
                          <option>Maid</option><option>Cook</option><option>Driver</option><option>House help</option>
                       </select>
                    </div>
                 </div>
                 <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-4">Rate ({currency})</label>
                    <input type="number" className="w-full p-8 bg-slate-900 text-white border border-slate-800 rounded-[2.5rem] font-black text-4xl text-center outline-none focus:ring-4 focus:ring-indigo-600/10 transition-all" value={staffFormData.baseRate} onChange={e => setStaffFormData({...staffFormData, baseRate: e.target.value})} />
                 </div>
                 <div className="flex gap-3 pt-4">
                    <button onClick={() => { setShowAddStaff(false); resetForm(); }} className="flex-1 py-5 bg-slate-100 text-slate-400 font-black text-[10px] uppercase rounded-2xl">Abort</button>
                    <button onClick={() => {
                      if (!staffFormData.name.trim()) return alert("Identity required.");
                      const staffData: Staff = {
                        id: editingStaffId || Math.random().toString(36).substr(2, 9),
                        name: staffFormData.name, role: staffFormData.role,
                        baseRate: Number(staffFormData.baseRate), wageType: staffFormData.wageType,
                        attendance: editingStaffId ? (staffList.find(s => s.id === editingStaffId)?.attendance || []) : [],
                        joiningDate: staffFormData.joiningDate
                      };
                      if (editingStaffId) updateStaff(staffData); else addStaff(staffData);
                      setShowAddStaff(false); resetForm();
                    }} className="flex-[2] py-5 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl shadow-indigo-500/20 active:scale-95 transition-all">Establish</button>
                 </div>
              </div>
           </div>
        </div>
      )}

      {showSettleModal && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/95 backdrop-blur-2xl p-6">
           <div className="bg-white w-full max-w-sm rounded-[4rem] p-12 shadow-2xl text-center animate-in zoom-in-95 border border-slate-200">
              {!isRecordingSuccess ? (
                <>
                  <div className="w-20 h-20 bg-emerald-50 text-emerald-600 rounded-full flex items-center justify-center text-4xl mx-auto mb-8 shadow-inner border border-emerald-100">💸</div>
                  <h3 className="text-3xl font-black text-slate-900 uppercase tracking-tighter mb-1">Wage Payout</h3>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-10">{monthName}</p>

                  <div className="p-10 bg-slate-50 rounded-[3rem] mb-10 shadow-inner border border-slate-100">
                    <p className="text-5xl font-black text-emerald-600 tracking-tighter">{formatCurrency(calculateMonthlyTotal(showSettleModal), currency).split('.')[0]}</p>
                    <p className="text-[9px] font-black text-slate-400 uppercase mt-3 tracking-widest">Net Liability</p>
                  </div>

                  <div className="space-y-6">
                    <div className="space-y-2">
                       <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block text-left ml-4">Fund Source</label>
                       <select className="w-full p-5 bg-slate-100 border border-slate-200 rounded-[2rem] font-black text-xs outline-none cursor-pointer appearance-none shadow-sm" value={settlementMode?.id || ''} onChange={(e) => {
                           const acc = availableAccounts.find(a => a.id === e.target.value);
                           if (acc) setSettlementMode(acc);
                         }}>
                         <option value="">Select Account</option>
                         {availableAccounts.map(acc => (<option key={acc.id} value={acc.id}>{acc.name} ({acc.type})</option>))}
                       </select>
                    </div>

                    <div className="flex flex-col gap-3">
                      <button onClick={() => handleSettle(showSettleModal)} className="w-full py-6 bg-indigo-600 text-white font-black text-xs uppercase rounded-[2rem] shadow-2xl shadow-indigo-500/40 hover:bg-indigo-700 transition-all active:scale-95">Post Payout</button>
                      <button onClick={() => { setShowSettleModal(null); setSettlementMode(null); }} className="w-full py-4 bg-slate-100 text-slate-400 font-black text-[9px] uppercase rounded-[1.5rem]">Abort</button>
                    </div>
                  </div>
                </>
              ) : (
                <div className="animate-in zoom-in-95 duration-700 py-10">
                  <div className="w-28 h-28 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center text-6xl mx-auto mb-10 shadow-xl border border-emerald-200 animate-bounce">✅</div>
                  <h3 className="text-3xl font-black text-slate-900 uppercase tracking-tighter mb-2">Success</h3>
                  <p className="text-[10px] font-black text-slate-400 uppercase mb-12 tracking-widest">Transaction posted to ledger</p>
                  <button onClick={() => { setShowSettleModal(null); setIsRecordingSuccess(false); }} className="w-full py-6 bg-slate-900 text-white font-black text-xs uppercase rounded-[2rem] shadow-2xl hover:bg-black transition-all">Close</button>
                </div>
              )}
           </div>
        </div>
      )}
    </div>
  );
};

export default StaffManager;

import React, { useState, useMemo, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Staff, StaffAttendance, WageType, Transaction } from '../types';

const StaffManager: React.FC = () => {
  const { state, addStaff, updateStaff, deleteStaff, logStaffAttendance, addTransaction } = useFinance();
  const [showAddStaff, setShowAddStaff] = useState(false);
  const [editingStaffId, setEditingStaffId] = useState<string | null>(null);
  const [selectedStaffId, setSelectedStaffId] = useState<string | null>(null);
  const [viewDate, setViewDate] = useState(new Date());
  const [showSettleModal, setShowSettleModal] = useState<Staff | null>(null);
  const [swapOverride, setSwapOverride] = useState<{ day: number, dateStr: string } | null>(null);
  const [selectedDay, setSelectedDay] = useState<number>(new Date().getDate());

  const [settlementMode, setSettlementMode] = useState<{ id: string, name: string, type: 'bank' | 'card' | 'wallet' | 'liability' } | null>(null);
  const [isRecordingSuccess, setIsRecordingSuccess] = useState(false);

  const [staffFormData, setStaffFormData] = useState({ 
    name: '', role: 'Maid', customRole: '', baseRate: '500', wageType: 'Daily' as WageType,
    joiningDate: new Date().toISOString().split('T')[0], exitDate: ''
  });

  const [swapType, setSwapType] = useState<'OWN' | 'PROXY' | 'BOTH' | 'REMOVE'>('OWN');
  const [proxyRate, setProxyRate] = useState<string>('0');

  const currency = state.profile.currency;
  const staffList = state.staff || [];
  const selectedStaff = staffList.find(s => s.id === selectedStaffId);

  useEffect(() => {
    if (!selectedStaffId && staffList.length > 0) {
      setSelectedStaffId(staffList[0].id);
    }
  }, [staffList, selectedStaffId]);

  const availableAccounts = useMemo(() => {
    const list: { id: string, name: string, type: 'bank' | 'card' | 'wallet' | 'liability' }[] = [];
    state.banks.forEach(b => list.push({ id: b.id, name: b.name, type: 'bank' }));
    state.wallets.forEach(w => list.push({ id: w.id, name: w.name, type: 'wallet' }));
    state.cards.forEach(c => list.push({ id: c.id, name: c.lenderName, type: 'card' }));
    return list;
  }, [state]);

  const daysInMonth = useMemo(() => {
    return new Date(viewDate.getFullYear(), viewDate.getMonth() + 1, 0).getDate();
  }, [viewDate]);

  const monthName = viewDate.toLocaleString('default', { month: 'long', year: 'numeric' });

  const resetForm = () => {
    setStaffFormData({
      name: '', role: 'Maid', customRole: '', baseRate: '500', wageType: 'Daily',
      joiningDate: new Date().toISOString().split('T')[0], exitDate: ''
    });
    setEditingStaffId(null);
  };

  const getAttendanceStatusForDay = (staff: Staff, dateStr: string) => {
    const manualLog = staff.attendance?.find(a => a.date === dateStr);
    if (manualLog) return manualLog;

    const today = new Date().toISOString().split('T')[0];
    const joining = staff.joiningDate;
    const exit = staff.exitDate;

    if (dateStr >= joining && (!exit || dateStr <= exit) && dateStr <= today) {
       let rate = staff.baseRate;
       if (staff.wageType === 'Monthly') {
          const d = new Date(dateStr);
          rate = staff.baseRate / new Date(d.getFullYear(), d.getMonth() + 1, 0).getDate();
       }
       return { status: 'Present', rate: rate, isSubstitute: false, isDefault: true };
    }
    return { status: 'None', rate: 0, isSubstitute: false, isDefault: true };
  };

  const openSwapModal = (day: number) => {
    const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSwapOverride({ day, dateStr });
  };

  const handleCommitSwap = () => {
    if (!selectedStaff || !swapOverride) return;
    if (swapType === 'REMOVE') {
      logStaffAttendance(selectedStaff.id, { date: swapOverride.dateStr, status: 'None' });
    } else {
      let finalRate = swapType === 'OWN' ? Number(selectedStaff.baseRate) : (swapType === 'PROXY' ? Number(proxyRate) : Number(selectedStaff.baseRate) + Number(proxyRate));
      logStaffAttendance(selectedStaff.id, {
        date: swapOverride.dateStr, status: 'Present', rate: finalRate, isSubstitute: swapType !== 'OWN'
      });
    }
    setSwapOverride(null);
  };

  const calculateMonthlyTotal = (staff: Staff) => {
    let total = 0;
    for (let i = 1; i <= daysInMonth; i++) {
      const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(i).padStart(2, '0')}`;
      const log = getAttendanceStatusForDay(staff, dateStr);
      if (log.status === 'Present') total += log.rate;
    }
    return total;
  };

  const handleSettle = (staff: Staff) => {
    if (!settlementMode) return alert("Select target account first.");
    const amount = calculateMonthlyTotal(staff);
    if (amount <= 0) return alert("No dues to settle.");

    const tx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'Expense',
      amount: amount,
      nature: staff.name,
      description: `Wages payout for ${monthName}`,
      accountId: settlementMode.id,
      accountType: settlementMode.type,
      date: new Date().toISOString().split('T')[0],
      status: 'active'
    };

    addTransaction(tx);
    setIsRecordingSuccess(true);
    setSettlementMode(null);
  };

  const handleAttendanceToggle = (targetStatus: 'Present' | 'Absent') => {
    if (!selectedStaff) return;
    const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(selectedDay).padStart(2, '0')}`;
    const currentLog = getAttendanceStatusForDay(selectedStaff, dateStr);

    if (!(currentLog as any).isDefault && currentLog.status === targetStatus) {
      logStaffAttendance(selectedStaff.id, { date: dateStr, status: 'None' });
      return;
    }

    let rate = targetStatus === 'Present' ? selectedStaff.baseRate : 0;
    if (targetStatus === 'Present' && selectedStaff.wageType === 'Monthly') {
      const d = new Date(dateStr);
      rate = selectedStaff.baseRate / new Date(d.getFullYear(), d.getMonth() + 1, 0).getDate();
    }

    logStaffAttendance(selectedStaff.id, { 
      date: dateStr, 
      status: targetStatus, 
      rate: rate, 
      isSubstitute: false 
    });
  };

  const selectedDateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(selectedDay).padStart(2, '0')}`;
  const selectedLog = selectedStaff ? getAttendanceStatusForDay(selectedStaff, selectedDateStr) : null;

  return (
    <div className="h-[calc(100dvh-120px)] flex flex-col md:flex-row gap-4 animate-in fade-in duration-500 overflow-hidden font-sans">

      {/* PERSONNEL REGISTRY - SCROLLABLE LIST */}
      <div className="w-full md:w-72 flex flex-col bg-white border border-slate-200 rounded-[2rem] overflow-hidden shadow-sm shrink-0">
        <div className="p-5 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Registry</h3>
          <button 
            onClick={() => { resetForm(); setShowAddStaff(true); }} 
            className="w-8 h-8 flex items-center justify-center bg-indigo-600 text-white rounded-xl text-lg shadow-lg hover:scale-105 transition-transform"
          >
            +
          </button>
        </div>

        <div className="flex-1 overflow-y-auto no-scrollbar p-3 space-y-2">
          {staffList.map(s => (
            <div 
              key={s.id} 
              onClick={() => setSelectedStaffId(s.id)} 
              className={`p-4 rounded-2xl flex items-center gap-3 cursor-pointer transition-all border ${selectedStaffId === s.id ? 'bg-indigo-600 border-indigo-700 text-white shadow-lg' : 'bg-white border-slate-100 text-slate-800 hover:bg-slate-50'}`}
            >
              <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-lg shrink-0 ${selectedStaffId === s.id ? 'bg-white/20' : 'bg-slate-100'}`}>👤</div>
              <div className="min-w-0 flex-1">
                <p className={`text-[11px] font-black uppercase truncate ${selectedStaffId === s.id ? 'text-white' : 'text-slate-800'}`}>{s.name}</p>
                <p className={`text-[9px] font-black uppercase tracking-widest mt-0.5 ${selectedStaffId === s.id ? 'text-white/60' : 'text-slate-400'}`}>{s.role}</p>
              </div>
            </div>
          ))}
          {staffList.length === 0 && (
            <div className="py-20 text-center flex flex-col items-center gap-3">
               <div className="text-3xl opacity-20">👥</div>
               <p className="text-[9px] font-black text-slate-300 uppercase tracking-widest">No Personnel</p>
            </div>
          )}
        </div>
      </div>

      {/* MAIN WORKSPACE: CALENDAR GRID & ACTIONS */}
      <div className="flex-1 flex flex-col bg-white border border-slate-200 rounded-[2.5rem] overflow-hidden shadow-sm">
        {selectedStaff ? (
          <>
            {/* WORKSPACE HEADER */}
            <div className="p-6 border-b border-slate-100 flex flex-col sm:flex-row justify-between items-center gap-4 bg-white shrink-0">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-slate-900 text-white rounded-2xl flex items-center justify-center text-xl font-black">
                  {selectedStaff.name.charAt(0)}
                </div>
                <div>
                   <h2 className="text-lg font-black text-slate-900 uppercase tracking-tighter leading-none mb-1">{selectedStaff.name}</h2>
                   <div className="flex items-center gap-2">
                      <p className="text-[9px] font-black text-indigo-600 uppercase tracking-widest">{selectedStaff.role}</p>
                      <button onClick={() => { 
                        setEditingStaffId(selectedStaff.id); 
                        setStaffFormData({ 
                          ...staffFormData, 
                          name: selectedStaff.name, 
                          role: selectedStaff.role,
                          baseRate: String(selectedStaff.baseRate),
                          wageType: selectedStaff.wageType
                        }); 
                        setShowAddStaff(true); 
                      }} className="w-5 h-5 rounded-md bg-slate-100 flex items-center justify-center text-[8px] hover:bg-indigo-50 hover:text-indigo-600 transition-colors">✎</button>
                   </div>
                </div>
              </div>

              <div className="flex items-center gap-1 bg-slate-50 p-1 rounded-full border border-slate-100 shadow-inner">
                 <button onClick={() => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() - 1))} className="w-10 h-10 flex items-center justify-center hover:bg-white rounded-full text-slate-400 transition-all active:scale-90 shadow-sm border border-transparent">←</button>
                 <span className="px-4 text-[9px] font-black uppercase tracking-[0.2em] text-slate-800">{monthName}</span>
                 <button onClick={() => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() + 1))} className="w-10 h-10 flex items-center justify-center hover:bg-white rounded-full text-slate-400 transition-all active:scale-90 shadow-sm border border-transparent">→</button>
              </div>
            </div>

            {/* SCROLLABLE CALENDAR GRID */}
            <div className="flex-1 overflow-hidden p-4 bg-slate-50/40">
              <div className="h-full border border-slate-200 rounded-[2rem] bg-white shadow-xl overflow-hidden flex flex-col">
                <div className="grid grid-cols-7 border-b border-slate-100 shrink-0 bg-slate-50/50">
                  {['S','M','T','W','T','F','S'].map((d, i) => (
                    <div key={i} className="py-4 text-center text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">{d}</div>
                  ))}
                </div>
                <div className="flex-1 grid grid-cols-7 auto-rows-fr overflow-y-auto no-scrollbar">
                  {Array.from({ length: new Date(viewDate.getFullYear(), viewDate.getMonth(), 1).getDay() }).map((_, i) => (
                    <div key={`empty-${i}`} className="border-r border-b border-slate-50 bg-slate-50/10"></div>
                  ))}
                  {Array.from({ length: daysInMonth }).map((_, i) => {
                    const day = i + 1;
                    const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
                    const log = getAttendanceStatusForDay(selectedStaff, dateStr);
                    const isActive = selectedDay === day;

                    return (
                      <div 
                        key={day} 
                        onClick={() => setSelectedDay(day)}
                        className={`group flex flex-col items-center justify-center border-r border-b border-slate-50 cursor-pointer transition-all relative ${isActive ? 'bg-indigo-600 text-white z-10 scale-[1.02] shadow-xl' : 'hover:bg-slate-50/60'}`}
                      >
                        <span className={`text-sm font-black transition-all ${isActive ? 'scale-110' : 'text-slate-400 group-hover:text-slate-800'}`}>{day}</span>

                        <div className="mt-1 h-2 flex items-center justify-center">
                          {log.status === 'Present' ? (
                            <div className={`w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white' : (log.isSubstitute ? 'bg-amber-400' : 'bg-emerald-500')}`}></div>
                          ) : log.status === 'Absent' ? (
                            <div className={`w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white/40' : 'bg-rose-400'}`}></div>
                          ) : null}
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>

            {/* ACTIONS FOOTER */}
            <div className="p-6 border-t border-slate-100 bg-white">
               <div className="flex flex-col lg:flex-row items-stretch lg:items-center gap-4">
                  <div className="flex-1 flex gap-3">
                     <button 
                       onClick={() => handleAttendanceToggle('Present')}
                       className={`flex-1 py-4 rounded-[1.25rem] border-2 flex items-center justify-center gap-2 transition-all active:scale-95 ${selectedLog?.status === 'Present' && !selectedLog.isSubstitute ? 'bg-emerald-500 border-emerald-600 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-400 hover:bg-emerald-50 hover:text-emerald-600'}`}
                     >
                        <span className="text-lg">✅</span>
                        <span className="text-[9px] font-black uppercase tracking-widest hidden sm:inline">Present</span>
                     </button>
                     <button 
                       onClick={() => handleAttendanceToggle('Absent')}
                       className={`flex-1 py-4 rounded-[1.25rem] border-2 flex items-center justify-center gap-2 transition-all active:scale-95 ${selectedLog?.status === 'Absent' ? 'bg-rose-500 border-rose-600 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-400 hover:bg-rose-50 hover:text-rose-600'}`}
                     >
                        <span className="text-lg">❌</span>
                        <span className="text-[9px] font-black uppercase tracking-widest hidden sm:inline">Absent</span>
                     </button>
                     <button 
                       onClick={() => openSwapModal(selectedDay)}
                       className={`flex-1 py-4 rounded-[1.25rem] border-2 flex items-center justify-center gap-2 transition-all active:scale-95 ${selectedLog?.isSubstitute ? 'bg-amber-500 border-amber-600 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-400 hover:bg-amber-50 hover:text-amber-600'}`}
                     >
                        <span className="text-lg">🔄</span>
                        <span className="text-[9px] font-black uppercase tracking-widest hidden sm:inline">Swap</span>
                     </button>
                  </div>

                  <div className="lg:w-64 p-5 bg-slate-900 rounded-[1.5rem] text-white flex items-center justify-between gap-4 shadow-xl">
                     <div className="min-w-0">
                        <p className="text-[8px] font-black text-indigo-400 uppercase tracking-widest mb-1">Dues</p>
                        <p className="text-xl font-black tracking-tighter truncate">{formatCurrency(calculateMonthlyTotal(selectedStaff), currency).split('.')[0]}</p>
                     </div>
                     <button onClick={() => setShowSettleModal(selectedStaff)} className="px-4 py-2 bg-indigo-600 text-white rounded-xl text-[8px] font-black uppercase tracking-widest hover:bg-indigo-700 transition-all shrink-0">Settle</button>
                  </div>
               </div>
            </div>
          </>
        ) : (
          <div className="h-full flex flex-col items-center justify-center p-12 text-center bg-slate-50/20">
             <div className="w-20 h-20 bg-white rounded-[2rem] flex items-center justify-center text-4xl mb-6 shadow-xl border border-slate-100 animate-float">📈</div>
             <h4 className="text-xl font-black text-slate-800 uppercase tracking-tighter">Personnel Control</h4>
             <p className="text-[10px] font-black text-slate-400 uppercase mt-4 tracking-widest leading-loose max-w-xs">
               Select or onboard staff to manage daily logs and monthly settlements.
             </p>
          </div>
        )}
      </div>

      {/* MODALS */}
      {swapOverride && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/90 backdrop-blur-md p-6">
           <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-8 shadow-2xl animate-in zoom-in-95 border border-slate-200">
              <div className="flex justify-between items-center mb-8">
                 <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter">Duty Swap</h3>
                 <button onClick={() => setSwapOverride(null)} className="text-slate-300 hover:text-slate-800 text-2xl font-black">✕</button>
              </div>

              <div className="space-y-3">
                 {[
                   { id: 'OWN', label: 'Primary Personnel', icon: '👤' },
                   { id: 'PROXY', label: 'Proxy Substitute', icon: '🔄' },
                   { id: 'BOTH', label: 'Double Log', icon: '⭐' },
                   { id: 'REMOVE', label: 'Clear Entry', icon: '🧹' }
                 ].map(t => (
                   <button key={t.id} onClick={() => setSwapType(t.id as any)} className={`w-full p-4 text-left rounded-2xl border-2 transition-all flex items-center gap-4 group ${swapType === t.id ? 'bg-indigo-600 border-indigo-700 text-white' : 'bg-slate-50 border-transparent hover:border-slate-200'}`}>
                      <span className="text-2xl">{t.icon}</span>
                      <p className={`text-[11px] font-black uppercase ${swapType === t.id ? 'text-white' : 'text-slate-800'}`}>{t.label}</p>
                   </button>
                 ))}
              </div>

              <div className="flex gap-3 mt-8">
                 <button onClick={() => setSwapOverride(null)} className="flex-1 py-4 bg-slate-100 text-slate-400 font-black text-[10px] uppercase rounded-xl">Cancel</button>
                 <button onClick={handleCommitSwap} className="flex-[2] py-4 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-xl shadow-lg active:scale-95 transition-all">Confirm Swap</button>
              </div>
           </div>
        </div>
      )}

      {showAddStaff && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/90 backdrop-blur-md p-6">
           <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-8 border border-slate-200 shadow-2xl animate-in zoom-in-95">
              <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter mb-8">{editingStaffId ? 'Update Personnel' : 'Onboard Help'}</h3>
              <div className="space-y-6">
                 <div className="space-y-1">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-2">Name</label>
                    <input autoFocus className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl font-black text-xs uppercase outline-none focus:ring-4 focus:ring-indigo-600/5 transition-all" value={staffFormData.name} onChange={e => setStaffFormData({...staffFormData, name: e.target.value})} placeholder="Full Identity" />
                 </div>
                 <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1">
                       <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-2">Wage Basis</label>
                       <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl font-black text-[10px] outline-none cursor-pointer" value={staffFormData.wageType} onChange={e => setStaffFormData({...staffFormData, wageType: e.target.value as WageType})}>
                          <option value="Monthly">Monthly</option>
                          <option value="Daily">Daily</option>
                       </select>
                    </div>
                    <div className="space-y-1">
                       <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-2">Role</label>
                       <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl font-black text-[10px] outline-none cursor-pointer" value={staffFormData.role} onChange={e => setStaffFormData({...staffFormData, role: e.target.value})}>
                          <option>Maid</option><option>Cook</option><option>Driver</option><option>Helper</option>
                       </select>
                    </div>
                 </div>
                 <div className="space-y-1">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-2">Rate ({currency})</label>
                    <input type="number" className="w-full p-6 bg-slate-900 text-white border border-slate-800 rounded-2xl font-black text-3xl text-center outline-none" value={staffFormData.baseRate} onChange={e => setStaffFormData({...staffFormData, baseRate: e.target.value})} />
                 </div>
                 <div className="flex gap-3 pt-4">
                    <button onClick={() => { setShowAddStaff(false); resetForm(); }} className="flex-1 py-4 bg-slate-100 text-slate-400 font-black text-[10px] uppercase rounded-xl">Cancel</button>
                    <button onClick={() => {
                      if (!staffFormData.name.trim()) return alert("Identity required.");
                      const staffData: Staff = {
                        id: editingStaffId || Math.random().toString(36).substr(2, 9),
                        name: staffFormData.name, role: staffFormData.role,
                        baseRate: Number(staffFormData.baseRate), wageType: staffFormData.wageType,
                        attendance: editingStaffId ? (staffList.find(s => s.id === editingStaffId)?.attendance || []) : [],
                        joiningDate: staffFormData.joiningDate
                      };
                      if (editingStaffId) updateStaff(staffData); else addStaff(staffData);
                      setShowAddStaff(false); resetForm();
                    }} className="flex-[2] py-4 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-xl shadow-lg active:scale-95 transition-all">Onboard</button>
                 </div>
              </div>
           </div>
        </div>
      )}

      {showSettleModal && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/95 backdrop-blur-2xl p-6">
           <div className="bg-white w-full max-w-sm rounded-[3rem] p-10 shadow-2xl text-center animate-in zoom-in-95 border border-slate-200">
              {!isRecordingSuccess ? (
                <>
                  <div className="w-16 h-16 bg-emerald-50 text-emerald-600 rounded-full flex items-center justify-center text-3xl mx-auto mb-6 shadow-inner border border-emerald-100">💸</div>
                  <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tighter mb-1">Wage Settlement</h3>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-8">{monthName}</p>

                  <div className="p-8 bg-slate-50 rounded-3xl mb-8 shadow-inner border border-slate-100">
                    <p className="text-4xl font-black text-emerald-600 tracking-tighter">{formatCurrency(calculateMonthlyTotal(showSettleModal), currency).split('.')[0]}</p>
                    <p className="text-[9px] font-black text-slate-400 uppercase mt-3 tracking-widest">Calculated Balance</p>
                  </div>

                  <div className="space-y-6">
                    <div className="space-y-1">
                       <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block text-left ml-2">Source Fund</label>
                       <select className="w-full p-4 bg-slate-100 border border-slate-200 rounded-xl font-black text-xs outline-none cursor-pointer" value={settlementMode?.id || ''} onChange={(e) => {
                           const acc = availableAccounts.find(a => a.id === e.target.value);
                           if (acc) setSettlementMode(acc);
                         }}>
                         <option value="">Select Account</option>
                         {availableAccounts.map(acc => (<option key={acc.id} value={acc.id}>{acc.name} ({acc.type})</option>))}
                       </select>
                    </div>

                    <div className="flex flex-col gap-3">
                      <button onClick={() => handleSettle(showSettleModal)} className="w-full py-5 bg-indigo-600 text-white font-black text-xs uppercase rounded-xl shadow-xl shadow-indigo-100 active:scale-95">Verify & Post</button>
                      <button onClick={() => { setShowSettleModal(null); setSettlementMode(null); }} className="w-full py-3 bg-slate-100 text-slate-400 font-black text-[9px] uppercase rounded-xl">Abort</button>
                    </div>
                  </div>
                </>
              ) : (
                <div className="animate-in zoom-in-95 duration-700 py-6">
                  <div className="w-24 h-24 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-xl border border-emerald-200 animate-bounce">✅</div>
                  <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tighter mb-2">Success</h3>
                  <p className="text-[10px] font-black text-slate-400 uppercase mb-10 tracking-widest">Payout Entry Archived</p>
                  <button onClick={() => { setShowSettleModal(null); setIsRecordingSuccess(false); }} className="w-full py-5 bg-slate-900 text-white font-black text-xs uppercase rounded-xl shadow-2xl">Close</button>
                </div>
              )}
           </div>
        </div>
      )}
    </div>
  );
};

export default StaffManager;

import React, { useState, useMemo, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Staff, StaffAttendance, WageType, Transaction } from '../types';

const StaffManager: React.FC = () => {
  const { state, addStaff, updateStaff, deleteStaff, logStaffAttendance, addTransaction } = useFinance();
  const [showAddStaff, setShowAddStaff] = useState(false);
  const [editingStaffId, setEditingStaffId] = useState<string | null>(null);
  const [selectedStaffId, setSelectedStaffId] = useState<string | null>(null);
  const [viewDate, setViewDate] = useState(new Date());
  const [showSettleModal, setShowSettleModal] = useState<Staff | null>(null);
  const [swapOverride, setSwapOverride] = useState<{ day: number, dateStr: string } | null>(null);
  const [selectedDay, setSelectedDay] = useState<number>(new Date().getDate());

  const [settlementMode, setSettlementMode] = useState<{ id: string, name: string, type: 'bank' | 'card' | 'wallet' | 'liability' } | null>(null);
  const [isRecordingSuccess, setIsRecordingSuccess] = useState(false);

  const [staffFormData, setStaffFormData] = useState({ 
    name: '', role: 'Maid', customRole: '', baseRate: '500', wageType: 'Daily' as WageType,
    joiningDate: new Date().toISOString().split('T')[0], exitDate: ''
  });

  const [swapType, setSwapType] = useState<'OWN' | 'PROXY' | 'BOTH' | 'REMOVE'>('OWN');
  const [proxyRate, setProxyRate] = useState<string>('0');

  const currency = state.profile.currency;
  const staffList = state.staff || [];
  const selectedStaff = staffList.find(s => s.id === selectedStaffId);

  // Initialize selection
  useEffect(() => {
    if (!selectedStaffId && staffList.length > 0) {
      setSelectedStaffId(staffList[0].id);
    }
  }, [staffList, selectedStaffId]);

  const daysInMonth = useMemo(() => {
    return new Date(viewDate.getFullYear(), viewDate.getMonth() + 1, 0).getDate();
  }, [viewDate]);

  // Clamp selected day when month changes
  useEffect(() => {
    if (selectedDay > daysInMonth) {
      setSelectedDay(daysInMonth);
    }
  }, [viewDate, daysInMonth, selectedDay]);

  const availableAccounts = useMemo(() => {
    const list: { id: string, name: string, type: 'bank' | 'card' | 'wallet' | 'liability' }[] = [];
    state.banks.forEach(b => list.push({ id: b.id, name: b.name, type: 'bank' }));
    state.wallets.forEach(w => list.push({ id: w.id, name: w.name, type: 'wallet' }));
    state.cards.forEach(c => list.push({ id: c.id, name: c.lenderName, type: 'card' }));
    return list;
  }, [state]);

  const monthName = viewDate.toLocaleString('default', { month: 'long', year: 'numeric' });

  const resetForm = () => {
    setStaffFormData({
      name: '', role: 'Maid', baseRate: '500', wageType: 'Daily',
      joiningDate: new Date().toISOString().split('T')[0], exitDate: ''
    });
    setEditingStaffId(null);
  };

  const getAttendanceStatusForDay = (staff: Staff, dateStr: string) => {
    const manualLog = staff.attendance?.find(a => a.date === dateStr);
    if (manualLog) return manualLog;

    const today = new Date().toISOString().split('T')[0];
    const joining = staff.joiningDate;
    const exit = staff.exitDate;

    // Tenure check for default "Present" logic
    if (dateStr >= joining && (!exit || dateStr <= exit) && dateStr <= today) {
       let rate = staff.baseRate;
       if (staff.wageType === 'Monthly') {
          const d = new Date(dateStr);
          rate = staff.baseRate / new Date(d.getFullYear(), d.getMonth() + 1, 0).getDate();
       }
       return { status: 'Present' as const, rate: rate, isSubstitute: false, isDefault: true };
    }
    return { status: 'None' as const, rate: 0, isSubstitute: false, isDefault: true };
  };

  const openSwapModal = (day: number) => {
    const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSwapOverride({ day, dateStr });
  };

  const handleCommitSwap = () => {
    if (!selectedStaff || !swapOverride) return;
    if (swapType === 'REMOVE') {
      logStaffAttendance(selectedStaff.id, { date: swapOverride.dateStr, status: 'None' });
    } else {
      let finalRate = swapType === 'OWN' ? Number(selectedStaff.baseRate) : (swapType === 'PROXY' ? Number(proxyRate) : Number(selectedStaff.baseRate) + Number(proxyRate));
      logStaffAttendance(selectedStaff.id, {
        date: swapOverride.dateStr, status: 'Present', rate: finalRate, isSubstitute: swapType !== 'OWN'
      });
    }
    setSwapOverride(null);
  };

  const calculateMonthlyTotal = (staff: Staff) => {
    let total = 0;
    for (let i = 1; i <= daysInMonth; i++) {
      const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(i).padStart(2, '0')}`;
      const log = getAttendanceStatusForDay(staff, dateStr);
      if (log.status === 'Present') total += log.rate;
    }
    return total;
  };

  const handleSettle = (staff: Staff) => {
    if (!settlementMode) return alert("Select target account first.");
    const amount = calculateMonthlyTotal(staff);
    if (amount <= 0) return alert("No dues to settle.");

    const tx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'Expense',
      amount: amount,
      nature: staff.name,
      description: `Wages payout for ${monthName}`,
      accountId: settlementMode.id,
      accountType: settlementMode.type,
      date: new Date().toISOString().split('T')[0],
      status: 'active'
    };

    addTransaction(tx);
    setIsRecordingSuccess(true);
    setSettlementMode(null);
  };

  const handleAttendanceToggle = (targetStatus: 'Present' | 'Absent') => {
    if (!selectedStaff) return;
    const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(selectedDay).padStart(2, '0')}`;
    const currentLog = getAttendanceStatusForDay(selectedStaff, dateStr);

    if (!(currentLog as any).isDefault && currentLog.status === targetStatus) {
      logStaffAttendance(selectedStaff.id, { date: dateStr, status: 'None' });
      return;
    }

    let rate = targetStatus === 'Present' ? selectedStaff.baseRate : 0;
    if (targetStatus === 'Present' && selectedStaff.wageType === 'Monthly') {
      const d = new Date(dateStr);
      rate = selectedStaff.baseRate / new Date(d.getFullYear(), d.getMonth() + 1, 0).getDate();
    }

    logStaffAttendance(selectedStaff.id, { 
      date: dateStr, 
      status: targetStatus, 
      rate: rate, 
      isSubstitute: false 
    });
  };

  const selectedDateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(selectedDay).padStart(2, '0')}`;
  const selectedLog = selectedStaff ? getAttendanceStatusForDay(selectedStaff, selectedDateStr) : null;

  return (
    <div className="h-[calc(100dvh-120px)] flex flex-col md:flex-row gap-4 animate-in fade-in duration-500 overflow-hidden font-sans p-2">

      {/* PERSONNEL REGISTRY - SCROLLABLE LIST */}
      <div className="w-full md:w-72 flex flex-col bg-white border border-slate-200 rounded-[2rem] overflow-hidden shadow-sm shrink-0">
        <div className="p-5 border-b border-slate-100 flex justify-between items-center bg-slate-50/50 shrink-0">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Registry</h3>
          <button 
            onClick={() => { resetForm(); setShowAddStaff(true); }} 
            className="w-8 h-8 flex items-center justify-center bg-indigo-600 text-white rounded-xl text-lg shadow-lg hover:scale-105 transition-transform"
          >
            +
          </button>
        </div>

        <div className="flex-1 overflow-y-auto no-scrollbar p-3 space-y-2">
          {staffList.map(s => (
            <div 
              key={s.id} 
              onClick={() => setSelectedStaffId(s.id)} 
              className={`p-4 rounded-2xl flex items-center gap-3 cursor-pointer transition-all border ${selectedStaffId === s.id ? 'bg-indigo-600 border-indigo-700 text-white shadow-lg' : 'bg-white border-slate-100 text-slate-800 hover:bg-slate-50'}`}
            >
              <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-lg shrink-0 ${selectedStaffId === s.id ? 'bg-white/20' : 'bg-slate-100'}`}>👤</div>
              <div className="min-w-0 flex-1">
                <p className={`text-[11px] font-black uppercase truncate ${selectedStaffId === s.id ? 'text-white' : 'text-slate-800'}`}>{s.name}</p>
                <p className={`text-[9px] font-black uppercase tracking-widest mt-0.5 ${selectedStaffId === s.id ? 'text-white/60' : 'text-slate-400'}`}>{s.role}</p>
              </div>
            </div>
          ))}
          {staffList.length === 0 && (
            <div className="py-20 text-center flex flex-col items-center gap-3">
               <div className="text-3xl opacity-20">👥</div>
               <p className="text-[9px] font-black text-slate-300 uppercase tracking-widest">No Personnel</p>
            </div>
          )}
        </div>
      </div>

      {/* MAIN WORKSPACE: CALENDAR GRID & ACTIONS */}
      <div className="flex-1 flex flex-col bg-white border border-slate-200 rounded-[2.5rem] overflow-hidden shadow-sm">
        {selectedStaff ? (
          <>
            {/* WORKSPACE HEADER */}
            <div className="p-6 border-b border-slate-100 flex flex-col sm:flex-row justify-between items-center gap-4 bg-white shrink-0">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-slate-900 text-white rounded-2xl flex items-center justify-center text-xl font-black">
                  {selectedStaff.name.charAt(0)}
                </div>
                <div>
                   <h2 className="text-lg font-black text-slate-900 uppercase tracking-tighter leading-none mb-1">{selectedStaff.name}</h2>
                   <div className="flex items-center gap-2">
                      <p className="text-[9px] font-black text-indigo-600 uppercase tracking-widest">{selectedStaff.role}</p>
                      <button onClick={() => { 
                        setEditingStaffId(selectedStaff.id); 
                        setStaffFormData({ 
                          ...staffFormData, 
                          name: selectedStaff.name, 
                          role: selectedStaff.role,
                          baseRate: String(selectedStaff.baseRate),
                          wageType: selectedStaff.wageType
                        }); 
                        setShowAddStaff(true); 
                      }} className="w-5 h-5 rounded-md bg-slate-100 flex items-center justify-center text-[8px] hover:bg-indigo-50 hover:text-indigo-600 transition-colors">✎</button>
                   </div>
                </div>
              </div>

              <div className="flex items-center gap-1 bg-slate-50 p-1 rounded-full border border-slate-100 shadow-inner">
                 <button onClick={() => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() - 1))} className="w-10 h-10 flex items-center justify-center hover:bg-white rounded-full text-slate-400 transition-all active:scale-90 shadow-sm border border-transparent">←</button>
                 <span className="px-4 text-[9px] font-black uppercase tracking-[0.2em] text-slate-800">{monthName}</span>
                 <button onClick={() => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() + 1))} className="w-10 h-10 flex items-center justify-center hover:bg-white rounded-full text-slate-400 transition-all active:scale-90 shadow-sm border border-transparent">→</button>
              </div>
            </div>

            {/* SCROLLABLE CALENDAR GRID - Fixed Visibility with flex-1 min-h-0 */}
            <div className="flex-1 overflow-hidden p-4 bg-slate-50/40 flex flex-col min-h-0">
              <div className="flex-1 border border-slate-200 rounded-[2rem] bg-white shadow-xl overflow-hidden flex flex-col min-h-0">
                <div className="grid grid-cols-7 border-b border-slate-100 shrink-0 bg-slate-50/50">
                  {['S','M','T','W','T','F','S'].map((d, i) => (
                    <div key={i} className="py-4 text-center text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">{d}</div>
                  ))}
                </div>
                <div className="flex-1 grid grid-cols-7 auto-rows-fr overflow-y-auto no-scrollbar min-h-0">
                  {Array.from({ length: new Date(viewDate.getFullYear(), viewDate.getMonth(), 1).getDay() }).map((_, i) => (
                    <div key={`empty-${i}`} className="border-r border-b border-slate-50 bg-slate-50/10"></div>
                  ))}
                  {Array.from({ length: daysInMonth }).map((_, i) => {
                    const day = i + 1;
                    const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
                    const log = getAttendanceStatusForDay(selectedStaff, dateStr);
                    const isActive = selectedDay === day;

                    return (
                      <div 
                        key={day} 
                        onClick={() => setSelectedDay(day)}
                        className={`group flex flex-col items-center justify-center border-r border-b border-slate-50 cursor-pointer transition-all relative ${isActive ? 'bg-indigo-600 text-white z-10 scale-[1.02] shadow-xl' : 'hover:bg-slate-50/60'}`}
                      >
                        <span className={`text-sm font-black transition-all ${isActive ? 'scale-110' : 'text-slate-400 group-hover:text-slate-800'}`}>{day}</span>

                        <div className="mt-1 h-2 flex items-center justify-center">
                          {log.status === 'Present' ? (
                            <div className={`w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white' : (log.isSubstitute ? 'bg-amber-400' : 'bg-emerald-500')}`}></div>
                          ) : log.status === 'Absent' ? (
                            <div className={`w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white/40' : 'bg-rose-400'}`}></div>
                          ) : null}
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>

            {/* ACTIONS FOOTER */}
            <div className="p-6 border-t border-slate-100 bg-white shrink-0">
               <div className="flex flex-col lg:flex-row items-stretch lg:items-center gap-4">
                  <div className="flex-1 flex gap-3">
                     <button 
                       onClick={() => handleAttendanceToggle('Present')}
                       className={`flex-1 py-4 rounded-[1.25rem] border-2 flex items-center justify-center gap-2 transition-all active:scale-95 ${selectedLog?.status === 'Present' && !selectedLog.isSubstitute ? 'bg-emerald-500 border-emerald-600 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-400 hover:bg-emerald-50 hover:text-emerald-600'}`}
                     >
                        <span className="text-lg">✅</span>
                        <span className="text-[9px] font-black uppercase tracking-widest hidden sm:inline">Present</span>
                     </button>
                     <button 
                       onClick={() => handleAttendanceToggle('Absent')}
                       className={`flex-1 py-4 rounded-[1.25rem] border-2 flex items-center justify-center gap-2 transition-all active:scale-95 ${selectedLog?.status === 'Absent' ? 'bg-rose-500 border-rose-600 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-400 hover:bg-rose-50 hover:text-rose-600'}`}
                     >
                        <span className="text-lg">❌</span>
                        <span className="text-[9px] font-black uppercase tracking-widest hidden sm:inline">Absent</span>
                     </button>
                     <button 
                       onClick={() => openSwapModal(selectedDay)}
                       className={`flex-1 py-4 rounded-[1.25rem] border-2 flex items-center justify-center gap-2 transition-all active:scale-95 ${selectedLog?.isSubstitute ? 'bg-amber-500 border-amber-600 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-400 hover:bg-amber-50 hover:text-amber-600'}`}
                     >
                        <span className="text-lg">🔄</span>
                        <span className="text-[9px] font-black uppercase tracking-widest hidden sm:inline">Swap</span>
                     </button>
                  </div>

                  <div className="lg:w-64 p-5 bg-slate-900 rounded-[1.5rem] text-white flex items-center justify-between gap-4 shadow-xl">
                     <div className="min-w-0">
                        <p className="text-[8px] font-black text-indigo-400 uppercase tracking-widest mb-1">Dues</p>
                        <p className="text-xl font-black tracking-tighter truncate">{formatCurrency(calculateMonthlyTotal(selectedStaff), currency).split('.')[0]}</p>
                     </div>
                     <button onClick={() => setShowSettleModal(selectedStaff)} className="px-4 py-2 bg-indigo-600 text-white rounded-xl text-[8px] font-black uppercase tracking-widest hover:bg-indigo-700 transition-all shrink-0">Settle</button>
                  </div>
               </div>
            </div>
          </>
        ) : (
          <div className="h-full flex flex-col items-center justify-center p-12 text-center bg-slate-50/20">
             <div className="w-20 h-20 bg-white rounded-[2rem] flex items-center justify-center text-4xl mb-6 shadow-xl border border-slate-100 animate-float">📈</div>
             <h4 className="text-xl font-black text-slate-800 uppercase tracking-tighter">Personnel Control</h4>
             <p className="text-[10px] font-black text-slate-400 uppercase mt-4 tracking-widest leading-loose max-w-xs">
               Select or onboard staff to manage daily logs and monthly settlements.
             </p>
          </div>
        )}
      </div>

      {/* MODALS */}
      {swapOverride && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/90 backdrop-blur-md p-6">
           <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-8 shadow-2xl animate-in zoom-in-95 border border-slate-200">
              <div className="flex justify-between items-center mb-8">
                 <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter">Duty Swap</h3>
                 <button onClick={() => setSwapOverride(null)} className="text-slate-300 hover:text-slate-800 text-2xl font-black">✕</button>
              </div>

              <div className="space-y-3">
                 {[
                   { id: 'OWN', label: 'Primary Personnel', icon: '👤' },
                   { id: 'PROXY', label: 'Proxy Substitute', icon: '🔄' },
                   { id: 'BOTH', label: 'Double Log', icon: '⭐' },
                   { id: 'REMOVE', label: 'Clear Entry', icon: '🧹' }
                 ].map(t => (
                   <button key={t.id} onClick={() => setSwapType(t.id as any)} className={`w-full p-4 text-left rounded-2xl border-2 transition-all flex items-center gap-4 group ${swapType === t.id ? 'bg-indigo-600 border-indigo-700 text-white' : 'bg-slate-50 border-transparent hover:border-slate-200'}`}>
                      <span className="text-2xl">{t.icon}</span>
                      <p className={`text-[11px] font-black uppercase ${swapType === t.id ? 'text-white' : 'text-slate-800'}`}>{t.label}</p>
                   </button>
                 ))}
              </div>

              <div className="flex gap-3 mt-8">
                 <button onClick={() => setSwapOverride(null)} className="flex-1 py-4 bg-slate-100 text-slate-400 font-black text-[10px] uppercase rounded-xl">Cancel</button>
                 <button onClick={handleCommitSwap} className="flex-[2] py-4 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-xl shadow-lg active:scale-95 transition-all">Confirm Swap</button>
              </div>
           </div>
        </div>
      )}

      {showAddStaff && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/90 backdrop-blur-md p-6">
           <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-8 border border-slate-200 shadow-2xl animate-in zoom-in-95">
              <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter mb-8">{editingStaffId ? 'Update Personnel' : 'Onboard Help'}</h3>
              <div className="space-y-6">
                 <div className="space-y-1">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-2">Name</label>
                    <input autoFocus className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl font-black text-xs uppercase outline-none focus:ring-4 focus:ring-indigo-600/5 transition-all" value={staffFormData.name} onChange={e => setStaffFormData({...staffFormData, name: e.target.value})} placeholder="Full Identity" />
                 </div>
                 <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1">
                       <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-2">Wage Basis</label>
                       <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl font-black text-[10px] outline-none cursor-pointer" value={staffFormData.wageType} onChange={e => setStaffFormData({...staffFormData, wageType: e.target.value as WageType})}>
                          <option value="Monthly">Monthly</option>
                          <option value="Daily">Daily</option>
                       </select>
                    </div>
                    <div className="space-y-1">
                       <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-2">Role</label>
                       <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl font-black text-[10px] outline-none cursor-pointer" value={staffFormData.role} onChange={e => setStaffFormData({...staffFormData, role: e.target.value})}>
                          <option>Maid</option><option>Cook</option><option>Driver</option><option>Helper</option>
                       </select>
                    </div>
                 </div>
                 <div className="space-y-1">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-2">Rate ({currency})</label>
                    <input type="number" className="w-full p-6 bg-slate-900 text-white border border-slate-800 rounded-2xl font-black text-3xl text-center outline-none" value={staffFormData.baseRate} onChange={e => setStaffFormData({...staffFormData, baseRate: e.target.value})} />
                 </div>
                 <div className="flex gap-3 pt-4">
                    <button onClick={() => { setShowAddStaff(false); resetForm(); }} className="flex-1 py-4 bg-slate-100 text-slate-400 font-black text-[10px] uppercase rounded-xl">Cancel</button>
                    <button onClick={() => {
                      if (!staffFormData.name.trim()) return alert("Identity required.");
                      const staffData: Staff = {
                        id: editingStaffId || Math.random().toString(36).substr(2, 9),
                        name: staffFormData.name, role: staffFormData.role,
                        baseRate: Number(staffFormData.baseRate), wageType: staffFormData.wageType,
                        attendance: editingStaffId ? (staffList.find(s => s.id === editingStaffId)?.attendance || []) : [],
                        joiningDate: staffFormData.joiningDate
                      };
                      if (editingStaffId) updateStaff(staffData); else addStaff(staffData);
                      setShowAddStaff(false); resetForm();
                    }} className="flex-[2] py-4 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-xl shadow-lg active:scale-95 transition-all">Onboard</button>
                 </div>
              </div>
           </div>
        </div>
      )}

      {showSettleModal && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/95 backdrop-blur-2xl p-6">
           <div className="bg-white w-full max-sm rounded-[3rem] p-10 shadow-2xl text-center animate-in zoom-in-95 border border-slate-200">
              {!isRecordingSuccess ? (
                <>
                  <div className="w-16 h-16 bg-emerald-50 text-emerald-600 rounded-full flex items-center justify-center text-3xl mx-auto mb-6 shadow-inner border border-emerald-100">💸</div>
                  <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tighter mb-1">Wage Settlement</h3>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-8">{monthName}</p>

                  <div className="p-8 bg-slate-50 rounded-3xl mb-8 shadow-inner border border-slate-100">
                    <p className="text-4xl font-black text-emerald-600 tracking-tighter">{formatCurrency(calculateMonthlyTotal(showSettleModal), currency).split('.')[0]}</p>
                    <p className="text-[9px] font-black text-slate-400 uppercase mt-3 tracking-widest">Calculated Balance</p>
                  </div>

                  <div className="space-y-6">
                    <div className="space-y-1">
                       <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block text-left ml-2">Source Fund</label>
                       <select className="w-full p-4 bg-slate-100 border border-slate-200 rounded-xl font-black text-xs outline-none cursor-pointer" value={settlementMode?.id || ''} onChange={(e) => {
                           const acc = availableAccounts.find(a => a.id === e.target.value);
                           if (acc) setSettlementMode(acc);
                         }}>
                         <option value="">Select Account</option>
                         {availableAccounts.map(acc => (<option key={acc.id} value={acc.id}>{acc.name} ({acc.type})</option>))}
                       </select>
                    </div>

                    <div className="flex flex-col gap-3">
                      <button onClick={() => handleSettle(showSettleModal)} className="w-full py-5 bg-indigo-600 text-white font-black text-xs uppercase rounded-xl shadow-xl shadow-indigo-100 active:scale-95">Verify & Post</button>
                      <button onClick={() => { setShowSettleModal(null); setSettlementMode(null); }} className="w-full py-3 bg-slate-100 text-slate-400 font-black text-[9px] uppercase rounded-xl">Abort</button>
                    </div>
                  </div>
                </>
              ) : (
                <div className="animate-in zoom-in-95 duration-700 py-6">
                  <div className="w-24 h-24 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-xl border border-emerald-200 animate-bounce">✅</div>
                  <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tighter mb-2">Success</h3>
                  <p className="text-[10px] font-black text-slate-400 uppercase mb-10 tracking-widest">Payout Entry Archived</p>
                  <button onClick={() => { setShowSettleModal(null); setIsRecordingSuccess(false); }} className="w-full py-5 bg-slate-900 text-white font-black text-xs uppercase rounded-xl shadow-2xl">Close</button>
                </div>
              )}
           </div>
        </div>
      )}
    </div>
  );
};

export default StaffManager;

import React, { useState, useMemo, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Staff, StaffAttendance, WageType, Transaction } from '../types';

const StaffManager: React.FC = () => {
  const { state, addStaff, updateStaff, deleteStaff, logStaffAttendance, addTransaction } = useFinance();
  const [showAddStaff, setShowAddStaff] = useState(false);
  const [editingStaffId, setEditingStaffId] = useState<string | null>(null);
  const [selectedStaffId, setSelectedStaffId] = useState<string | null>(null);
  const [viewDate, setViewDate] = useState(new Date());
  const [showSettleModal, setShowSettleModal] = useState<Staff | null>(null);
  const [swapOverride, setSwapOverride] = useState<{ day: number, dateStr: string } | null>(null);
  const [selectedDay, setSelectedDay] = useState<number>(new Date().getDate());

  const [settlementMode, setSettlementMode] = useState<{ id: string, name: string, type: 'bank' | 'card' | 'wallet' | 'liability' } | null>(null);
  const [isRecordingSuccess, setIsRecordingSuccess] = useState(false);

  const [staffFormData, setStaffFormData] = useState({ 
    name: '', role: 'Maid', customRole: '', baseRate: '500', wageType: 'Daily' as WageType,
    joiningDate: new Date().toISOString().split('T')[0], exitDate: ''
  });

  const [swapType, setSwapType] = useState<'OWN' | 'PROXY' | 'BOTH' | 'REMOVE'>('OWN');
  const [proxyRate, setProxyRate] = useState<string>('0');

  const currency = state.profile.currency;
  const staffList = state.staff || [];
  const selectedStaff = staffList.find(s => s.id === selectedStaffId);

  // Initialize selection
  useEffect(() => {
    if (!selectedStaffId && staffList.length > 0) {
      setSelectedStaffId(staffList[0].id);
    }
  }, [staffList, selectedStaffId]);

  const daysInMonth = useMemo(() => {
    return new Date(viewDate.getFullYear(), viewDate.getMonth() + 1, 0).getDate();
  }, [viewDate]);

  // Clamp selected day when month changes
  useEffect(() => {
    if (selectedDay > daysInMonth) {
      setSelectedDay(daysInMonth);
    }
  }, [viewDate, daysInMonth, selectedDay]);

  const availableAccounts = useMemo(() => {
    const list: { id: string, name: string, type: 'bank' | 'card' | 'wallet' | 'liability' }[] = [];
    state.banks.forEach(b => list.push({ id: b.id, name: b.name, type: 'bank' }));
    state.wallets.forEach(w => list.push({ id: w.id, name: w.name, type: 'wallet' }));
    state.cards.forEach(c => list.push({ id: c.id, name: c.lenderName, type: 'card' }));
    return list;
  }, [state]);

  const monthName = viewDate.toLocaleString('default', { month: 'long', year: 'numeric' });

  const resetForm = () => {
    setStaffFormData({
      name: '', role: 'Maid', baseRate: '500', wageType: 'Daily',
      joiningDate: new Date().toISOString().split('T')[0], exitDate: ''
    });
    setEditingStaffId(null);
  };

  const getAttendanceStatusForDay = (staff: Staff, dateStr: string) => {
    const manualLog = staff.attendance?.find(a => a.date === dateStr);
    if (manualLog) return manualLog;

    const today = new Date().toISOString().split('T')[0];
    const joining = staff.joiningDate;
    const exit = staff.exitDate;

    // Tenure check for default "Present" logic
    if (dateStr >= joining && (!exit || dateStr <= exit) && dateStr <= today) {
       let rate = staff.baseRate;
       if (staff.wageType === 'Monthly') {
          const d = new Date(dateStr);
          rate = staff.baseRate / new Date(d.getFullYear(), d.getMonth() + 1, 0).getDate();
       }
       return { status: 'Present' as const, rate: rate, isSubstitute: false, isDefault: true };
    }
    return { status: 'None' as const, rate: 0, isSubstitute: false, isDefault: true };
  };

  const openSwapModal = (day: number) => {
    const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSwapOverride({ day, dateStr });
  };

  const handleCommitSwap = () => {
    if (!selectedStaff || !swapOverride) return;
    if (swapType === 'REMOVE') {
      logStaffAttendance(selectedStaff.id, { date: swapOverride.dateStr, status: 'None' });
    } else {
      let finalRate = swapType === 'OWN' ? Number(selectedStaff.baseRate) : (swapType === 'PROXY' ? Number(proxyRate) : Number(selectedStaff.baseRate) + Number(proxyRate));
      logStaffAttendance(selectedStaff.id, {
        date: swapOverride.dateStr, status: 'Present', rate: finalRate, isSubstitute: swapType !== 'OWN'
      });
    }
    setSwapOverride(null);
  };

  const calculateMonthlyTotal = (staff: Staff) => {
    let total = 0;
    for (let i = 1; i <= daysInMonth; i++) {
      const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(i).padStart(2, '0')}`;
      const log = getAttendanceStatusForDay(staff, dateStr);
      if (log.status === 'Present') total += log.rate;
    }
    return total;
  };

  const handleSettle = (staff: Staff) => {
    if (!settlementMode) return alert("Select target account first.");
    const amount = calculateMonthlyTotal(staff);
    if (amount <= 0) return alert("No dues to settle.");

    const tx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'Expense',
      amount: amount,
      nature: staff.name,
      description: `Wages payout for ${monthName}`,
      accountId: settlementMode.id,
      accountType: settlementMode.type,
      date: new Date().toISOString().split('T')[0],
      status: 'active'
    };

    addTransaction(tx);
    setIsRecordingSuccess(true);
    setSettlementMode(null);
  };

  const handleAttendanceToggle = (targetStatus: 'Present' | 'Absent') => {
    if (!selectedStaff) return;
    const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(selectedDay).padStart(2, '0')}`;
    const currentLog = getAttendanceStatusForDay(selectedStaff, dateStr);

    if (!(currentLog as any).isDefault && currentLog.status === targetStatus) {
      logStaffAttendance(selectedStaff.id, { date: dateStr, status: 'None' });
      return;
    }

    let rate = targetStatus === 'Present' ? selectedStaff.baseRate : 0;
    if (targetStatus === 'Present' && selectedStaff.wageType === 'Monthly') {
      const d = new Date(dateStr);
      rate = selectedStaff.baseRate / new Date(d.getFullYear(), d.getMonth() + 1, 0).getDate();
    }

    logStaffAttendance(selectedStaff.id, { 
      date: dateStr, 
      status: targetStatus, 
      rate: rate, 
      isSubstitute: false 
    });
  };

  const selectedDateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(selectedDay).padStart(2, '0')}`;
  const selectedLog = selectedStaff ? getAttendanceStatusForDay(selectedStaff, selectedDateStr) : null;

  return (
    <div className="h-[calc(100dvh-120px)] flex flex-col md:flex-row gap-4 animate-in fade-in duration-500 overflow-hidden font-sans p-2">

      {/* PERSONNEL REGISTRY - SCROLLABLE LIST */}
      <div className="w-full md:w-72 flex flex-col bg-white border border-slate-200 rounded-[2rem] overflow-hidden shadow-sm shrink-0">
        <div className="p-5 border-b border-slate-100 flex justify-between items-center bg-slate-50/50 shrink-0">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Registry</h3>
          <button 
            onClick={() => { resetForm(); setShowAddStaff(true); }} 
            className="w-8 h-8 flex items-center justify-center bg-indigo-600 text-white rounded-xl text-lg shadow-lg hover:scale-105 transition-transform"
          >
            +
          </button>
        </div>

        <div className="flex-1 overflow-y-auto no-scrollbar p-3 space-y-2">
          {staffList.map(s => (
            <div 
              key={s.id} 
              onClick={() => setSelectedStaffId(s.id)} 
              className={`p-4 rounded-2xl flex items-center gap-3 cursor-pointer transition-all border ${selectedStaffId === s.id ? 'bg-indigo-600 border-indigo-700 text-white shadow-lg' : 'bg-white border-slate-100 text-slate-800 hover:bg-slate-50'}`}
            >
              <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-lg shrink-0 ${selectedStaffId === s.id ? 'bg-white/20' : 'bg-slate-100'}`}>👤</div>
              <div className="min-w-0 flex-1">
                <p className={`text-[11px] font-black uppercase truncate ${selectedStaffId === s.id ? 'text-white' : 'text-slate-800'}`}>{s.name}</p>
                <p className={`text-[9px] font-black uppercase tracking-widest mt-0.5 ${selectedStaffId === s.id ? 'text-white/60' : 'text-slate-400'}`}>{s.role}</p>
              </div>
            </div>
          ))}
          {staffList.length === 0 && (
            <div className="py-20 text-center flex flex-col items-center gap-3">
               <div className="text-3xl opacity-20">👥</div>
               <p className="text-[9px] font-black text-slate-300 uppercase tracking-widest">No Personnel</p>
            </div>
          )}
        </div>
      </div>

      {/* MAIN WORKSPACE: CALENDAR GRID & ACTIONS */}
      <div className="flex-1 flex flex-col bg-white border border-slate-200 rounded-[2.5rem] overflow-hidden shadow-sm min-h-0">
        {selectedStaff ? (
          <>
            {/* WORKSPACE HEADER */}
            <div className="p-6 border-b border-slate-100 flex flex-col sm:flex-row justify-between items-center gap-4 bg-white shrink-0">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-slate-900 text-white rounded-2xl flex items-center justify-center text-xl font-black">
                  {selectedStaff.name.charAt(0)}
                </div>
                <div>
                   <h2 className="text-lg font-black text-slate-900 uppercase tracking-tighter leading-none mb-1">{selectedStaff.name}</h2>
                   <div className="flex items-center gap-2">
                      <p className="text-[9px] font-black text-indigo-600 uppercase tracking-widest">{selectedStaff.role}</p>
                      <button onClick={() => { 
                        setEditingStaffId(selectedStaff.id); 
                        setStaffFormData({ 
                          ...staffFormData, 
                          name: selectedStaff.name, 
                          role: selectedStaff.role,
                          baseRate: String(selectedStaff.baseRate),
                          wageType: selectedStaff.wageType
                        }); 
                        setShowAddStaff(true); 
                      }} className="w-5 h-5 rounded-md bg-slate-100 flex items-center justify-center text-[8px] hover:bg-indigo-50 hover:text-indigo-600 transition-colors">✎</button>
                   </div>
                </div>
              </div>

              <div className="flex items-center gap-1 bg-slate-50 p-1 rounded-full border border-slate-100 shadow-inner">
                 <button onClick={() => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() - 1))} className="w-10 h-10 flex items-center justify-center hover:bg-white rounded-full text-slate-400 transition-all active:scale-90 shadow-sm border border-transparent">←</button>
                 <span className="px-4 text-[9px] font-black uppercase tracking-[0.2em] text-slate-800">{monthName}</span>
                 <button onClick={() => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() + 1))} className="w-10 h-10 flex items-center justify-center hover:bg-white rounded-full text-slate-400 transition-all active:scale-90 shadow-sm border border-transparent">→</button>
              </div>
            </div>

            {/* SCROLLABLE CALENDAR GRID - Robust Container Layout */}
            <div className="flex-1 overflow-hidden p-4 bg-slate-50/40 flex flex-col min-h-0">
              <div className="flex-1 border border-slate-200 rounded-[2rem] bg-white shadow-xl overflow-hidden flex flex-col min-h-0">
                <div className="grid grid-cols-7 border-b border-slate-100 shrink-0 bg-slate-50/50">
                  {['S','M','T','W','T','F','S'].map((d, i) => (
                    <div key={i} className="py-4 text-center text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">{d}</div>
                  ))}
                </div>
                <div className="flex-1 overflow-y-auto no-scrollbar min-h-0">
                  <div className="grid grid-cols-7 gap-px bg-slate-100">
                    {Array.from({ length: new Date(viewDate.getFullYear(), viewDate.getMonth(), 1).getDay() }).map((_, i) => (
                      <div key={`empty-${i}`} className="bg-slate-50/10 aspect-square"></div>
                    ))}
                    {Array.from({ length: daysInMonth }).map((_, i) => {
                      const day = i + 1;
                      const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
                      const log = getAttendanceStatusForDay(selectedStaff, dateStr);
                      const isActive = selectedDay === day;

                      return (
                        <div 
                          key={day} 
                          onClick={() => setSelectedDay(day)}
                          className={`group flex flex-col items-center justify-center aspect-square cursor-pointer transition-all relative ${isActive ? 'bg-indigo-600 text-white z-10 scale-[1.02] shadow-xl' : 'bg-white hover:bg-slate-50/60'}`}
                        >
                          <span className={`text-sm font-black transition-all ${isActive ? 'scale-110' : 'text-slate-400 group-hover:text-slate-800'}`}>{day}</span>

                          <div className="mt-1 h-2 flex items-center justify-center">
                            {log.status === 'Present' ? (
                              <div className={`w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white' : (log.isSubstitute ? 'bg-amber-400' : 'bg-emerald-500')}`}></div>
                            ) : log.status === 'Absent' ? (
                              <div className={`w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white/40' : 'bg-rose-400'}`}></div>
                            ) : null}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </div>
              </div>
            </div>

            {/* ACTIONS FOOTER */}
            <div className="p-6 border-t border-slate-100 bg-white shrink-0">
               <div className="flex flex-col lg:flex-row items-stretch lg:items-center gap-4">
                  <div className="flex-1 flex gap-3">
                     <button 
                       onClick={() => handleAttendanceToggle('Present')}
                       className={`flex-1 py-4 rounded-[1.25rem] border-2 flex items-center justify-center gap-2 transition-all active:scale-95 ${selectedLog?.status === 'Present' && !selectedLog.isSubstitute ? 'bg-emerald-500 border-emerald-600 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-400 hover:bg-emerald-50 hover:text-emerald-600'}`}
                     >
                        <span className="text-lg">✅</span>
                        <span className="text-[9px] font-black uppercase tracking-widest hidden sm:inline">Present</span>
                     </button>
                     <button 
                       onClick={() => handleAttendanceToggle('Absent')}
                       className={`flex-1 py-4 rounded-[1.25rem] border-2 flex items-center justify-center gap-2 transition-all active:scale-95 ${selectedLog?.status === 'Absent' ? 'bg-rose-500 border-rose-600 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-400 hover:bg-rose-50 hover:text-rose-600'}`}
                     >
                        <span className="text-lg">❌</span>
                        <span className="text-[9px] font-black uppercase tracking-widest hidden sm:inline">Absent</span>
                     </button>
                     <button 
                       onClick={() => openSwapModal(selectedDay)}
                       className={`flex-1 py-4 rounded-[1.25rem] border-2 flex items-center justify-center gap-2 transition-all active:scale-95 ${selectedLog?.isSubstitute ? 'bg-amber-500 border-amber-600 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-400 hover:bg-amber-50 hover:text-amber-600'}`}
                     >
                        <span className="text-lg">🔄</span>
                        <span className="text-[9px] font-black uppercase tracking-widest hidden sm:inline">Swap</span>
                     </button>
                  </div>

                  <div className="lg:w-64 p-5 bg-slate-900 rounded-[1.5rem] text-white flex items-center justify-between gap-4 shadow-xl">
                     <div className="min-w-0">
                        <p className="text-[8px] font-black text-indigo-400 uppercase tracking-widest mb-1">Dues</p>
                        <p className="text-xl font-black tracking-tighter truncate">{formatCurrency(calculateMonthlyTotal(selectedStaff), currency).split('.')[0]}</p>
                     </div>
                     <button onClick={() => setShowSettleModal(selectedStaff)} className="px-4 py-2 bg-indigo-600 text-white rounded-xl text-[8px] font-black uppercase tracking-widest hover:bg-indigo-700 transition-all shrink-0">Settle</button>
                  </div>
               </div>
            </div>
          </>
        ) : (
          <div className="h-full flex flex-col items-center justify-center p-12 text-center bg-slate-50/20">
             <div className="w-20 h-20 bg-white rounded-[2rem] flex items-center justify-center text-4xl mb-6 shadow-xl border border-slate-100 animate-float">📈</div>
             <h4 className="text-xl font-black text-slate-800 uppercase tracking-tighter">Personnel Control</h4>
             <p className="text-[10px] font-black text-slate-400 uppercase mt-4 tracking-widest leading-loose max-w-xs">
               Select or onboard staff to manage daily logs and monthly settlements.
             </p>
          </div>
        )}
      </div>

      {/* MODALS */}
      {swapOverride && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/90 backdrop-blur-md p-6">
           <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-8 shadow-2xl animate-in zoom-in-95 border border-slate-200">
              <div className="flex justify-between items-center mb-8">
                 <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter">Duty Swap</h3>
                 <button onClick={() => setSwapOverride(null)} className="text-slate-300 hover:text-slate-800 text-2xl font-black">✕</button>
              </div>

              <div className="space-y-3">
                 {[
                   { id: 'OWN', label: 'Primary Personnel', icon: '👤' },
                   { id: 'PROXY', label: 'Proxy Substitute', icon: '🔄' },
                   { id: 'BOTH', label: 'Double Log', icon: '⭐' },
                   { id: 'REMOVE', label: 'Clear Entry', icon: '🧹' }
                 ].map(t => (
                   <button key={t.id} onClick={() => setSwapType(t.id as any)} className={`w-full p-4 text-left rounded-2xl border-2 transition-all flex items-center gap-4 group ${swapType === t.id ? 'bg-indigo-600 border-indigo-700 text-white' : 'bg-slate-50 border-transparent hover:border-slate-200'}`}>
                      <span className="text-2xl">{t.icon}</span>
                      <p className={`text-[11px] font-black uppercase ${swapType === t.id ? 'text-white' : 'text-slate-800'}`}>{t.label}</p>
                   </button>
                 ))}
              </div>

              <div className="flex gap-3 mt-8">
                 <button onClick={() => setSwapOverride(null)} className="flex-1 py-4 bg-slate-100 text-slate-400 font-black text-[10px] uppercase rounded-xl">Cancel</button>
                 <button onClick={handleCommitSwap} className="flex-[2] py-4 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-xl shadow-lg active:scale-95 transition-all">Confirm Swap</button>
              </div>
           </div>
        </div>
      )}

      {showAddStaff && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/90 backdrop-blur-md p-6">
           <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-8 border border-slate-200 shadow-2xl animate-in zoom-in-95">
              <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter mb-8">{editingStaffId ? 'Update Personnel' : 'Onboard Help'}</h3>
              <div className="space-y-6">
                 <div className="space-y-1">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-2">Name</label>
                    <input autoFocus className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl font-black text-xs uppercase outline-none focus:ring-4 focus:ring-indigo-600/5 transition-all" value={staffFormData.name} onChange={e => setStaffFormData({...staffFormData, name: e.target.value})} placeholder="Full Identity" />
                 </div>
                 <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1">
                       <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-2">Wage Basis</label>
                       <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl font-black text-[10px] outline-none cursor-pointer" value={staffFormData.wageType} onChange={e => setStaffFormData({...staffFormData, wageType: e.target.value as WageType})}>
                          <option value="Monthly">Monthly</option>
                          <option value="Daily">Daily</option>
                       </select>
                    </div>
                    <div className="space-y-1">
                       <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-2">Role</label>
                       <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl font-black text-[10px] outline-none cursor-pointer" value={staffFormData.role} onChange={e => setStaffFormData({...staffFormData, role: e.target.value})}>
                          <option>Maid</option><option>Cook</option><option>Driver</option><option>Helper</option>
                       </select>
                    </div>
                 </div>
                 <div className="space-y-1">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-2">Rate ({currency})</label>
                    <input type="number" className="w-full p-6 bg-slate-900 text-white border border-slate-800 rounded-2xl font-black text-3xl text-center outline-none" value={staffFormData.baseRate} onChange={e => setStaffFormData({...staffFormData, baseRate: e.target.value})} />
                 </div>
                 <div className="flex gap-3 pt-4">
                    <button onClick={() => { setShowAddStaff(false); resetForm(); }} className="flex-1 py-4 bg-slate-100 text-slate-400 font-black text-[10px] uppercase rounded-xl">Cancel</button>
                    <button onClick={() => {
                      if (!staffFormData.name.trim()) return alert("Identity required.");
                      const staffData: Staff = {
                        id: editingStaffId || Math.random().toString(36).substr(2, 9),
                        name: staffFormData.name, role: staffFormData.role,
                        baseRate: Number(staffFormData.baseRate), wageType: staffFormData.wageType,
                        attendance: editingStaffId ? (staffList.find(s => s.id === editingStaffId)?.attendance || []) : [],
                        joiningDate: staffFormData.joiningDate
                      };
                      if (editingStaffId) updateStaff(staffData); else addStaff(staffData);
                      setShowAddStaff(false); resetForm();
                    }} className="flex-[2] py-4 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-xl shadow-lg active:scale-95 transition-all">Onboard</button>
                 </div>
              </div>
           </div>
        </div>
      )}

      {showSettleModal && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/95 backdrop-blur-2xl p-6">
           <div className="bg-white w-full max-w-sm rounded-[3rem] p-10 shadow-2xl text-center animate-in zoom-in-95 border border-slate-200">
              {!isRecordingSuccess ? (
                <>
                  <div className="w-16 h-16 bg-emerald-50 text-emerald-600 rounded-full flex items-center justify-center text-3xl mx-auto mb-6 shadow-inner border border-emerald-100">💸</div>
                  <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tighter mb-1">Wage Settlement</h3>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-8">{monthName}</p>

                  <div className="p-8 bg-slate-50 rounded-3xl mb-8 shadow-inner border border-slate-100">
                    <p className="text-4xl font-black text-emerald-600 tracking-tighter">{formatCurrency(calculateMonthlyTotal(showSettleModal), currency).split('.')[0]}</p>
                    <p className="text-[9px] font-black text-slate-400 uppercase mt-3 tracking-widest">Calculated Balance</p>
                  </div>

                  <div className="space-y-6">
                    <div className="space-y-1">
                       <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block text-left ml-2">Source Fund</label>
                       <select className="w-full p-4 bg-slate-100 border border-slate-200 rounded-xl font-black text-xs outline-none cursor-pointer" value={settlementMode?.id || ''} onChange={(e) => {
                           const acc = availableAccounts.find(a => a.id === e.target.value);
                           if (acc) setSettlementMode(acc);
                         }}>
                         <option value="">Select Account</option>
                         {availableAccounts.map(acc => (<option key={acc.id} value={acc.id}>{acc.name} ({acc.type})</option>))}
                       </select>
                    </div>

                    <div className="flex flex-col gap-3">
                      <button onClick={() => handleSettle(showSettleModal)} className="w-full py-5 bg-indigo-600 text-white font-black text-xs uppercase rounded-xl shadow-xl shadow-indigo-100 active:scale-95">Verify & Post</button>
                      <button onClick={() => { setShowSettleModal(null); setSettlementMode(null); }} className="w-full py-3 bg-slate-100 text-slate-400 font-black text-[9px] uppercase rounded-xl">Abort</button>
                    </div>
                  </div>
                </>
              ) : (
                <div className="animate-in zoom-in-95 duration-700 py-6">
                  <div className="w-24 h-24 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-xl border border-emerald-200 animate-bounce">✅</div>
                  <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tighter mb-2">Success</h3>
                  <p className="text-[10px] font-black text-slate-400 uppercase mb-10 tracking-widest">Payout Entry Archived</p>
                  <button onClick={() => { setShowSettleModal(null); setIsRecordingSuccess(false); }} className="w-full py-5 bg-slate-900 text-white font-black text-xs uppercase rounded-xl shadow-2xl">Close</button>
                </div>
              )}
           </div>
        </div>
      )}
    </div>
  );
};

export default StaffManager;

import React, { useState, useMemo, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Staff, StaffAttendance, WageType, Transaction } from '../types';

const StaffManager: React.FC = () => {
  const { state, addStaff, updateStaff, deleteStaff, logStaffAttendance, addTransaction } = useFinance();
  const [showAddStaff, setShowAddStaff] = useState(false);
  const [editingStaffId, setEditingStaffId] = useState<string | null>(null);
  const [selectedStaffId, setSelectedStaffId] = useState<string | null>(null);
  const [viewDate, setViewDate] = useState(new Date());
  const [showSettleModal, setShowSettleModal] = useState<Staff | null>(null);
  const [swapOverride, setSwapOverride] = useState<{ day: number, dateStr: string } | null>(null);
  const [selectedDay, setSelectedDay] = useState<number>(new Date().getDate());

  const [settlementMode, setSettlementMode] = useState<{ id: string, name: string, type: 'bank' | 'card' | 'wallet' | 'liability' } | null>(null);
  const [isRecordingSuccess, setIsRecordingSuccess] = useState(false);

  const [staffFormData, setStaffFormData] = useState({ 
    name: '', role: 'Maid', baseRate: '500', wageType: 'Daily' as WageType,
    joiningDate: new Date().toISOString().split('T')[0]
  });

  const [swapType, setSwapType] = useState<'OWN' | 'PROXY' | 'BOTH' | 'REMOVE'>('OWN');
  const [proxyRate, setProxyRate] = useState<string>('0');

  const currency = state.profile.currency;
  const staffList = state.staff || [];
  const selectedStaff = staffList.find(s => s.id === selectedStaffId);

  useEffect(() => {
    if (!selectedStaffId && staffList.length > 0) {
      setSelectedStaffId(staffList[0].id);
    }
  }, [staffList, selectedStaffId]);

  const daysInMonth = useMemo(() => {
    return new Date(viewDate.getFullYear(), viewDate.getMonth() + 1, 0).getDate();
  }, [viewDate]);

  useEffect(() => {
    if (selectedDay > daysInMonth) setSelectedDay(daysInMonth);
  }, [viewDate, daysInMonth, selectedDay]);

  const availableAccounts = useMemo(() => {
    const list: { id: string, name: string, type: 'bank' | 'card' | 'wallet' | 'liability' }[] = [];
    state.banks.forEach(b => list.push({ id: b.id, name: b.name, type: 'bank' }));
    state.wallets.forEach(w => list.push({ id: w.id, name: w.name, type: 'wallet' }));
    state.cards.forEach(c => list.push({ id: c.id, name: c.lenderName, type: 'card' }));
    return list;
  }, [state]);

  const monthName = viewDate.toLocaleString('default', { month: 'long', year: 'numeric' });

  const resetForm = () => {
    setStaffFormData({
      name: '', role: 'Maid', baseRate: '500', wageType: 'Daily',
      joiningDate: new Date().toISOString().split('T')[0]
    });
    setEditingStaffId(null);
  };

  const getAttendanceStatusForDay = (staff: Staff, dateStr: string) => {
    const manualLog = staff.attendance?.find(a => a.date === dateStr);
    if (manualLog) return manualLog;
    const today = new Date().toISOString().split('T')[0];
    const joining = staff.joiningDate;
    const exit = staff.exitDate;

    if (dateStr >= joining && (!exit || dateStr <= exit) && dateStr <= today) {
       let rate = staff.baseRate;
       if (staff.wageType === 'Monthly') {
          const d = new Date(dateStr);
          rate = staff.baseRate / new Date(d.getFullYear(), d.getMonth() + 1, 0).getDate();
       }
       return { status: 'Present' as const, rate: rate, isSubstitute: false, isDefault: true };
    }
    return { status: 'None' as const, rate: 0, isSubstitute: false, isDefault: true };
  };

  const currentMonthStats = useMemo(() => {
    if (!selectedStaff) return { present: 0, absent: 0, swap: 0, total: 0 };
    let present = 0, absent = 0, swap = 0, total = 0;
    for (let i = 1; i <= daysInMonth; i++) {
      const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(i).padStart(2, '0')}`;
      const log = getAttendanceStatusForDay(selectedStaff, dateStr);
      if (log.status === 'Present') {
        present++;
        total += log.rate;
        if (log.isSubstitute) swap++;
      } else if (log.status === 'Absent') {
        absent++;
      }
    }
    return { present, absent, swap, total };
  }, [selectedStaff, viewDate, daysInMonth]);

  const handleSettle = (staff: Staff) => {
    if (!settlementMode) return alert("Select target account first.");
    const amount = currentMonthStats.total;
    if (amount <= 0) return alert("No dues to settle.");

    const tx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'Expense',
      amount: amount,
      nature: staff.name,
      description: `Wages payout for ${monthName}`,
      accountId: settlementMode.id,
      accountType: settlementMode.type,
      date: new Date().toISOString().split('T')[0],
      status: 'active'
    };

    addTransaction(tx);
    setIsRecordingSuccess(true);
    setSettlementMode(null);
  };

  const handleAttendanceToggle = (targetStatus: 'Present' | 'Absent') => {
    if (!selectedStaff) return;
    const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(selectedDay).padStart(2, '0')}`;
    const currentLog = getAttendanceStatusForDay(selectedStaff, dateStr);

    if (!(currentLog as any).isDefault && currentLog.status === targetStatus) {
      logStaffAttendance(selectedStaff.id, { date: dateStr, status: 'None' });
      return;
    }

    let rate = targetStatus === 'Present' ? selectedStaff.baseRate : 0;
    if (targetStatus === 'Present' && selectedStaff.wageType === 'Monthly') {
      const d = new Date(dateStr);
      rate = selectedStaff.baseRate / new Date(d.getFullYear(), d.getMonth() + 1, 0).getDate();
    }

    logStaffAttendance(selectedStaff.id, { 
      date: dateStr, 
      status: targetStatus, 
      rate: rate, 
      isSubstitute: false 
    });
  };

  const selectedDateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(selectedDay).padStart(2, '0')}`;
  const selectedLog = selectedStaff ? getAttendanceStatusForDay(selectedStaff, selectedDateStr) : null;

  return (
    <div className="h-[calc(100dvh-120px)] flex flex-col md:flex-row gap-6 animate-in fade-in duration-500 overflow-hidden font-sans p-2">

      {/* LEFT: PERSONNEL REGISTRY */}
      <div className="w-full md:w-80 flex flex-col bg-slate-50 border border-slate-200 rounded-[2.5rem] overflow-hidden shadow-sm shrink-0">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-white">
          <div>
            <h3 className="text-xs font-black text-slate-800 uppercase tracking-widest">Personnel</h3>
            <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">Management Registry</p>
          </div>
          <button 
            onClick={() => { resetForm(); setShowAddStaff(true); }} 
            className="w-10 h-10 flex items-center justify-center bg-indigo-600 text-white rounded-2xl text-xl shadow-lg hover:scale-105 active:scale-95 transition-transform"
          >
            +
          </button>
        </div>

        <div className="flex-1 overflow-y-auto no-scrollbar p-4 space-y-3">
          {staffList.map(s => {
            const isSelected = selectedStaffId === s.id;
            return (
              <div 
                key={s.id} 
                onClick={() => setSelectedStaffId(s.id)} 
                className={`group p-4 rounded-3xl cursor-pointer transition-all border flex items-center justify-between ${isSelected ? 'bg-indigo-600 border-indigo-700 text-white shadow-xl translate-x-2' : 'bg-white border-slate-100 text-slate-800 hover:bg-slate-50'}`}
              >
                <div className="flex items-center gap-4 min-w-0">
                  <div className={`w-11 h-11 rounded-2xl flex items-center justify-center text-lg shrink-0 font-black ${isSelected ? 'bg-white/20' : 'bg-slate-100 text-slate-400'}`}>
                    {s.name.charAt(0)}
                  </div>
                  <div className="min-w-0">
                    <p className={`text-xs font-black uppercase truncate leading-none mb-1 ${isSelected ? 'text-white' : 'text-slate-800'}`}>{s.name}</p>
                    <p className={`text-[9px] font-black uppercase tracking-widest ${isSelected ? 'text-white/60' : 'text-slate-400'}`}>{s.role}</p>
                  </div>
                </div>
                {isSelected && <span className="text-white/40 text-xs">→</span>}
              </div>
            );
          })}
          {staffList.length === 0 && (
            <div className="py-20 text-center flex flex-col items-center gap-4">
               <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center text-3xl opacity-20">👤</div>
               <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.3em]">No Personnel Links</p>
            </div>
          )}
        </div>
      </div>

      {/* RIGHT: WORKSPACE */}
      <div className="flex-1 flex flex-col bg-white border border-slate-200 rounded-[3rem] overflow-hidden shadow-sm min-h-0 relative">
        {selectedStaff ? (
