                    <p className="text-[9px] font-black text-indigo-400 uppercase mt-4 tracking-widest font-black">Verified Dues Balance</p>
                  </div>

                  <div className="space-y-6">
                    <div className="space-y-2">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block text-left ml-3">Source Capital Account</label>
                       <select className="w-full p-5 bg-slate-100 border border-slate-200 rounded-2xl font-black text-xs outline-none cursor-pointer uppercase" value={settlementMode?.id || ''} onChange={(e) => {
