                        >
                          <span className={`text-base font-black transition-all ${isActive ? 'scale-110' : 'text-slate-400 group-hover:text-slate-900'}`}>{day}</span>

                          <div className="mt-2 h-1.5 flex items-center justify-center gap-1">
                            {log.status === 'Present' ? (
                              <div className={`w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white' : (log.isSubstitute ? 'bg-amber-400 shadow-[0_0_8px_rgba(251,191,36,0.6)]' : 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.6)]')}`}></div>
                            ) : log.status === 'Absent' ? (
                              <div className={`w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white/40' : 'bg-rose-400 shadow-[0_0_8px_rgba(244,63,94,0.6)]'}`}></div>
                            ) : null}
                          </div>

                          {!isActive && log.rate > 0 && (
                            <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity">
                               <p className="text-[7px] font-black text-indigo-400 uppercase tracking-tighter">{formatCurrency(log.rate, currency).split('.')[0]}</p>
                            </div>
                          )}
                        </div>
