               <div className="flex flex-col lg:flex-row items-stretch lg:items-center gap-6">
                  <div className="flex-1 flex gap-4">
                     <button 
                       onClick={() => handleAttendanceToggle('Present')}
                       className={`flex-1 py-5 rounded-[1.5rem] border-2 flex items-center justify-center gap-3 transition-all active:scale-95 ${selectedLog?.status === 'Present' && !selectedLog.isSubstitute ? 'bg-emerald-500 border-emerald-600 text-white shadow-xl' : 'bg-slate-50 border-slate-100 text-slate-400 hover:bg-emerald-50 hover:text-emerald-600'}`}
                     >
                        <span className="text-xl">✅</span>
                        <span className="text-[10px] font-black uppercase tracking-[0.2em] hidden sm:inline">Present</span>
                     </button>
                     <button 
                       onClick={() => handleAttendanceToggle('Absent')}
                       className={`flex-1 py-5 rounded-[1.5rem] border-2 flex items-center justify-center gap-3 transition-all active:scale-95 ${selectedLog?.status === 'Absent' ? 'bg-rose-500 border-rose-600 text-white shadow-xl' : 'bg-slate-50 border-slate-100 text-slate-400 hover:bg-rose-50 hover:text-rose-600'}`}
                     >
                        <span className="text-xl">❌</span>
                        <span className="text-[10px] font-black uppercase tracking-[0.2em] hidden sm:inline">Absent</span>
                     </button>
                     <button 
                       onClick={() => {
                          const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(selectedDay).padStart(2, '0')}`;
                          setSwapOverride({ day: selectedDay, dateStr });
                       }}
                       className={`flex-1 py-5 rounded-[1.5rem] border-2 flex items-center justify-center gap-3 transition-all active:scale-95 ${selectedLog?.isSubstitute ? 'bg-amber-500 border-amber-600 text-white shadow-xl' : 'bg-slate-50 border-slate-100 text-slate-400 hover:bg-amber-50 hover:text-amber-600'}`}
                     >
                        <span className="text-xl">🔄</span>
                        <span className="text-[10px] font-black uppercase tracking-[0.2em] hidden sm:inline">Substitute</span>
                     </button>
                  </div>

                  <div className="lg:w-72 p-6 bg-slate-900 rounded-[2rem] text-white flex items-center justify-between gap-5 shadow-2xl group transition-all hover:bg-black">
                     <div className="min-w-0">
                        <p className="text-[9px] font-black text-indigo-400 uppercase tracking-widest mb-1">Dues (Period)</p>
                        <p className="text-2xl font-black tracking-tighter truncate">{formatCurrency(currentMonthStats.total, currency).split('.')[0]}</p>
                     </div>
                     <button onClick={() => setShowSettleModal(selectedStaff)} className="px-6 py-3 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-lg active:scale-95 shrink-0">Settle</button>
                  </div>
               </div>
            </div>
          </>
        ) : (
          <div className="h-full flex flex-col items-center justify-center p-12 text-center bg-slate-50/20">
             <div className="w-24 h-24 bg-white rounded-[2.5rem] flex items-center justify-center text-5xl mb-8 shadow-2xl border border-slate-100 animate-float">📈</div>
             <h4 className="text-2xl font-black text-slate-900 uppercase tracking-tighter">Control Center</h4>
             <p className="text-[11px] font-black text-slate-400 uppercase mt-4 tracking-[0.3em] leading-loose max-w-sm">
               Select personnel from the registry to manage daily logs and monthly fiscal settlements.
             </p>
          </div>
        )}
      </div>

      {/* OVERLAY MODALS */}
      {swapOverride && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/90 backdrop-blur-xl p-6">
           <div className="bg-white w-full max-w-md rounded-[3rem] p-10 shadow-2xl animate-in zoom-in-95 border border-slate-200">
              <div className="flex justify-between items-center mb-10">
                 <div>
                   <h3 className="text-2xl font-black text-slate-800 uppercase tracking-tighter">Duty Swap</h3>
                   <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Configuring Day {swapOverride.day}</p>
                 </div>
                 <button onClick={() => setSwapOverride(null)} className="text-slate-300 hover:text-slate-800 text-3xl font-black transition-colors">✕</button>
              </div>

              <div className="grid grid-cols-1 gap-3">
                 {[
                   { id: 'OWN', label: 'Primary (Standard Rate)', icon: '👤' },
                   { id: 'PROXY', label: 'Substitute (Manual Rate)', icon: '🔄' },
                   { id: 'BOTH', label: 'Overtime / Double Entry', icon: '⭐' },
                   { id: 'REMOVE', label: 'Clear Daily Record', icon: '🧹' }
                 ].map(t => (
                   <button key={t.id} onClick={() => setSwapType(t.id as any)} className={`w-full p-5 text-left rounded-2xl border-2 transition-all flex items-center gap-5 group ${swapType === t.id ? 'bg-indigo-600 border-indigo-700 text-white shadow-xl' : 'bg-slate-50 border-transparent hover:border-slate-200'}`}>
                      <span className="text-3xl">{t.icon}</span>
                      <p className={`text-[11px] font-black uppercase tracking-widest ${swapType === t.id ? 'text-white' : 'text-slate-800'}`}>{t.label}</p>
                   </button>
                 ))}
              </div>

              {swapType !== 'OWN' && swapType !== 'REMOVE' && (
                <div className="mt-8 space-y-2 animate-in slide-in-from-top-4">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-2">Override Rate ({currency})</label>
                  <input type="number" className="w-full p-5 bg-slate-50 border border-slate-200 rounded-2xl font-black text-xl outline-none focus:ring-4 focus:ring-indigo-600/5 transition-all" value={proxyRate} onChange={e => setProxyRate(e.target.value)} />
                </div>
              )}

              <div className="flex gap-4 mt-10">
                 <button onClick={() => setSwapOverride(null)} className="flex-1 py-5 bg-slate-100 text-slate-400 font-black text-[10px] uppercase rounded-2xl">Abort</button>
                 <button onClick={handleCommitSwap} className="flex-[2] py-5 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl active:scale-95 transition-all">Verify Update</button>
              </div>
           </div>
        </div>
      )}

      {showAddStaff && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/90 backdrop-blur-xl p-6">
           <div className="bg-white w-full max-w-md rounded-[3rem] p-10 border border-slate-200 shadow-2xl animate-in zoom-in-95">
