                    </div>

                    <div className="flex flex-col gap-4">
                      <button onClick={() => handleSettle(showSettleModal)} className="w-full py-6 bg-indigo-600 text-white font-black text-xs uppercase tracking-[0.2em] rounded-2xl shadow-2xl shadow-indigo-100 active:scale-95">Verify & Post Payout</button>
                      <button onClick={() => { setShowSettleModal(null); setSettlementMode(null); }} className="w-full py-4 bg-slate-100 text-slate-400 font-black text-[9px] uppercase rounded-2xl">Abort Protocol</button>
                    </div>
                  </div>
                </>
              ) : (
                <div className="animate-in zoom-in-95 duration-700 py-10">
                  <div className="w-28 h-28 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center text-6xl mx-auto mb-10 shadow-2xl border border-emerald-200 animate-bounce">✅</div>
                  <h3 className="text-3xl font-black text-slate-900 uppercase tracking-tighter mb-3">Settled</h3>
                  <p className="text-[11px] font-black text-slate-400 uppercase mb-12 tracking-widest">Wages Archived in Ledger</p>
                  <button onClick={() => { setShowSettleModal(null); setIsRecordingSuccess(false); }} className="w-full py-6 bg-slate-900 text-white font-black text-xs uppercase rounded-2xl shadow-2xl active:scale-95">Return to Console</button>
                </div>
              )}
           </div>
        </div>
      )}
    </div>
  );
};

export default StaffManager;

import React, { useState, useMemo, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Staff, StaffAttendance, WageType, Transaction } from '../types';

const StaffManager: React.FC = () => {
  const { state, addStaff, updateStaff, deleteStaff, logStaffAttendance, addTransaction } = useFinance();
  const [showAddStaff, setShowAddStaff] = useState(false);
  const [editingStaffId, setEditingStaffId] = useState<string | null>(null);
  const [selectedStaffId, setSelectedStaffId] = useState<string | null>(null);
  const [viewDate, setViewDate] = useState(new Date());
  const [showSettleModal, setShowSettleModal] = useState<Staff | null>(null);
  const [swapOverride, setSwapOverride] = useState<{ day: number, dateStr: string } | null>(null);
  const [selectedDay, setSelectedDay] = useState<number>(new Date().getDate());

  const [settlementMode, setSettlementMode] = useState<{ id: string, name: string, type: 'bank' | 'card' | 'wallet' | 'liability' } | null>(null);
  const [isRecordingSuccess, setIsRecordingSuccess] = useState(false);

  const [staffFormData, setStaffFormData] = useState({ 
    name: '', role: 'Maid', baseRate: '500', wageType: 'Daily' as WageType,
    joiningDate: new Date().toISOString().split('T')[0]
  });

  const [swapType, setSwapType] = useState<'OWN' | 'PROXY' | 'BOTH' | 'REMOVE'>('OWN');
  const [proxyRate, setProxyRate] = useState<string>('0');

  const currency = state.profile.currency;
  const staffList = state.staff || [];
  const selectedStaff = staffList.find(s => s.id === selectedStaffId);

  useEffect(() => {
    if (!selectedStaffId && staffList.length > 0) {
      setSelectedStaffId(staffList[0].id);
    }
  }, [staffList, selectedStaffId]);

  const daysInMonth = useMemo(() => {
    return new Date(viewDate.getFullYear(), viewDate.getMonth() + 1, 0).getDate();
  }, [viewDate]);

  useEffect(() => {
    if (selectedDay > daysInMonth) setSelectedDay(daysInMonth);
  }, [viewDate, daysInMonth, selectedDay]);

  const availableAccounts = useMemo(() => {
    const list: { id: string, name: string, type: 'bank' | 'card' | 'wallet' | 'liability' }[] = [];
    state.banks.forEach(b => list.push({ id: b.id, name: b.name, type: 'bank' }));
    state.wallets.forEach(w => list.push({ id: w.id, name: w.name, type: 'wallet' }));
    state.cards.forEach(c => list.push({ id: c.id, name: c.lenderName, type: 'card' }));
    return list;
  }, [state]);

  const monthName = viewDate.toLocaleString('default', { month: 'long', year: 'numeric' });

  const resetForm = () => {
    setStaffFormData({
      name: '', role: 'Maid', baseRate: '500', wageType: 'Daily',
      joiningDate: new Date().toISOString().split('T')[0]
    });
    setEditingStaffId(null);
  };

  const getAttendanceStatusForDay = (staff: Staff, dateStr: string) => {
    const manualLog = staff.attendance?.find(a => a.date === dateStr);
    if (manualLog) return manualLog;
    const today = new Date().toISOString().split('T')[0];
    const joining = staff.joiningDate;
    const exit = staff.exitDate;

    if (dateStr >= joining && (!exit || dateStr <= exit) && dateStr <= today) {
       let rate = staff.baseRate;
       if (staff.wageType === 'Monthly') {
          const d = new Date(dateStr);
          rate = staff.baseRate / new Date(d.getFullYear(), d.getMonth() + 1, 0).getDate();
       }
       return { status: 'Present' as const, rate: rate, isSubstitute: false, isDefault: true };
    }
    return { status: 'None' as const, rate: 0, isSubstitute: false, isDefault: true };
  };

  const currentMonthStats = useMemo(() => {
    if (!selectedStaff) return { present: 0, absent: 0, swap: 0, total: 0 };
    let present = 0, absent = 0, swap = 0, total = 0;
    for (let i = 1; i <= daysInMonth; i++) {
      const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(i).padStart(2, '0')}`;
      const log = getAttendanceStatusForDay(selectedStaff, dateStr);
      if (log.status === 'Present') {
        present++;
        total += log.rate;
        if (log.isSubstitute) swap++;
      } else if (log.status === 'Absent') {
        absent++;
      }
    }
    return { present, absent, swap, total };
  }, [selectedStaff, viewDate, daysInMonth]);

  const handleSettle = (staff: Staff) => {
    if (!settlementMode) return alert("Select target account first.");
    const amount = currentMonthStats.total;
    if (amount <= 0) return alert("No dues to settle.");

    const tx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'Expense',
      amount: amount,
      nature: staff.name,
      description: `Wages payout for ${monthName}`,
      accountId: settlementMode.id,
      accountType: settlementMode.type,
      date: new Date().toISOString().split('T')[0],
      status: 'active'
    };

    addTransaction(tx);
    setIsRecordingSuccess(true);
    setSettlementMode(null);
  };

  const handleAttendanceToggle = (targetStatus: 'Present' | 'Absent') => {
    if (!selectedStaff) return;
    const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(selectedDay).padStart(2, '0')}`;
    const currentLog = getAttendanceStatusForDay(selectedStaff, dateStr);

    if (!(currentLog as any).isDefault && currentLog.status === targetStatus) {
      logStaffAttendance(selectedStaff.id, { date: dateStr, status: 'None' });
      return;
    }

    let rate = targetStatus === 'Present' ? selectedStaff.baseRate : 0;
    if (targetStatus === 'Present' && selectedStaff.wageType === 'Monthly') {
      const d = new Date(dateStr);
      rate = selectedStaff.baseRate / new Date(d.getFullYear(), d.getMonth() + 1, 0).getDate();
    }

    logStaffAttendance(selectedStaff.id, { 
      date: dateStr, 
      status: targetStatus, 
      rate: rate, 
      isSubstitute: false 
    });
  };

  const handleCommitSwap = () => {
    if (!selectedStaff || !swapOverride) return;
    const { dateStr } = swapOverride;

    if (swapType === 'REMOVE') {
      logStaffAttendance(selectedStaff.id, { date: dateStr, status: 'None' });
    } else {
      let finalRate = 0;
      let isSub = false;

      if (swapType === 'OWN') {
        finalRate = selectedStaff.baseRate;
        if (selectedStaff.wageType === 'Monthly') {
          const d = new Date(dateStr);
          finalRate = selectedStaff.baseRate / new Date(d.getFullYear(), d.getMonth() + 1, 0).getDate();
        }
        isSub = false;
      } else if (swapType === 'PROXY') {
        finalRate = Number(proxyRate);
        isSub = true;
      } else if (swapType === 'BOTH') {
        let ownRate = selectedStaff.baseRate;
        if (selectedStaff.wageType === 'Monthly') {
          const d = new Date(dateStr);
          ownRate = selectedStaff.baseRate / new Date(d.getFullYear(), d.getMonth() + 1, 0).getDate();
        }
        finalRate = ownRate + Number(proxyRate);
        isSub = true;
      }

      logStaffAttendance(selectedStaff.id, { 
        date: dateStr, 
        status: 'Present', 
        rate: finalRate, 
        isSubstitute: isSub 
      });
    }
    setSwapOverride(null);
  };

  const selectedDateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(selectedDay).padStart(2, '0')}`;
  const selectedLog = selectedStaff ? getAttendanceStatusForDay(selectedStaff, selectedDateStr) : null;

  return (
    <div className="h-[calc(100dvh-120px)] flex flex-col md:flex-row gap-4 md:gap-6 animate-in fade-in duration-500 overflow-hidden font-sans p-2">

      {/* ADAPTIVE REGISTRY: Horizontal on Mobile, Vertical on Desktop */}
      <div className="w-full md:w-80 flex flex-col bg-slate-50 border border-slate-200 rounded-[2.5rem] overflow-hidden shadow-sm shrink-0">
        <div className="p-5 md:p-6 border-b border-slate-100 flex justify-between items-center bg-white shrink-0">
          <div>
            <h3 className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Personnel</h3>
            <p className="text-[7px] font-bold text-slate-300 uppercase tracking-widest hidden md:block">Management Console</p>
          </div>
          <button 
            onClick={() => { resetForm(); setShowAddStaff(true); }} 
            className="w-8 h-8 md:w-10 md:h-10 flex items-center justify-center bg-brand-deep text-white rounded-xl md:rounded-2xl text-xl shadow-lg hover:scale-105 active:scale-95 transition-transform"
          >
            +
          </button>
        </div>

        {/* Horizontal Strip on Mobile / Scroll List on Desktop */}
        <div className="flex-1 flex md:flex-col overflow-x-auto md:overflow-y-auto no-scrollbar p-3 md:p-4 gap-3">
          {staffList.map(s => {
            const isSelected = selectedStaffId === s.id;
            return (
              <div 
                key={s.id} 
                onClick={() => setSelectedStaffId(s.id)} 
                className={`flex-none md:flex-1 p-3 md:p-4 rounded-2xl md:rounded-3xl cursor-pointer transition-all border flex items-center gap-3 md:gap-4 min-w-[140px] md:min-w-0 ${isSelected ? 'bg-indigo-600 border-indigo-700 text-white shadow-xl md:translate-x-2' : 'bg-white border-slate-100 text-slate-800 hover:bg-slate-50'}`}
              >
                <div className={`w-10 h-10 md:w-11 md:h-11 rounded-xl md:rounded-2xl flex items-center justify-center text-lg shrink-0 font-black ${isSelected ? 'bg-white/20' : 'bg-slate-100 text-slate-400'}`}>
                  {s.name.charAt(0)}
                </div>
                <div className="min-w-0 overflow-hidden">
                  <p className={`text-[10px] md:text-xs font-black uppercase truncate leading-none mb-1 ${isSelected ? 'text-white' : 'text-slate-800'}`}>{s.name}</p>
                  <p className={`text-[8px] md:text-[9px] font-black uppercase tracking-widest ${isSelected ? 'text-white/60' : 'text-slate-400'}`}>{s.role}</p>
                </div>
              </div>
            );
          })}
          {staffList.length === 0 && (
            <div className="py-10 md:py-20 text-center flex flex-col items-center gap-4 w-full">
               <p className="text-[9px] font-black text-slate-300 uppercase tracking-widest">No Records</p>
            </div>
          )}
        </div>
      </div>

      {/* MAIN WORKSPACE */}
      <div className="flex-1 flex flex-col bg-white border border-slate-200 rounded-[3rem] overflow-hidden shadow-sm min-h-0 relative">
        {selectedStaff ? (
          <>
            {/* WORKSPACE HEADER: Matching Screenshot exactly */}
            <div className="p-6 md:p-8 border-b border-slate-100 flex flex-col sm:flex-row justify-between items-center gap-6 bg-white shrink-0">
              <div className="flex items-center gap-5 w-full sm:w-auto">
                <div className="w-16 h-16 bg-slate-900 text-white rounded-[1.5rem] flex items-center justify-center text-2xl font-black shadow-xl">
                  {selectedStaff.name.charAt(0).toLowerCase()}
                </div>
                <div className="flex-1">
                   <div className="flex items-center gap-3 mb-1">
                      <h2 className="text-2xl md:text-3xl font-black text-slate-900 uppercase tracking-tighter leading-none">{selectedStaff.name}</h2>
                      <button onClick={() => { 
                        setEditingStaffId(selectedStaff.id); 
                        setStaffFormData({ 
                          name: selectedStaff.name, 
                          role: selectedStaff.role,
                          baseRate: String(selectedStaff.baseRate),
                          wageType: selectedStaff.wageType,
                          joiningDate: selectedStaff.joiningDate
                        }); 
                        setShowAddStaff(true); 
                      }} className="w-8 h-8 rounded-xl border border-slate-100 flex items-center justify-center text-[12px] text-slate-400 hover:bg-slate-50 transition-colors">✎</button>
                   </div>
                   <div className="flex items-center gap-2">
                      <p className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.1em]">{selectedStaff.role}</p>
                      <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Monthly Audit</p>
                   </div>
                </div>
              </div>

              {/* DATE CONTROLS */}
              <div className="flex items-center gap-1 bg-slate-50 p-1.5 rounded-full border border-slate-100 shrink-0">
                 <button onClick={() => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() - 1))} className="w-9 h-9 flex items-center justify-center hover:bg-white rounded-full text-slate-400 transition-all shadow-sm border border-transparent">←</button>
                 <span className="px-5 text-[9px] font-black uppercase tracking-[0.2em] text-slate-800">{monthName}</span>
                 <button onClick={() => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() + 1))} className="w-9 h-9 flex items-center justify-center hover:bg-white rounded-full text-slate-400 transition-all shadow-sm border border-transparent">→</button>
              </div>
            </div>

            {/* PERFORMANCE BAR */}
            <div className="px-8 py-4 bg-white flex justify-center md:justify-start gap-8 md:gap-12 shrink-0 border-b border-slate-50">
               <div className="text-center">
                  <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest mb-1">Present</p>
                  <p className="text-xl font-black text-emerald-500 leading-none">{currentMonthStats.present}</p>
               </div>
               <div className="w-px h-6 bg-slate-100 my-auto"></div>
               <div className="text-center">
                  <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest mb-1">Absent</p>
                  <p className="text-xl font-black text-rose-500 leading-none">{currentMonthStats.absent}</p>
               </div>
               <div className="w-px h-6 bg-slate-100 my-auto"></div>
               <div className="text-center">
                  <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest mb-1">Swaps</p>
                  <p className="text-xl font-black text-amber-500 leading-none">{currentMonthStats.swap}</p>
               </div>
            </div>

            {/* CALENDAR WORKSPACE: FIXED MIN-H-0 and FLEX-1 to ensure visibility */}
            <div className="flex-1 overflow-hidden p-4 md:p-6 bg-slate-50/30 flex flex-col min-h-0">
              <div className="flex-1 border border-slate-200 rounded-[2.5rem] bg-white shadow-xl overflow-hidden flex flex-col min-h-0">
                <div className="grid grid-cols-7 border-b border-slate-100 shrink-0 bg-slate-50/50">
                  {['S','M','T','W','T','F','S'].map((d, i) => (
                    <div key={i} className="py-4 text-center text-[9px] font-black text-slate-300 uppercase tracking-[0.3em]">{d}</div>
                  ))}
                </div>
                <div className="flex-1 overflow-y-auto no-scrollbar min-h-0">
                  <div className="grid grid-cols-7 gap-px bg-slate-100/50">
                    {Array.from({ length: new Date(viewDate.getFullYear(), viewDate.getMonth(), 1).getDay() }).map((_, i) => (
                      <div key={`empty-${i}`} className="bg-slate-50/10 aspect-square"></div>
                    ))}
                    {Array.from({ length: daysInMonth }).map((_, i) => {
                      const day = i + 1;
                      const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
                      const log = getAttendanceStatusForDay(selectedStaff, dateStr);
                      const isActive = selectedDay === day;

                      return (
                        <div 
                          key={day} 
                          onClick={() => setSelectedDay(day)}
                          className={`group flex flex-col items-center justify-center aspect-square cursor-pointer transition-all relative ${isActive ? 'bg-indigo-600 text-white z-10 scale-[1.02] shadow-2xl rounded-xl' : 'bg-white hover:bg-slate-50'}`}
                        >
                          <span className={`text-base font-black transition-all ${isActive ? 'scale-110' : 'text-slate-400 group-hover:text-slate-900'}`}>{day}</span>
                          <div className="mt-1 h-1 flex items-center justify-center gap-1">
                            {log.status === 'Present' ? (
                              <div className={`w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white' : (log.isSubstitute ? 'bg-amber-400 shadow-[0_0_5px_rgba(251,191,36,0.5)]' : 'bg-emerald-500 shadow-[0_0_5px_rgba(16,185,129,0.5)]')}`}></div>
                            ) : log.status === 'Absent' ? (
                              <div className={`w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white/40' : 'bg-rose-400 shadow-[0_0_5px_rgba(244,63,94,0.5)]'}`}></div>
                            ) : null}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </div>
              </div>
            </div>

            {/* ACTION CENTER FOOTER */}
            <div className="p-6 md:p-8 border-t border-slate-100 bg-white shrink-0">
               <div className="flex flex-col lg:flex-row items-stretch lg:items-center gap-6">
                  <div className="flex-1 flex gap-3">
                     <button 
                       onClick={() => handleAttendanceToggle('Present')}
                       className={`flex-1 py-4 md:py-5 rounded-2xl border-2 flex items-center justify-center gap-3 transition-all active:scale-95 ${selectedLog?.status === 'Present' && !selectedLog.isSubstitute ? 'bg-emerald-500 border-emerald-600 text-white shadow-xl' : 'bg-slate-50 border-slate-100 text-slate-400 hover:bg-emerald-50 hover:text-emerald-600'}`}
                     >
                        <span className="text-xl">✅</span>
                        <span className="text-[10px] font-black uppercase tracking-[0.2em] hidden sm:inline">Present</span>
                     </button>
                     <button 
                       onClick={() => handleAttendanceToggle('Absent')}
                       className={`flex-1 py-4 md:py-5 rounded-2xl border-2 flex items-center justify-center gap-3 transition-all active:scale-95 ${selectedLog?.status === 'Absent' ? 'bg-rose-500 border-rose-600 text-white shadow-xl' : 'bg-slate-50 border-slate-100 text-slate-400 hover:bg-rose-50 hover:text-rose-600'}`}
                     >
                        <span className="text-xl">❌</span>
                        <span className="text-[10px] font-black uppercase tracking-[0.2em] hidden sm:inline">Absent</span>
                     </button>
                     <button 
                       onClick={() => setSwapOverride({ day: selectedDay, dateStr: selectedDateStr })}
                       className={`flex-1 py-4 md:py-5 rounded-2xl border-2 flex items-center justify-center gap-3 transition-all active:scale-95 ${selectedLog?.isSubstitute ? 'bg-amber-500 border-amber-600 text-white shadow-xl' : 'bg-slate-50 border-slate-100 text-slate-400 hover:bg-amber-50 hover:text-amber-600'}`}
                     >
                        <span className="text-xl">🔄</span>
                        <span className="text-[10px] font-black uppercase tracking-[0.2em] hidden sm:inline">Swap</span>
                     </button>
                  </div>

                  <div className="lg:w-72 p-5 md:p-6 bg-slate-900 rounded-[2rem] text-white flex items-center justify-between gap-5 shadow-2xl">
                     <div className="min-w-0">
                        <p className="text-[8px] font-black text-indigo-400 uppercase tracking-widest mb-1">Period Dues</p>
                        <p className="text-2xl font-black tracking-tighter truncate">{formatCurrency(currentMonthStats.total, currency).split('.')[0]}</p>
                     </div>
                     <button onClick={() => setShowSettleModal(selectedStaff)} className="px-5 py-3 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-700 transition-all active:scale-95 shrink-0 shadow-lg">Settle</button>
                  </div>
               </div>
            </div>
          </>
        ) : (
          <div className="h-full flex flex-col items-center justify-center p-12 text-center bg-slate-50/20">
             <div className="w-20 h-20 bg-white rounded-[2rem] flex items-center justify-center text-4xl mb-6 shadow-2xl border border-slate-100 animate-float">📊</div>
             <h4 className="text-2xl font-black text-slate-900 uppercase tracking-tighter">Staff Vault</h4>
             <p className="text-[11px] font-black text-slate-400 uppercase mt-4 tracking-[0.3em] leading-loose max-w-sm">
               Select personnel to manage attendance audit and period wage settlements.
             </p>
          </div>
        )}
      </div>

      {/* MODALS */}
      {swapOverride && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/90 backdrop-blur-xl p-6">
           <div className="bg-white w-full max-w-md rounded-[3rem] p-10 shadow-2xl animate-in zoom-in-95 border border-slate-200">
              <div className="flex justify-between items-center mb-8">
                 <h3 className="text-2xl font-black text-slate-800 uppercase tracking-tighter">Duty Protocol</h3>
                 <button onClick={() => setSwapOverride(null)} className="text-slate-300 hover:text-slate-800 text-2xl font-black">✕</button>
              </div>
              <div className="space-y-3">
                 {[
                   { id: 'OWN', label: 'Primary Personnel', icon: '👤' },
                   { id: 'PROXY', label: 'Substitute Proxy', icon: '🔄' },
                   { id: 'BOTH', label: 'Double Shift/Entry', icon: '⭐' },
                   { id: 'REMOVE', label: 'Clear Entry', icon: '🧹' }
                 ].map(t => (
                   <button key={t.id} onClick={() => setSwapType(t.id as any)} className={`w-full p-5 text-left rounded-2xl border-2 transition-all flex items-center gap-5 group ${swapType === t.id ? 'bg-indigo-600 border-indigo-700 text-white shadow-xl' : 'bg-slate-50 border-transparent hover:border-slate-200'}`}>
                      <span className="text-3xl">{t.icon}</span>
                      <p className={`text-[11px] font-black uppercase tracking-widest ${swapType === t.id ? 'text-white' : 'text-slate-800'}`}>{t.label}</p>
                   </button>
                 ))}
              </div>
              {swapType !== 'OWN' && swapType !== 'REMOVE' && (
                <div className="mt-6 space-y-2 animate-in slide-in-from-top-4">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-2">Override Amount ({currency})</label>
                  <input type="number" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl font-black text-xl outline-none" value={proxyRate} onChange={e => setProxyRate(e.target.value)} />
                </div>
              )}
              <div className="flex gap-4 mt-8">
                 <button onClick={() => setSwapOverride(null)} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-2xl">Cancel</button>
                 <button onClick={handleCommitSwap} className="flex-[2] py-5 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl active:scale-95">Commit Swap</button>
              </div>
           </div>
        </div>
      )}

      {showAddStaff && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/90 backdrop-blur-xl p-6">
           <div className="bg-white w-full max-w-md rounded-[3rem] p-10 border border-slate-200 shadow-2xl animate-in zoom-in-95">
              <h3 className="text-2xl font-black text-slate-800 uppercase tracking-tighter mb-10">{editingStaffId ? 'Update Registry' : 'Personnel Onboarding'}</h3>
              <div className="space-y-8">
                 <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Identity</label>
                    <input autoFocus className="w-full p-5 bg-slate-50 border border-slate-200 rounded-2xl font-black text-sm uppercase outline-none focus:ring-4 focus:ring-indigo-600/5 transition-all" value={staffFormData.name} onChange={e => setStaffFormData({...staffFormData, name: e.target.value})} placeholder="Full Name" />
                 </div>
                 <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Basis</label>
                       <select className="w-full p-5 bg-slate-50 border border-slate-200 rounded-2xl font-black text-[11px] outline-none cursor-pointer uppercase" value={staffFormData.wageType} onChange={e => setStaffFormData({...staffFormData, wageType: e.target.value as WageType})}>
                          <option value="Monthly">Monthly</option>
                          <option value="Daily">Daily</option>
                       </select>
                    </div>
                    <div className="space-y-2">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Role</label>
                       <select className="w-full p-5 bg-slate-50 border border-slate-200 rounded-2xl font-black text-[11px] outline-none cursor-pointer uppercase" value={staffFormData.role} onChange={e => setStaffFormData({...staffFormData, role: e.target.value})}>
                          <option>Maid</option><option>Cook</option><option>Driver</option><option>Helper</option><option>Security</option>
                       </select>
                    </div>
                 </div>
                 <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Compensation ({currency})</label>
                    <input type="number" className="w-full p-8 bg-slate-900 text-white border border-slate-800 rounded-3xl font-black text-4xl text-center outline-none" value={staffFormData.baseRate} onChange={e => setStaffFormData({...staffFormData, baseRate: e.target.value})} />
                 </div>
                 <div className="flex gap-4 pt-4">
                    <button onClick={() => { setShowAddStaff(false); resetForm(); }} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-2xl">Cancel</button>
                    <button onClick={() => {
                      if (!staffFormData.name.trim()) return alert("Name required.");
                      const staffData: Staff = {
                        id: editingStaffId || Math.random().toString(36).substr(2, 9),
                        name: staffFormData.name, role: staffFormData.role,
                        baseRate: Number(staffFormData.baseRate), wageType: staffFormData.wageType,
                        attendance: editingStaffId ? (staffList.find(s => s.id === editingStaffId)?.attendance || []) : [],
                        joiningDate: staffFormData.joiningDate
                      };
                      if (editingStaffId) updateStaff(staffData); else addStaff(staffData);
                      setShowAddStaff(false); resetForm();
                    }} className="flex-[2] py-5 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl active:scale-95">Commit Entry</button>
                 </div>
              </div>
           </div>
        </div>
      )}

      {showSettleModal && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/95 backdrop-blur-2xl p-6">
           <div className="bg-white w-full max-w-sm rounded-[3.5rem] p-12 shadow-2xl text-center animate-in zoom-in-95 border border-slate-200">
              {!isRecordingSuccess ? (
                <>
                  <div className="w-20 h-20 bg-emerald-50 text-emerald-600 rounded-[2rem] flex items-center justify-center text-4xl mx-auto mb-8 shadow-inner border border-emerald-100">💸</div>
                  <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tighter mb-2">Wage Settlement</h3>
                  <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest mb-10">{monthName}</p>
                  <div className="p-10 bg-slate-50 rounded-[2.5rem] mb-10 shadow-inner border border-slate-100">
                    <p className="text-5xl font-black text-slate-900 tracking-tighter">{formatCurrency(currentMonthStats.total, currency).split('.')[0]}</p>
                    <p className="text-[9px] font-black text-indigo-400 uppercase mt-4 tracking-widest font-black">Final Audit Balance</p>
                  </div>
                  <div className="space-y-6">
                    <div className="space-y-2">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block text-left ml-3">Payout Account</label>
                       <select className="w-full p-5 bg-slate-100 border border-slate-200 rounded-2xl font-black text-xs outline-none cursor-pointer uppercase" value={settlementMode?.id || ''} onChange={(e) => {
                           const acc = availableAccounts.find(a => a.id === e.target.value);
                           if (acc) setSettlementMode(acc);
                         }}>
                         <option value="">Select Target</option>
                         {availableAccounts.map(acc => (<option key={acc.id} value={acc.id}>{acc.name} ({acc.type})</option>))}
                       </select>
                    </div>
                    <div className="flex flex-col gap-4">
                      <button onClick={() => handleSettle(showSettleModal)} className="w-full py-6 bg-indigo-600 text-white font-black text-xs uppercase tracking-[0.2em] rounded-2xl shadow-2xl shadow-indigo-100 active:scale-95">Release Funds</button>
                      <button onClick={() => { setShowSettleModal(null); setSettlementMode(null); }} className="w-full py-4 bg-slate-100 text-slate-400 font-black text-[9px] uppercase rounded-2xl">Abort Protocol</button>
                    </div>
                  </div>
                </>
              ) : (
                <div className="animate-in zoom-in-95 duration-700 py-10">
                  <div className="w-28 h-28 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center text-6xl mx-auto mb-10 shadow-2xl border border-emerald-200 animate-bounce">✅</div>
                  <h3 className="text-3xl font-black text-slate-900 uppercase tracking-tighter mb-3">Settled</h3>
                  <p className="text-[11px] font-black text-slate-400 uppercase mb-12 tracking-widest">Wages Archived in Ledger</p>
                  <button onClick={() => { setShowSettleModal(null); setIsRecordingSuccess(false); }} className="w-full py-6 bg-slate-900 text-white font-black text-xs uppercase rounded-2xl shadow-2xl active:scale-95">Return to Console</button>
                </div>
