import React, { useState, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { calculateRates, calculateNetWorth, ANNUAL_MULTIPLIERS } from '../utils/calculations';
import { formatCurrency } from '../utils/formatters';
import { Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';
import { Staff } from '../types';

const Dashboard: React.FC<{ onNavigate: (tab: string) => void }> = ({ onNavigate }) => {
  const { filteredState, state, logStaffAttendance } = useFinance();
  const [displayMode, setDisplayMode] = useState<'hourly' | 'daily' | 'monthly'>('monthly');
  const [activeHours, setActiveHours] = useState<number>(24);

  const rawRates = calculateRates(filteredState);
  const netWorthData = calculateNetWorth(filteredState);
  const currency = filteredState.profile.currency;
  const staffList = state.staff || [];

  const timeScaler = useMemo(() => {
    const now = new Date();
    const daysInMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0).getDate();

    if (displayMode === 'monthly') return 1;
    if (displayMode === 'daily') return 1 / daysInMonth;
    return (1 / daysInMonth) / activeHours;
  }, [displayMode, activeHours]);

  const cycleLabel = useMemo(() => {
    if (displayMode === 'monthly') return 'Month';
    if (displayMode === 'daily') return 'Day';
    return `Hour`;
  }, [displayMode]);

  const currentDisplay = useMemo(() => {
    const daysPassed = Math.max(1, rawRates.daysPassed);

    const monthlyBudgetIncome = (filteredState.budgets || [])
      .filter(b => b.type === 'Income')
      .reduce((acc, b) => {
         const annualMult = (ANNUAL_MULTIPLIERS as Record<string, number>)[b.frequency as string] || 12;
         return acc + (b.amount * annualMult) / 12;
      }, 0);

    const monthlyBudgetExpense = (filteredState.budgets || [])
      .filter(b => b.type === 'Expense')
      .reduce((acc, b) => {
         const annualMult = (ANNUAL_MULTIPLIERS as Record<string, number>)[b.frequency as string] || 12;
         return acc + (b.amount * annualMult) / 12;
      }, 0);

    const actualIncome = (displayMode === 'monthly' ? rawRates.income : (rawRates.income / daysPassed) * (displayMode === 'hourly' ? 1/activeHours : 1));
    const actualExpense = (displayMode === 'monthly' ? rawRates.expense : (rawRates.expense / daysPassed) * (displayMode === 'hourly' ? 1/activeHours : 1));
    const budgetIncome = monthlyBudgetIncome * timeScaler;
    const budgetExpense = monthlyBudgetExpense * timeScaler;

    const actualSavings = actualIncome - actualExpense;
    const budgetSavings = budgetIncome - budgetExpense;

    return { 
      actualIncome,
      actualExpense,
      actualSavings,
      budgetIncome,
      budgetExpense,
      budgetSavings
    };
  }, [rawRates, displayMode, activeHours, filteredState.budgets, timeScaler]);

  const pieData = [
    { name: 'Assets', value: netWorthData.assets, color: '#8B5CF6' },
    { name: 'Liabilities', value: netWorthData.liabilities, color: '#DDD6FE' },
  ];

  const getGreeting = () => {
    const hour = new Date().getHours();
    if (hour < 12) return "Good morning";
    if (hour < 17) return "Good afternoon";
    return "Good evening";
  };

  const services = [
    { id: 'accounts', label: 'Vaults', icon: '🏦', desc: 'Vault' },
    { id: 'budget', label: 'Goals', icon: '🎯', desc: 'Goal' },
    { id: 'calendar', label: 'Fiscal', icon: '📅', desc: 'Sntl' },
    { id: 'statements', label: 'Audit', icon: '📜', desc: 'Stat' },
  ];

  const todayStr = new Date().toISOString().split('T')[0];

  const handleQuickAttendance = (staffId: string, status: 'Present' | 'Absent') => {
    const staffMember = staffList.find(s => s.id === staffId);
    if (!staffMember) return;

    const existingLog = staffMember.attendance?.find(a => a.date === todayStr);

    if (existingLog?.status === status) {
      logStaffAttendance(staffId, { date: todayStr, status: 'None' });
      return;
    }

    let rate = 0;
    if (status === 'Present') {
       if (staffMember.wageType === 'Daily' || staffMember.wageType === 'Task') {
          rate = staffMember.baseRate;
       } else if (staffMember.wageType === 'Monthly') {
          const daysInMonth = new Date(new Date().getFullYear(), new Date().getMonth() + 1, 0).getDate();
          rate = staffMember.baseRate / daysInMonth;
       }
    }

    logStaffAttendance(staffId, {
      date: todayStr,
      status: status,
      rate: rate,
      isSubstitute: false,
      hoursWorked: staffMember.wageType === 'Hourly' ? 8 : undefined 
    });
  };

  return (
    <div className="space-y-4 md:space-y-6 animate-in fade-in duration-500 max-w-full pb-16">
      <div className="flex justify-between items-center px-1">
        <div>
           <h1 className="text-xl font-black text-brand-deep tracking-tight">
             {getGreeting()}, <span className="text-brand-purple">{state.profile.name?.split(' ')[0] || 'User'}</span>
           </h1>
           <p className="text-[8px] font-black text-purple-900/30 uppercase tracking-[0.2em]">Live Fiscal Audit</p>
        </div>
        <div className="w-10 h-10 bg-brand-purple/10 rounded-full flex items-center justify-center text-brand-purple font-black text-xs border border-brand-purple/20">
          {state.profile.name?.charAt(0) || 'U'}
        </div>
      </div>

      <section className="grid grid-cols-2 gap-3 md:gap-4">
        {services.map(service => (
          <button 
            key={service.id} 
            onClick={() => onNavigate(service.id)}
            className="glass-card p-6 rounded-[2.5rem] flex flex-col items-center justify-center gap-3 transition-all hover:scale-[1.02] active:scale-[0.95] group border border-white/60 aspect-square shadow-sm"
          >
            <div className="text-3xl bg-white/50 w-16 h-16 rounded-3xl flex items-center justify-center shadow-inner group-hover:scale-110 transition-transform">
              {service.icon}
            </div>
            <div className="text-center">
              <h5 className="text-[11px] font-black text-brand-deep uppercase leading-tight tracking-[0.2em]">{service.label}</h5>
              <p className="text-[7px] font-black text-brand-purple/30 uppercase mt-1 tracking-widest">{service.desc} Intelligence</p>
            </div>
          </button>
        ))}
      </section>

      {/* NEWLY FORMED STAFF PULSE SECTION */}
      <section className="animate-in slide-in-from-bottom-4 duration-500">
        <div className="bg-white/40 md:rounded-[3rem] p-1 overflow-hidden">
           <div className="px-5 mb-4">
              <h3 className="text-xs font-black text-brand-deep uppercase tracking-[0.2em]">Staff Pulse</h3>
              <p className="text-[8px] font-black text-indigo-400 uppercase tracking-widest mt-0.5">Direct Ledger Control</p>
           </div>

           <div className="flex overflow-x-auto no-scrollbar gap-4 px-4 pb-4">
              {staffList.length > 0 ? staffList.map(staff => {
                const attendance = staff.attendance?.find(a => a.date === todayStr);
                const isPresent = attendance?.status === 'Present';
                const isAbsent = attendance?.status === 'Absent';

                return (
                  <div key={staff.id} className="flex-none w-[260px] bg-white rounded-[2.5rem] p-6 border border-slate-100 shadow-xl shadow-slate-200/50 flex flex-col justify-between group transition-all hover:shadow-2xl">
                    <div className="flex items-center gap-4 mb-6">
                      <div className="w-14 h-14 bg-slate-900 text-white rounded-[1.25rem] flex items-center justify-center text-xl font-black shadow-lg">
                        {staff.name.charAt(0).toLowerCase()}
                      </div>
                      <div className="min-w-0 flex-1">
                        <h4 className="text-lg font-black text-slate-900 uppercase tracking-tighter truncate leading-none mb-1">{staff.name}</h4>
                        <div className="flex items-center gap-1.5 overflow-hidden">
                           <span className="text-[9px] font-black text-indigo-600 uppercase tracking-widest whitespace-nowrap">{staff.role}</span>
                           <span className="w-1 h-1 bg-slate-200 rounded-full shrink-0"></span>
                           <span className="text-[9px] font-black text-slate-300 uppercase tracking-widest truncate">Monthly Audit</span>
                        </div>
                      </div>
                    </div>

                    <div className="flex gap-2">
                       <button 
                         onClick={() => handleQuickAttendance(staff.id, 'Present')}
                         className={`flex-1 py-3.5 rounded-2xl border-2 flex items-center justify-center gap-2 transition-all active:scale-95 ${isPresent ? 'bg-emerald-500 border-emerald-600 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-300 hover:bg-emerald-50 hover:text-emerald-600'}`}
                       >
                          <span className="text-sm">✅</span>
                          <span className="text-[9px] font-black uppercase tracking-widest">Present</span>
                       </button>
                       <button 
                         onClick={() => handleQuickAttendance(staff.id, 'Absent')}
                         className={`flex-1 py-3.5 rounded-2xl border-2 flex items-center justify-center gap-2 transition-all active:scale-95 ${isAbsent ? 'bg-rose-500 border-rose-600 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-300 hover:bg-rose-50 hover:text-rose-600'}`}
                       >
                          <span className="text-sm">❌</span>
                          <span className="text-[9px] font-black uppercase tracking-widest">Absent</span>
                       </button>
                    </div>
                  </div>
                );
              }) : (
                <div className="w-full py-12 flex flex-col items-center justify-center bg-white/40 border-2 border-dashed border-indigo-100 rounded-[2.5rem]">
                   <span className="text-4xl mb-4 opacity-20">👥</span>
                   <p className="text-[10px] font-black text-indigo-300 uppercase tracking-[0.3em]">No personnel linked to vault</p>
                   <button onClick={() => onNavigate('staff')} className="mt-4 px-6 py-3 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest shadow-lg">Setup Help Registry</button>
                </div>
              )}
           </div>
        </div>
      </section>

      <div className="flex flex-col items-center gap-1.5 mt-2 px-1">
        <div className={`transition-all duration-300 overflow-hidden flex justify-center ${displayMode === 'hourly' ? 'max-h-12 opacity-100 mb-1' : 'max-h-0 opacity-0'}`}>
          <div className="flex items-center gap-3 bg-white/70 px-4 py-1.5 rounded-full border border-white/50 shadow-sm">
            <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Active Basis:</span>
            <select 
              value={activeHours}
              onChange={(e) => setActiveHours(Number(e.target.value))}
              className="bg-transparent text-[10px] font-black text-brand-deep uppercase outline-none cursor-pointer border-none focus:ring-0 p-0"
            >
              {Array.from({ length: 24 }, (_, i) => i + 1).map(h => (
                <option key={h} value={h}>{h} Hours</option>
              ))}
            </select>
            <span className="text-[10px]">⏰</span>
          </div>
        </div>

        <div className="inline-flex items-center p-1 bg-white/95 backdrop-blur-md rounded-full shadow-md border border-white/60 w-full max-w-[340px]">
          {(['hourly', 'daily', 'monthly'] as const).map(mode => (
            <button
              key={mode}
              onClick={() => setDisplayMode(mode)}
              className={`flex-1 py-3 rounded-full text-[9px] font-black uppercase tracking-widest transition-all duration-300 ${
                displayMode === mode 
                  ? 'bg-brand-deep text-white shadow-lg scale-100' 
                  : 'text-slate-400 hover:text-slate-600'
              }`}
            >
              {mode}
            </button>
          ))}
        </div>
      </div>

      <section className="space-y-1">
        <div className="glass-card rounded-[2rem] overflow-hidden border border-white/70 shadow-lg">
           <table className="w-full text-left border-collapse table-fixed">
              <thead>
                <tr className="bg-purple-50/50 border-b border-white/60">
                  <th className="p-4 text-[8px] font-black text-purple-900/40 uppercase tracking-widest w-[40%]">Metric Particulars</th>
                  <th className="p-4 text-right text-[8px] font-black text-purple-900/40 uppercase tracking-widest">Actual</th>
                  <th className="p-4 text-right text-[8px] font-black text-purple-900/40 uppercase tracking-widest">Budget</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-purple-100/10">
                <tr className="hover:bg-purple-100/5 transition-colors">
                  <td className="p-4 text-[10px] font-black text-brand-deep uppercase truncate">Vault Inflow/{cycleLabel.charAt(0)}</td>
                  <td className="p-4 text-right text-[12px] font-black text-emerald-600">{formatCurrency(currentDisplay.actualIncome, currency)}</td>
                  <td className="p-4 text-right text-[11px] font-black text-slate-400">{formatCurrency(currentDisplay.budgetIncome, currency)}</td>
                </tr>
                <tr className="hover:bg-purple-100/5 transition-colors">
                  <td className="p-4 text-[10px] font-black text-brand-deep uppercase truncate">Vault Outflow/{cycleLabel.charAt(0)}</td>
                  <td className="p-4 text-right text-[12px] font-black text-rose-500">{formatCurrency(currentDisplay.actualExpense, currency)}</td>
                  <td className="p-4 text-right text-[11px] font-black text-slate-400">{formatCurrency(currentDisplay.budgetExpense, currency)}</td>
                </tr>
                <tr className="bg-brand-purple/5">
                  <td className="p-4 text-[10px] font-black text-brand-deep uppercase truncate font-black">
                    {currentDisplay.actualSavings >= 0 ? `Net Savings` : `Net Deficit`}
                  </td>
                  <td className={`p-4 text-right text-[12px] font-black ${currentDisplay.actualSavings >= 0 ? 'text-brand-purple' : 'text-rose-600'}`}>
                    {formatCurrency(currentDisplay.actualSavings, currency)}
                  </td>
                  <td className="p-4 text-right text-[11px] font-black text-slate-400">
                    {formatCurrency(currentDisplay.budgetSavings, currency)}
                  </td>
                </tr>
              </tbody>
           </table>
        </div>
      </section>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
         <div className="glass-card p-5 rounded-[2.5rem] flex items-center justify-between border border-white/60">
            <div className="h-16 w-16 relative shrink-0">
               <ResponsiveContainer width="100%" height="100%">
                 <PieChart>
                   <Pie data={pieData} cx="50%" cy="50%" innerRadius="70%" outerRadius="90%" paddingAngle={2} dataKey="value" stroke="none">
                     {pieData.map((entry, index) => <Cell key={`cell-${index}`} fill={entry.color} />)}
                   </Pie>
                 </PieChart>
               </ResponsiveContainer>
               <div className="absolute top-[50%] left-[50%] -translate-x-1/2 -translate-y-1/2 text-center pointer-events-none">
                  <p className="text-[7px] font-black text-brand-deep leading-none">{formatCurrency(netWorthData.netWorth, currency).split('.')[0]}</p>
               </div>
            </div>
            <div className="flex-1 ml-4 space-y-1.5">
               <div className="flex justify-between items-center px-3 py-1.5 bg-white/40 rounded-xl border border-white/50">
                  <span className="text-[7px] font-black text-slate-400 uppercase tracking-widest">Total Assets</span>
                  <span className="text-[10px] font-black text-brand-deep">{formatCurrency(netWorthData.assets, currency)}</span>
               </div>
               <div className="flex justify-between items-center px-3 py-1.5 bg-brand-deep text-white rounded-xl shadow-lg shadow-purple-500/10">
                  <span className="text-[7px] font-black text-white/40 uppercase tracking-widest">Net Value</span>
                  <span className="text-[10px] font-black">{formatCurrency(netWorthData.netWorth, currency)}</span>
               </div>
            </div>
         </div>

         <div className="glass-card p-5 rounded-[2.5rem] bg-gradient-to-br from-indigo-50/50 to-purple-50/50 border border-indigo-200/20 flex flex-col justify-center">
            <h4 className="text-[8px] font-black text-brand-deep uppercase tracking-widest mb-2 leading-none text-center">In/Out Cycle Signal</h4>
            <div className="flex gap-2">
               <div className="flex-1 p-2 bg-white/80 rounded-xl border border-slate-100 text-center shadow-sm">
                  <p className="text-[7px] font-black text-slate-300 uppercase leading-none">Inflow</p>
                  <p className="text-xs font-black text-emerald-600 mt-1">{formatCurrency(currentDisplay.actualIncome, currency).split('.')[0]}</p>
               </div>
               <div className="flex-1 p-2 bg-white/80 rounded-xl border border-slate-100 text-center shadow-sm">
                  <p className="text-[7px] font-black text-slate-300 uppercase leading-none">Outflow</p>
                  <p className="text-xs font-black text-rose-500 mt-1">{formatCurrency(currentDisplay.actualExpense, currency).split('.')[0]}</p>
               </div>
            </div>
         </div>
      </div>
    </div>
  );
};

