const Transactions: React.FC = () => {
  const { filteredState, state, addTransaction, updateTransaction, deleteTransaction, uploadToDrive, setIsNavHidden } = useFinance();
  const familyMembers = (state.profile?.familyMembers || []).filter(m => m.status === 'verified');
  const natures = state.transactionNatures || [];

  const [showModal, setShowModal] = useState(false);
  const [modalMode, setModalMode] = useState<'single' | 'broker_note'>('single');
  const [brokerEngine, setBrokerEngine] = useState<'AI' | 'Excel'>('Excel');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [selectedQuickType, setSelectedQuickType] = useState<TransactionType>('Expense');

  const [isScanning, setIsScanning] = useState(false);
  const [scanStep, setScanStep] = useState<string>('');
  const [pendingFiles, setPendingFiles] = useState<File[]>([]);
  const [isUploading, setIsUploading] = useState(false);
  const [viewingAttachments, setViewingAttachments] = useState<Transaction | null>(null);
  const [filterMode, setFilterMode] = useState<'All' | 'Month'>('Month');

  const [scanResult, setScanResult] = useState<{ 
    date: string; 
    trades: ExtractedTrade[];
    otherCharges: number;
  } | null>(null);

  const uploadInputRef = useRef<HTMLInputElement>(null);
  const excelInputRef = useRef<HTMLInputElement>(null);
  const genericFileInputRef = useRef<HTMLInputElement>(null);
  const currency = state.profile.currency;

  useEffect(() => {
    setIsNavHidden(showModal || viewingAttachments !== null);
    return () => setIsNavHidden(false);
  }, [showModal, viewingAttachments, setIsNavHidden]);

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '', 
    nature: '', 
    description: '',
    accountId: '',
    date: new Date().toISOString().split('T')[0],
    ownerId: '',
    isin: '',
    stockName: '',
    units: '',
    billingPeriod: '',
    estimatedLife: '1' 
  };

  const [formData, setFormData] = useState(initialFormState);

  const allAccounts = useMemo(() => {
    const banks = (state.banks || []).map(b => ({ id: b.id, name: b.name, type: 'bank' as const, ownerId: b.ownerId }));
    const cards = (state.cards || []).map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const, ownerId: c.ownerId }));
    const liabilities = (state.liabilities || []).filter(l => l.type === 'Debt' || l.type === 'Payable').map(l => ({ id: l.id, name: l.name, type: 'liability' as const, ownerId: l.ownerId }));
    const wallets = (state.wallets || []).map(w => ({ id: w.id, name: w.name, type: 'wallet' as const, ownerId: w.ownerId }));
    return [...banks, ...cards, ...wallets, ...liabilities];
  }, [state.banks, state.cards, state.wallets, state.liabilities]);

  const transactionList = useMemo(() => {
    const all = filteredState.transactions || [];
    if (filterMode === 'All') return all;

    const now = new Date();
    const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
    return all.filter(t => new Date(t.date) >= startOfMonth);
  }, [filteredState.transactions, filterMode]);

  const processExcelWithDanfo = async (file: File) => {
    setIsScanning(true);
    setScanStep('Waking Up Processing Engines...');
    try {
      const [XLSX, dfd] = await Promise.all([
        import('xlsx'),
        import('danfojs')
      ]);

      setScanStep('Ingesting Byte Stream...');
      const arrayBuffer = await file.arrayBuffer();
      const workbook = XLSX.read(arrayBuffer);
      const firstSheetName = workbook.SheetNames[0];
      const worksheet = workbook.Sheets[firstSheetName];

      setScanStep('Scanning Sheet Matrix...');
      const rawData = XLSX.utils.sheet_to_json(worksheet, { header: 1 }) as any[][];

      let headerIndex = -1;
      for (let i = 0; i < Math.min(rawData.length, 50); i++) {
        const row = rawData[i];
        if (row && row.some(cell => String(cell || '').includes('Order No.'))) {
          headerIndex = i;
          break;
        }
      }

      if (headerIndex === -1) {
        throw new Error("Invalid format: 'Order No.' header not found in the first 50 rows.");
      }

      setScanStep('Mapping Row Schemas...');
      const headerRow = rawData[headerIndex] || [];
      const dataRows = rawData.slice(headerIndex + 1);
      const maxCols = headerRow.length;
      let camelColumns: string[] = headerRow.map((col, idx) => 
        toCamelCase(String(col || '')) || `col${idx}`
      );

      setScanStep('Calibrating DataFrame...');
      const cleanedDataRows = dataRows.map(row => {
        if (!Array.isArray(row)) return new Array(maxCols).fill(null);
        if (row.length === maxCols) return row;
        const newRow = [...row];
        while (newRow.length < maxCols) newRow.push(null);
        return newRow.slice(0, maxCols);
      });

      let df = new dfd.DataFrame(cleanedDataRows, { columns: camelColumns });

      setScanStep('Filtering Noise & Merged Cells...');
      if (df.columns.includes('orderTime')) {
        const validMask = df['orderTime'].values.map(val => {
          const s = String(val || "").trim();
          return s !== "" && s !== "null" && s !== "undefined" && !s.toLowerCase().includes('order time');
        });
        df = df.loc({ rows: validMask });
      }

      setScanStep('Normalizing Security Descriptions...');
      if (df.columns.includes('securityContractDescription')) {
        const splitResults = df['securityContractDescription'].values.map(val => {
          const parts = String(val || "").split('/');
          return {
            security: parts[0]?.trim() || '',
            contractDescription: parts[1]?.trim() || ''
          };
        });
        df.addColumn('security', splitResults.map(r => r.security));
        df.addColumn('contractDescription', splitResults.map(r => r.contractDescription));
      }

      setScanStep('Generating Review Ledger...');
      const jsonRecords = dfd.toJSON(df) as any[];
      const trades: ExtractedTrade[] = [];

      jsonRecords.forEach(row => {
        const units = Number(row.quantity || row.quantityTraded || 0);
        const netValue = Number(row.netTotalBeforeLeviesRs || row.netTotal || row.tradeValue || 0);
        const buySell = String(row.buyBSellS || row.buySell || '').toUpperCase();

        trades.push({
          scrip: row.security || row.securityContractDescription || 'Unknown Security',
          type: (buySell.includes('S') || buySell.includes('SELL')) ? 'SELL' : 'BUY',
          units: units,
          grossValue: (Number(row.grossRateTradePricePerUnitRs || row.grossRatePricePerUnit) * units) || netValue,
          netTotal: Math.abs(netValue),
          date: new Date().toISOString().split('T')[0],
          isin: String(row.isin || ''),
          stt: Number(row.stt || 0),
          allocatedCharges: 0
        });
      });

      setScanResult({
        date: new Date().toISOString().split('T')[0],
        otherCharges: 0,
        trades: trades
      });
      setModalMode('broker_note');
    } catch (e) {
      console.error("Engine Error:", e);
      alert(`Critical: ${e instanceof Error ? e.message : 'Unknown parsing error'}`);
    } finally {
      setIsScanning(false);
      setScanStep('');
    }
  };

  const processDocumentWithAI = async (file: File) => {
    if (!file.type.startsWith('image/') && file.type !== 'application/pdf') return;
    setIsScanning(true);
    setScanStep('Uploading to AI Vision...');
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const reader = new FileReader();
      const base64DataPromise = new Promise<string>((resolve) => {
        reader.onload = () => resolve((reader.result as string).split(',')[1]);
        reader.readAsDataURL(file);
      });
      const base64Data = await base64DataPromise;

      setScanStep('Analyzing Financial Geometry...');
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: {
          parts: [
            { inlineData: { mimeType: file.type, data: base64Data } },
            { text: "Analyze this financial document. Extract: netTotal (number), date (YYYY-MM-DD), merchant (string), description (string). If it is a stock contract note, extract trades array with scrip, type (BUY/SELL), units, netTotal for each trade line." }
          ]
        },
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              netTotal: { type: Type.NUMBER },
              date: { type: Type.STRING },
              merchant: { type: Type.STRING },
              description: { type: Type.STRING },
              trades: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    scrip: { type: Type.STRING },
                    type: { type: Type.STRING },
                    units: { type: Type.NUMBER },
                    netTotal: { type: Type.NUMBER },
                  }
                }
              }
            }
          }
        }
      });

      setScanStep('Deserializing Intelligence...');
      const text = response.text;
      if (text) {
        const data = JSON.parse(text);
        if (data.trades && data.trades.length > 0) {
           setScanResult({
             date: data.date || new Date().toISOString().split('T')[0],
             otherCharges: 0,
             trades: data.trades.map((t: any) => ({
               scrip: t.scrip,
               type: t.type?.toUpperCase() || 'BUY',
               units: t.units || 0,
               netTotal: t.netTotal || 0,
               grossValue: t.netTotal || 0,
               date: data.date || new Date().toISOString().split('T')[0],
               isin: '',
               stt: 0,
               allocatedCharges: 0
             }))
           });
           setModalMode('broker_note');
        } else {
           setFormData(prev => ({
             ...prev,
             amount: data.netTotal ? String(data.netTotal) : prev.amount,
             date: data.date || prev.date,
             description: data.description || (data.merchant ? `Payment to ${data.merchant}` : prev.description),
           }));
           setModalMode('single');
        }
      }
    } catch (e) {
      console.error("AI Scan failed", e);
      alert("Could not analyze document.");
    } finally {
      setIsScanning(false);
      setScanStep('');
    }
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>, mode: 'AI' | 'Excel') => {
    if (e.target.files) {
