                         <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Nature / Category</label>
                         <SearchableNatureSelect value={formData.nature} onChange={(val) => setFormData({ ...formData, nature: val })} options={natures} />
                      </div>
                    </div>

                    {(formData.type === 'Expense' || formData.type === 'Asset' || formData.type === 'Income') && (
                      <div className="space-y-2">
                         <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Estimated Life (Months)</label>
                         <div className="flex flex-col sm:flex-row items-stretch sm:items-center gap-3">
                            <input 
                               required
                               type="number" 
                               min="1"
                               className="flex-1 p-4 bg-slate-50 border border-slate-200 rounded-2xl font-black text-sm outline-none focus:ring-4 focus:ring-indigo-600/5 transition-all" 
                               value={formData.estimatedLife} 
                               onChange={e => setFormData({ ...formData, estimatedLife: e.target.value })} 
                            />
                            <div className="px-6 py-4 bg-indigo-50 border border-indigo-100 rounded-2xl flex items-center justify-center">
                               <span className="text-[9px] font-black text-indigo-600 uppercase tracking-widest">
                                 Amortized Over {formData.estimatedLife} Month(s)
                               </span>
                            </div>
                         </div>
                         <p className="text-[8px] font-bold text-slate-400 uppercase ml-2 tracking-tight">
                           Impact is spread across future months in reports. Use '1' for immediate impact.
                         </p>
                      </div>
                    )}

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                       <div className="space-y-2">
                          <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Target Account</label>
                          <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                            <option value="">Select Account</option>
                            {allAccounts.map(acc => (<option key={acc.id} value={acc.id}>{acc.name}</option>))}
                          </select>
                       </div>
                    </div>
                  </form>
                )}
                <div className="flex gap-4 pt-8 border-t border-slate-100">
                   <button type="button" onClick={() => { if (scanResult) setScanResult(null); else setShowModal(false); }} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-2xl">
                     {scanResult ? 'Discard' : 'Abort'}
                   </button>
                   <button onClick={scanResult ? handleBatchCommit : (modalMode === 'single' ? handleSingleCommit : undefined)} disabled={isUploading || isScanning} className={`flex-[2] py-5 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl flex items-center justify-center gap-2 disabled:opacity-50 ${modalMode === 'broker_note' && !scanResult ? 'hidden' : ''}`}>
                     {isUploading ? <span className="animate-spin">⏳ Commit in Progress...</span> : (scanResult ? `Commit ${scanResult.trades.length} Records` : 'Post to Ledger')}
                   </button>
                </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

