               </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { useState, useMemo, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Staff, StaffAttendance, WageType, Transaction } from '../types';

const StaffManager: React.FC = () => {
  const { state, addStaff, updateStaff, deleteStaff, logStaffAttendance, addTransaction } = useFinance();
  const [showAddStaff, setShowAddStaff] = useState(false);
  const [editingStaffId, setEditingStaffId] = useState<string | null>(null);
  const [selectedStaffId, setSelectedStaffId] = useState<string | null>(null);
  const [viewDate, setViewDate] = useState(new Date());
  const [showSettleModal, setShowSettleModal] = useState<Staff | null>(null);
  const [swapOverride, setSwapOverride] = useState<{ day: number, dateStr: string } | null>(null);
  const [selectedDay, setSelectedDay] = useState<number>(new Date().getDate());

  const [settlementMode, setSettlementMode] = useState<{ id: string, name: string, type: 'bank' | 'card' | 'wallet' | 'liability' } | null>(null);
  const [isRecordingSuccess, setIsRecordingSuccess] = useState(false);

  const [staffFormData, setStaffFormData] = useState({ 
    name: '', role: 'Maid', baseRate: '500', wageType: 'Daily' as WageType,
    joiningDate: new Date().toISOString().split('T')[0]
  });

  const [swapType, setSwapType] = useState<'OWN' | 'PROXY' | 'BOTH' | 'REMOVE'>('OWN');
  const [proxyRate, setProxyRate] = useState<string>('0');

  const currency = state.profile.currency;
  const staffList = state.staff || [];
  const selectedStaff = staffList.find(s => s.id === selectedStaffId);

  useEffect(() => {
    if (!selectedStaffId && staffList.length > 0) {
      setSelectedStaffId(staffList[0].id);
    }
  }, [staffList, selectedStaffId]);

  const daysInMonth = useMemo(() => {
    return new Date(viewDate.getFullYear(), viewDate.getMonth() + 1, 0).getDate();
  }, [viewDate]);

  const availableAccounts = useMemo(() => {
    const list: { id: string, name: string, type: 'bank' | 'card' | 'wallet' | 'liability' }[] = [];
    state.banks.forEach(b => list.push({ id: b.id, name: b.name, type: 'bank' }));
    state.wallets.forEach(w => list.push({ id: w.id, name: w.name, type: 'wallet' }));
    state.cards.forEach(c => list.push({ id: c.id, name: c.lenderName, type: 'card' }));
    return list;
  }, [state]);

  const monthName = viewDate.toLocaleString('default', { month: 'long', year: 'numeric' });

  const resetForm = () => {
    setStaffFormData({
      name: '', role: 'Maid', baseRate: '500', wageType: 'Daily',
      joiningDate: new Date().toISOString().split('T')[0]
    });
    setEditingStaffId(null);
  };

  const getAttendanceStatusForDay = (staff: Staff, dateStr: string) => {
    const manualLog = staff.attendance?.find(a => a.date === dateStr);
    if (manualLog) return manualLog;
    const today = new Date().toISOString().split('T')[0];
    if (dateStr >= staff.joiningDate && (!staff.exitDate || dateStr <= staff.exitDate) && dateStr <= today) {
       let rate = staff.baseRate;
       if (staff.wageType === 'Monthly') {
          rate = staff.baseRate / new Date(new Date(dateStr).getFullYear(), new Date(dateStr).getMonth() + 1, 0).getDate();
       }
       return { status: 'Present' as const, rate: rate, isSubstitute: false, isDefault: true };
    }
    return { status: 'None' as const, rate: 0, isSubstitute: false, isDefault: true };
  };

  const currentMonthStats = useMemo(() => {
    if (!selectedStaff) return { present: 0, absent: 0, swap: 0, total: 0 };
    let present = 0, absent = 0, swap = 0, total = 0;
    for (let i = 1; i <= daysInMonth; i++) {
      const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(i).padStart(2, '0')}`;
      const log = getAttendanceStatusForDay(selectedStaff, dateStr);
      if (log.status === 'Present') {
        present++;
        total += log.rate;
        if (log.isSubstitute) swap++;
      } else if (log.status === 'Absent') {
        absent++;
      }
    }
    return { present, absent, swap, total };
  }, [selectedStaff, viewDate, daysInMonth]);

  const handleSettle = (staff: Staff) => {
    if (!settlementMode) return alert("Select target account first.");
    const amount = currentMonthStats.total;
    if (amount <= 0) return alert("No dues to settle.");
    const tx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'Expense',
      amount: amount,
      nature: staff.name,
      description: `Wages payout for ${monthName}`,
      accountId: settlementMode.id,
      accountType: settlementMode.type,
      date: new Date().toISOString().split('T')[0],
      status: 'active'
    };
    addTransaction(tx);
    setIsRecordingSuccess(true);
    setSettlementMode(null);
  };

  const handleAttendanceToggle = (targetStatus: 'Present' | 'Absent') => {
    if (!selectedStaff) return;
    const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(selectedDay).padStart(2, '0')}`;
    const currentLog = getAttendanceStatusForDay(selectedStaff, dateStr);
    if (!(currentLog as any).isDefault && currentLog.status === targetStatus) {
      logStaffAttendance(selectedStaff.id, { date: dateStr, status: 'None' });
      return;
    }
    let rate = targetStatus === 'Present' ? selectedStaff.baseRate : 0;
    if (targetStatus === 'Present' && selectedStaff.wageType === 'Monthly') {
      rate = selectedStaff.baseRate / new Date(viewDate.getFullYear(), viewDate.getMonth() + 1, 0).getDate();
    }
    logStaffAttendance(selectedStaff.id, { date: dateStr, status: targetStatus, rate: rate, isSubstitute: false });
  };

  const handleCommitSwap = () => {
    if (!selectedStaff || !swapOverride) return;
    const { dateStr } = swapOverride;
    if (swapType === 'REMOVE') {
      logStaffAttendance(selectedStaff.id, { date: dateStr, status: 'None' });
    } else {
      let finalRate = 0, isSub = false;
      if (swapType === 'OWN') {
        finalRate = selectedStaff.baseRate;
        if (selectedStaff.wageType === 'Monthly') {
          finalRate = selectedStaff.baseRate / new Date(viewDate.getFullYear(), viewDate.getMonth() + 1, 0).getDate();
        }
      } else if (swapType === 'PROXY') {
        finalRate = Number(proxyRate); isSub = true;
      } else if (swapType === 'BOTH') {
        let ownRate = selectedStaff.baseRate;
        if (selectedStaff.wageType === 'Monthly') ownRate = selectedStaff.baseRate / new Date(viewDate.getFullYear(), viewDate.getMonth() + 1, 0).getDate();
        finalRate = ownRate + Number(proxyRate); isSub = true;
      }
      logStaffAttendance(selectedStaff.id, { date: dateStr, status: 'Present', rate: finalRate, isSubstitute: isSub });
    }
    setSwapOverride(null);
  };

  return (
    <div className="flex flex-col md:flex-row gap-4 md:gap-6 animate-in fade-in duration-500 font-sans p-2 pb-24 max-w-full overflow-x-hidden">

      {/* Registry Panel */}
      <div className="w-full md:w-80 flex flex-col bg-slate-50 border border-slate-200 rounded-[2.5rem] shadow-sm shrink-0">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-white rounded-t-[2.5rem]">
          <div>
            <h3 className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Personnel</h3>
            <p className="text-[7px] font-bold text-slate-300 uppercase tracking-widest">Registry Audit</p>
          </div>
          <button 
            onClick={() => { resetForm(); setShowAddStaff(true); }} 
            className="w-10 h-10 flex items-center justify-center bg-brand-deep text-white rounded-2xl text-xl shadow-lg active:scale-90 transition-transform"
          >
            +
          </button>
        </div>
        <div className="flex md:flex-col overflow-x-auto md:overflow-y-visible no-scrollbar p-4 gap-3">
          {staffList.map(s => (
            <div 
              key={s.id} 
              onClick={() => setSelectedStaffId(s.id)} 
              className={`flex-none md:flex-1 p-4 rounded-3xl cursor-pointer transition-all border flex items-center gap-4 min-w-[160px] md:min-w-0 ${selectedStaffId === s.id ? 'bg-indigo-600 border-indigo-700 text-white shadow-xl' : 'bg-white border-slate-100 text-slate-800'}`}
            >
              <div className={`w-11 h-11 rounded-2xl flex items-center justify-center text-lg shrink-0 font-black ${selectedStaffId === s.id ? 'bg-white/20' : 'bg-slate-100 text-slate-400'}`}>
                {s.name.charAt(0)}
              </div>
              <div className="min-w-0">
                <p className="text-[10px] font-black uppercase truncate leading-none mb-1">{s.name}</p>
                <p className={`text-[8px] font-black uppercase tracking-widest ${selectedStaffId === s.id ? 'text-white/60' : 'text-slate-400'}`}>{s.role}</p>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Main Workspace */}
      <div className="flex-1 flex flex-col bg-white border border-slate-200 rounded-[3rem] shadow-sm relative min-h-0">
        {selectedStaff ? (
          <>
            <div className="p-6 md:p-8 border-b border-slate-100 flex flex-col sm:flex-row justify-between items-center gap-6">
              <div className="flex items-center gap-5 w-full sm:w-auto">
                <div className="w-16 h-16 bg-slate-900 text-white rounded-[1.5rem] flex items-center justify-center text-2xl font-black shadow-xl">
                  {selectedStaff.name.charAt(0).toLowerCase()}
                </div>
                <div className="flex-1">
                   <div className="flex items-center gap-3">
                      <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tighter">{selectedStaff.name}</h2>
                      <button onClick={() => { 
                        setEditingStaffId(selectedStaff.id); 
                        setStaffFormData({ name: selectedStaff.name, role: selectedStaff.role, baseRate: String(selectedStaff.baseRate), wageType: selectedStaff.wageType, joiningDate: selectedStaff.joiningDate }); 
                        setShowAddStaff(true); 
                      }} className="text-slate-300 hover:text-indigo-600">✎</button>
                   </div>
                   <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">{selectedStaff.role} • {selectedStaff.wageType} Basis</p>
                </div>
              </div>
              <div className="flex items-center gap-1 bg-slate-50 p-1 rounded-full border border-slate-100 shrink-0">
                 <button onClick={() => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() - 1))} className="w-8 h-8 flex items-center justify-center hover:bg-white rounded-full transition-all">←</button>
                 <span className="px-4 text-[9px] font-black uppercase tracking-[0.2em]">{monthName}</span>
                 <button onClick={() => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() + 1))} className="w-8 h-8 flex items-center justify-center hover:bg-white rounded-full transition-all">→</button>
              </div>
            </div>

            <div className="p-6 md:p-8 space-y-8">
              <div className="grid grid-cols-7 border border-slate-100 rounded-[2.5rem] overflow-hidden bg-white shadow-xl">
                {['S','M','T','W','T','F','S'].map((d, i) => (
                  <div key={i} className="py-4 text-center text-[9px] font-black text-slate-300 uppercase bg-slate-50/50 border-b border-slate-50">{d}</div>
                ))}
                {Array.from({ length: new Date(viewDate.getFullYear(), viewDate.getMonth(), 1).getDay() }).map((_, i) => (
                  <div key={`empty-${i}`} className="aspect-square bg-slate-50/10"></div>
                ))}
                {Array.from({ length: daysInMonth }).map((_, i) => {
                  const day = i + 1;
                  const dateStr = `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
                  const log = getAttendanceStatusForDay(selectedStaff, dateStr);
                  const isActive = selectedDay === day;
                  return (
                    <div 
                      key={day} 
                      onClick={() => setSelectedDay(day)}
                      className={`group flex flex-col items-center justify-center aspect-square cursor-pointer transition-all relative border-t border-l border-slate-50 ${isActive ? 'bg-indigo-600 text-white z-10 rounded-xl shadow-2xl scale-105' : 'bg-white hover:bg-slate-50'}`}
                    >
                      <span className={`text-xs font-black ${isActive ? 'text-white' : 'text-slate-400 group-hover:text-slate-900'}`}>{day}</span>
                      <div className="mt-1 h-1">
                        {log.status === 'Present' && <div className={`w-1 h-1 rounded-full ${isActive ? 'bg-white' : (log.isSubstitute ? 'bg-amber-400' : 'bg-emerald-500')}`}></div>}
                        {log.status === 'Absent' && <div className={`w-1 h-1 rounded-full ${isActive ? 'bg-white/50' : 'bg-rose-400'}`}></div>}
                      </div>
                    </div>
                  );
                })}
              </div>

              <div className="flex flex-col lg:flex-row items-stretch lg:items-center gap-6">
                <div className="flex-1 flex gap-2">
                  <button onClick={() => handleAttendanceToggle('Present')} className={`flex-1 py-5 rounded-2xl border-2 flex flex-col items-center gap-2 ${getAttendanceStatusForDay(selectedStaff, `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(selectedDay).padStart(2, '0')}`).status === 'Present' ? 'bg-emerald-500 border-emerald-600 text-white' : 'bg-slate-50 border-slate-100 text-slate-400'}`}>
                    <span className="text-xl">✅</span>
                    <span className="text-[8px] font-black uppercase tracking-widest">Present</span>
                  </button>
                  <button onClick={() => handleAttendanceToggle('Absent')} className={`flex-1 py-5 rounded-2xl border-2 flex flex-col items-center gap-2 ${getAttendanceStatusForDay(selectedStaff, `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(selectedDay).padStart(2, '0')}`).status === 'Absent' ? 'bg-rose-500 border-rose-600 text-white' : 'bg-slate-50 border-slate-100 text-slate-400'}`}>
                    <span className="text-xl">❌</span>
                    <span className="text-[8px] font-black uppercase tracking-widest">Absent</span>
                  </button>
                  <button onClick={() => setSwapOverride({ day: selectedDay, dateStr: `${viewDate.getFullYear()}-${String(viewDate.getMonth() + 1).padStart(2, '0')}-${String(selectedDay).padStart(2, '0')}` })} className="flex-1 py-5 rounded-2xl border-2 border-slate-100 bg-slate-50 flex flex-col items-center gap-2 text-slate-400 active:scale-95 transition-all">
                    <span className="text-xl">🔄</span>
                    <span className="text-[8px] font-black uppercase tracking-widest">Swap</span>
                  </button>
                </div>
                <div className="lg:w-64 p-6 bg-slate-900 rounded-[2rem] text-white flex items-center justify-between gap-4 shadow-xl">
                   <div><p className="text-[8px] font-black text-indigo-400 uppercase tracking-widest">Dues</p><p className="text-xl font-black tracking-tighter">{formatCurrency(currentMonthStats.total, currency).split('.')[0]}</p></div>
                   <button onClick={() => setShowSettleModal(selectedStaff)} className="px-4 py-2.5 bg-indigo-600 text-white rounded-xl text-[8px] font-black uppercase tracking-widest active:scale-95 transition-transform">Settle</button>
                </div>
              </div>
            </div>
          </>
        ) : (
          <div className="flex-1 flex flex-col items-center justify-center p-20 text-center text-slate-300">
             <span className="text-4xl mb-4">👥</span>
             <p className="text-[10px] font-black uppercase tracking-widest">Select Personnel to Audit</p>
          </div>
        )}
      </div>

      {/* SWAP PROTOCOL MODAL */}
      {swapOverride && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/90 backdrop-blur-xl p-6">
           <div className="bg-white w-full max-w-md rounded-[3rem] p-10 shadow-2xl animate-in zoom-in-95 border border-slate-200">
              <div className="flex justify-between items-center mb-8">
                 <h3 className="text-2xl font-black text-slate-800 uppercase tracking-tighter">Duty Protocol</h3>
                 <button onClick={() => setSwapOverride(null)} className="text-slate-300 hover:text-slate-800 text-2xl font-black">✕</button>
              </div>
              <div className="space-y-3">
                 {[
                   { id: 'OWN', label: 'Self Entry (Standard)', icon: '👤' },
                   { id: 'PROXY', label: 'Proxy Personnel', icon: '🔄' },
                   { id: 'BOTH', label: 'Double Shift (Full Pay)', icon: '⭐' },
                   { id: 'REMOVE', label: 'Clear Day Entry', icon: '🧹' }
                 ].map(t => (
                   <button key={t.id} onClick={() => setSwapType(t.id as any)} className={`w-full p-5 text-left rounded-2xl border-2 transition-all flex items-center gap-5 group ${swapType === t.id ? 'bg-indigo-600 border-indigo-700 text-white shadow-xl' : 'bg-slate-50 border-transparent hover:border-slate-200'}`}>
                      <span className="text-2xl">{t.icon}</span>
                      <p className={`text-[11px] font-black uppercase tracking-widest ${swapType === t.id ? 'text-white' : 'text-slate-800'}`}>{t.label}</p>
                   </button>
                 ))}
              </div>
              {swapType !== 'OWN' && swapType !== 'REMOVE' && (
                <div className="mt-6 space-y-2 animate-in slide-in-from-top-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-2">Override Payout ({currency})</label>
                  <input type="number" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl font-black text-xl outline-none" value={proxyRate} onChange={e => setProxyRate(e.target.value)} />
                </div>
              )}
              <div className="flex gap-4 mt-8">
                 <button onClick={() => setSwapOverride(null)} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-2xl">Abort</button>
                 <button onClick={handleCommitSwap} className="flex-[2] py-5 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl active:scale-95">Commit Log</button>
              </div>
           </div>
        </div>
      )}

      {/* ADD STAFF MODAL */}
      {showAddStaff && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/90 backdrop-blur-xl p-4">
           <div className="bg-white w-full max-w-md rounded-[3rem] p-10 border border-slate-200 shadow-2xl animate-in zoom-in-95">
              <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight mb-8">{editingStaffId ? 'Modify' : 'New'} Personnel</h3>
              <div className="space-y-6">
                 <input className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-black text-xs uppercase" value={staffFormData.name} onChange={e => setStaffFormData({...staffFormData, name: e.target.value})} placeholder="Identity" />
                 <div className="grid grid-cols-2 gap-4">
                    <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-black text-xs uppercase" value={staffFormData.wageType} onChange={e => setStaffFormData({...staffFormData, wageType: e.target.value as WageType})}><option value="Monthly">Monthly</option><option value="Daily">Daily</option></select>
                    <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-black text-xs uppercase" value={staffFormData.role} onChange={e => setStaffFormData({...staffFormData, role: e.target.value})}><option>Maid</option><option>Cook</option><option>Driver</option></select>
                 </div>
                 <input type="number" className="w-full p-6 bg-slate-900 text-white border border-slate-800 rounded-3xl font-black text-3xl text-center" value={staffFormData.baseRate} onChange={e => setStaffFormData({...staffFormData, baseRate: e.target.value})} />
                 <div className="flex gap-4 pt-4">
                    <button onClick={() => setShowAddStaff(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-2xl">Cancel</button>
                    <button onClick={() => {
                      if (!staffFormData.name) return;
                      const data: Staff = { id: editingStaffId || Math.random().toString(36).substr(2, 9), name: staffFormData.name, role: staffFormData.role, baseRate: Number(staffFormData.baseRate), wageType: staffFormData.wageType, attendance: editingStaffId ? staffList.find(s=>s.id===editingStaffId)?.attendance || [] : [], joiningDate: staffFormData.joiningDate };
                      editingStaffId ? updateStaff(data) : addStaff(data);
                      setShowAddStaff(false); resetForm();
                    }} className="flex-[2] py-4 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl">Commit</button>
                 </div>
              </div>
           </div>
        </div>
      )}

      {/* SETTLEMENT MODAL */}
      {showSettleModal && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-slate-900/95 backdrop-blur-2xl p-6">
           <div className="bg-white w-full max-w-sm rounded-[3.5rem] p-12 shadow-2xl text-center animate-in zoom-in-95 border border-slate-200">
              {!isRecordingSuccess ? (
                <>
                  <div className="w-20 h-20 bg-emerald-50 text-emerald-600 rounded-[2rem] flex items-center justify-center text-4xl mx-auto mb-8 shadow-inner border border-emerald-100">💸</div>
                  <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tighter mb-2">Wage Settlement</h3>
                  <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest mb-10">{monthName}</p>
                  <div className="p-10 bg-slate-50 rounded-[2.5rem] mb-10 shadow-inner border border-slate-100">
                    <p className="text-5xl font-black text-slate-900 tracking-tighter">{formatCurrency(currentMonthStats.total, currency).split('.')[0]}</p>
                    <p className="text-[9px] font-black text-indigo-400 uppercase mt-4 tracking-widest font-black">Verified Dues</p>
                  </div>
                  <div className="space-y-6">
                    <div className="space-y-2">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block text-left ml-3">Payout Account</label>
                       <select className="w-full p-5 bg-slate-100 border border-slate-200 rounded-2xl font-black text-xs outline-none cursor-pointer uppercase" value={settlementMode?.id || ''} onChange={(e) => {
                           const acc = availableAccounts.find(a => a.id === e.target.value);
                           if (acc) setSettlementMode(acc as any);
                         }}>
                         <option value="">Select Account</option>
                         {availableAccounts.map(acc => (<option key={acc.id} value={acc.id}>{acc.name} ({acc.type})</option>))}
                       </select>
                    </div>
                    <div className="flex flex-col gap-4">
                      <button onClick={() => handleSettle(showSettleModal)} className="w-full py-6 bg-indigo-600 text-white font-black text-xs uppercase tracking-[0.2em] rounded-2xl shadow-2xl active:scale-95">Release Funds</button>
                      <button onClick={() => { setShowSettleModal(null); setSettlementMode(null); }} className="w-full py-4 bg-slate-100 text-slate-400 font-black text-[9px] uppercase rounded-2xl">Abort</button>
                    </div>
                  </div>
                </>
              ) : (
                <div className="animate-in zoom-in-95 duration-700 py-10">
                  <div className="w-28 h-28 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center text-6xl mx-auto mb-10 shadow-2xl border border-emerald-200">✅</div>
                  <h3 className="text-3xl font-black text-slate-900 uppercase tracking-tighter mb-3">Settled</h3>
                  <button onClick={() => { setShowSettleModal(null); setIsRecordingSuccess(false); }} className="w-full py-6 bg-slate-900 text-white font-black text-xs uppercase rounded-2xl shadow-2xl active:scale-95">Back to Console</button>
                </div>
              )}
           </div>
        </div>
      )}
    </div>
  );
};

export default StaffManager;

import React, { createContext, useContext, useState, useEffect, ReactNode, useMemo } from 'react';
import { FinancialState, UserProfile, BankAccount, CreditCard, Wallet, IncomeStream, Expense, Asset, Liability, Transaction, FamilyMember, Notification, Budget, MonitoredApp, MemberPermissions, TransactionAttachment, Staff, StaffAttendance } from '../types';
import { supabase } from '../lib/supabase';

interface FinanceContextType {
  state: FinancialState;
  filteredState: FinancialState;
  isAuthenticated: boolean;
  activeMemberIds: string[];
  isCloudSyncing: boolean;
  connectionStatus: 'online' | 'offline' | 'checking';
  isNavHidden: boolean;
  setIsNavHidden: (hidden: boolean) => void;
  setActiveMemberIds: (ids: string[]) => void;
  setAuthenticated: (value: boolean) => void;
  updateProfile: (profile: UserProfile) => void;
  addFamilyMember: (member: FamilyMember) => Promise<{ success: boolean; syncedCount: number; error?: string }>;
  removeFamilyMember: (id: string) => void;
  updateMemberPermissions: (id: string, permissions: MemberPermissions) => void;
  verifyFamilyMember: (id: string) => void;
  approveTransaction: (id: string) => void;
  approveTransactions: (ids: string[]) => void;
  rejectTransaction: (id: string) => void;
  rejectTransactions: (ids: string[]) => void;
  addBank: (bank: BankAccount) => void;
  updateBank: (bank: BankAccount) => void;
  deleteBank: (id: string) => void;
  addCard: (card: CreditCard) => void;
  updateCard: (card: CreditCard) => void;
  deleteCard: (id: string) => void;
  addWallet: (wallet: Wallet) => void;
  updateWallet: (wallet: Wallet) => void;
  deleteWallet: (id: string) => void;
  addIncome: (income: IncomeStream) => void;
  addExpense: (expense: Expense) => void;
  addAsset: (asset: Asset) => void;
  updateAsset: (asset: Asset) => void;
  deleteAsset: (id: string) => void;
  addLiability: (liability: Liability) => void;
  updateLiability: (liability: Liability) => void;
  deleteLiability: (id: string) => void;
  addTransaction: (transaction: Transaction) => void;
  updateTransaction: (transaction: Transaction) => void;
  deleteTransaction: (id: string) => void;
  addBudget: (budget: Budget) => void;
  updateBudget: (budget: Budget) => void;
  deleteBudget: (id: string) => void;
  addTransactionNature: (nature: string) => void;
  deleteTransactionNature: (nature: string) => void;
  addStaff: (staff: Staff) => void;
  updateStaff: (staff: Staff) => void;
  deleteStaff: (id: string) => void;
  logStaffAttendance: (staffId: string, attendance: StaffAttendance | { date: string, status: 'None' }) => void;
  clearNotifications: () => void;
  markNotificationRead: (id: string) => void;
  simulateSync: () => Promise<void>;
  resetBoarding: () => Promise<void>;
  loadStateFromCloud: (mobile: string) => Promise<boolean>;
  verifyConnection: () => Promise<boolean>;
  importState: (newState: FinancialState) => void;
  updateMonitoredApps: (apps: MonitoredApp[]) => void;
  simulateIncomingRequest: (name: string, mobile: string, relation: string) => void;
  handleFamilyRequest: (notificationId: string, accepted: boolean) => void;
  uploadToDrive: (file: File) => Promise<TransactionAttachment>;
}

const GLOBAL_SESSION_KEY = 'myfin_active_session';
const STATE_PREFIX = 'myfin_state_';

const DEFAULT_PERMISSIONS: MemberPermissions = {
  viewDashboard: true,
  viewStatements: true,
  viewBudget: true,
  viewTransactions: true,
  viewCalendar: true,
  viewAccounts: true,
  canCreateTransactions: true
};

const initialState: FinancialState = {
  profile: { 
    name: '', designation: '', age: 0, city: '', country: 'India', currency: 'INR', mobileNumber: '',
    isBoarded: false, familyMembers: [], cloudDatabaseName: 'Default_Vault', monitoredApps: [], remindersEnabled: false,
    googleDriveConfig: { folderId: '', folderName: '', isConnected: false, linkedEmail: '' }
  },
  banks: [{ id: 'def-bank-1', name: 'Primary Savings Bank', balance: 0, accountType: 'Savings', classification: 'Current Asset' }],
  cards: [{ id: 'def-card-1', lenderName: 'Main Credit Card', balance: 0, last4: '0000', billingDay: 1, dueDate: '2024-01-15', offers: { movie: true, dining: true, concierge: false, lounge: true }, classification: 'Current Liability' }],
  wallets: [{ id: 'def-wallet-1', name: 'Cash', balance: 0, classification: 'Current Asset' }],
  incomes: [], expenses: [], assets: [], liabilities: [], transactions: [], budgets: [], notifications: [], transactionNatures: ['Salary', 'Rent', 'Food', 'Investment', 'Daily House Help'], capital: 0, staff: []
};

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error('useFinance must be used within a FinanceProvider');
  return context;
};

export const FinanceProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [isAuthenticated, setAuthenticated] = useState(false);
  const [activeMemberIds, setActiveMemberIds] = useState<string[]>([]);
  const [isCloudSyncing, setIsCloudSyncing] = useState(false);
  const [connectionStatus, setConnectionStatus] = useState<'online' | 'offline' | 'checking'>('checking');
  const [isNavHidden, setIsNavHidden] = useState(false);
  const [state, setState] = useState<FinancialState>(() => {
    const mobile = localStorage.getItem(GLOBAL_SESSION_KEY);
    if (mobile) {
      const saved = localStorage.getItem(`${STATE_PREFIX}${mobile}`);
      if (saved) return { ...initialState, ...JSON.parse(saved) };
    }
    return initialState;
  });

  const verifyConnection = async (): Promise<boolean> => {
    setConnectionStatus('checking');
    try {
      // Use a simple health check query that is lightweight
      const { error } = await supabase.from('user_states').select('mobile_number').limit(1);
      if (error) {
        setConnectionStatus('offline');
        return false;
      }
      setConnectionStatus('online');
      return true;
    } catch (err) {
      setConnectionStatus('offline');
      return false;
    }
  };

  useEffect(() => {
    const activeSession = localStorage.getItem(GLOBAL_SESSION_KEY);
    if (activeSession && state.profile.isBoarded && state.profile.mobileNumber === activeSession) {
      setAuthenticated(true);
      verifyConnection();
    }
  }, []);

  useEffect(() => {
    if (state.profile.mobileNumber && state.profile.isBoarded) {
      localStorage.setItem(GLOBAL_SESSION_KEY, state.profile.mobileNumber);
      localStorage.setItem(`${STATE_PREFIX}${state.profile.mobileNumber}`, JSON.stringify(state));

      const syncToCloud = async () => {
        setIsCloudSyncing(true);
        try {
          const { error } = await supabase.from('user_states').upsert({
            mobile_number: state.profile.mobileNumber,
            state: state,
            updated_at: new Date().toISOString()
          }, { onConflict: 'mobile_number' });

          if (error) {
            console.error('Supabase Sync Error:', error.message);
            setConnectionStatus('offline');
          } else {
            setConnectionStatus('online');
          }
        } catch (err) {
          console.error('Cloud Sync Exception:', err);
          setConnectionStatus('offline');
        } finally {
          setIsCloudSyncing(false);
        }
      };

      const timer = setTimeout(syncToCloud, 2000);
      return () => clearTimeout(timer);
    }
  }, [state]);

  const loadStateFromCloud = async (mobile: string): Promise<boolean> => {
    setIsCloudSyncing(true);
    setConnectionStatus('checking');
    try {
      const { data, error } = await supabase.from('user_states').select('state').eq('mobile_number', mobile).single();
      if (error && error.code !== 'PGRST116') {
        setConnectionStatus('offline');
        return false;
      }
      setConnectionStatus('online');
      if (data && data.state) {
        setState(prev => ({ ...initialState, ...data.state }));
        return true;
      }
      return false;
    } catch (err) {
      setConnectionStatus('offline');
      return false;
    } finally {
      setIsCloudSyncing(false);
    }
  };

  const simulateSync = async () => {
    if (state.profile.mobileNumber) await loadStateFromCloud(state.profile.mobileNumber);
  };

  const resetBoarding = async () => {
    if (state.profile.mobileNumber) localStorage.removeItem(`${STATE_PREFIX}${state.profile.mobileNumber}`);
    localStorage.removeItem(GLOBAL_SESSION_KEY);
    setAuthenticated(false);
    setState(initialState);
    setActiveMemberIds([]);
  };

  const uploadToDrive = async (file: File): Promise<TransactionAttachment> => {
    return new Promise((resolve) => {
      setTimeout(() => {
        resolve({
          id: `file_${Math.random().toString(36).substr(2, 9)}`,
          name: file.name,
          url: '#',
          mimeType: file.type,
          uploadDate: new Date().toISOString()
        });
      }, 1500);
    });
  };

  const applyTransactionEffect = (transaction: Transaction, newState: FinancialState, isReversing: boolean) => {
    if (transaction.status === 'pending_approval') return; 
    const factor = isReversing ? -1 : 1;
    const totalAmount = transaction.amount || 0;
    const balanceDelta = (transaction.type === 'Income' || transaction.type === 'Liability') ? totalAmount : -totalAmount;
    const finalBalanceDelta = balanceDelta * factor;

    if (transaction.accountType === 'bank') {
      newState.banks = newState.banks.map(b => b.id === transaction.accountId ? { ...b, balance: b.balance + finalBalanceDelta } : b);
    } else if (transaction.accountType === 'card') {
      const cardDelta = (transaction.type === 'Income' || transaction.type === 'Liability' ? -totalAmount : totalAmount) * factor;
      newState.cards = newState.cards.map(c => c.id === transaction.accountId ? { ...c, balance: c.balance + cardDelta } : c);
    } else if (transaction.accountType === 'wallet') {
      newState.wallets = newState.wallets.map(w => w.id === transaction.accountId ? { ...w, balance: w.balance + finalBalanceDelta } : w);
    } else if (transaction.accountType === 'liability') {
      const liabilityDelta = (transaction.type === 'Income' || transaction.type === 'Liability' ? -totalAmount : totalAmount) * factor;
      newState.liabilities = newState.liabilities.map(l => l.id === transaction.accountId ? { ...l, amount: l.amount + liabilityDelta } : l);
    }
  };

  const addTransaction = (transaction: Transaction) => {
    setState(prev => {
      const isForSelf = !transaction.ownerId || transaction.ownerId === '';
      const finalStatus: 'active' | 'pending_approval' = isForSelf ? 'active' : 'pending_approval';
      const creatorName = prev.profile.name || 'System'; 
      const txWithStatus: Transaction = { ...transaction, status: finalStatus, createdBy: creatorName };
      const newState = { ...prev, transactions: [txWithStatus, ...prev.transactions] };
      applyTransactionEffect(txWithStatus, newState, false);

      if (finalStatus === 'pending_approval') {
        const ownerName = prev.profile.familyMembers.find(m => m.id === transaction.ownerId)?.name || 'Member';
        newState.notifications = [{
          id: `approval_${txWithStatus.id}`,
          title: 'Pending Audit Sign-off',
          message: `A transaction of ${txWithStatus.amount} for ${ownerName} requires their verification.`,
          timestamp: new Date().toLocaleTimeString(),
          type: 'approval_request',
          isRead: false,
          transactionId: txWithStatus.id
        }, ...newState.notifications];
      }
      return newState;
    });
  };

  const approveTransaction = (id: string) => {
    setState(prev => {
      const tx = prev.transactions.find(t => t.id === id);
      if (!tx) return prev;
      const updatedTx = { ...tx, status: 'active' as const };
      const newState = { ...prev, transactions: prev.transactions.map(t => t.id === id ? updatedTx : t) };
      applyTransactionEffect(updatedTx, newState, false);
      newState.notifications = prev.notifications.filter(n => n.transactionId !== id);
      return newState;
    });
  };

  const approveTransactions = (ids: string[]) => {
    setState(prev => {
      let newState = { ...prev };
      const pendingTxs = prev.transactions.filter(t => ids.includes(t.id) && t.status === 'pending_approval');
      if (pendingTxs.length === 0) return prev;
      newState.transactions = prev.transactions.map(t => {
        if (ids.includes(t.id) && t.status === 'pending_approval') return { ...t, status: 'active' as const };
        return t;
      });
      pendingTxs.forEach(tx => applyTransactionEffect({ ...tx, status: 'active' }, newState, false));
      newState.notifications = prev.notifications.filter(n => !n.transactionId || !ids.includes(n.transactionId));
      return newState;
    });
  };

  const rejectTransaction = (id: string) => {
    setState(prev => ({
      ...prev,
      transactions: prev.transactions.filter(t => t.id !== id),
      notifications: prev.notifications.filter(n => n.transactionId !== id)
    }));
  };

  const rejectTransactions = (ids: string[]) => {
    setState(prev => ({
      ...prev,
      transactions: prev.transactions.filter(t => !ids.includes(t.id)),
      notifications: prev.notifications.filter(n => !n.transactionId || !ids.includes(n.transactionId))
    }));
  };

  const addFamilyMember = async (member: FamilyMember) => {
    setState(prev => ({ ...prev, profile: { ...prev.profile, familyMembers: [...prev.profile.familyMembers, { ...member, permissions: DEFAULT_PERMISSIONS, status: 'pending_invitation' }] } }));
    return { success: true, syncedCount: 0 };
  };

  const verifyFamilyMember = (id: string) => {
    setState(prev => ({
      ...prev,
      profile: { ...prev.profile, familyMembers: prev.profile.familyMembers.map(m => m.id === id ? { ...m, status: 'verified' as const } : m) }
    }));
  };

  const updateMemberPermissions = (id: string, permissions: MemberPermissions) => {
    setState(prev => ({
      ...prev,
      profile: { ...prev.profile, familyMembers: prev.profile.familyMembers.map(m => m.id === id ? { ...m, permissions } : m) }
    }));
  };

  const simulateIncomingRequest = (name: string, mobile: string, relation: string) => {
    const newNotif: Notification = {
      id: `req_${Date.now()}`,
      title: 'Priority: Family Link Request',
      message: `${name} (${relation}) is requesting to link vaults with you. Accept to grant access based on their settings.`,
      timestamp: new Date().toLocaleTimeString(),
      type: 'family_request',
      isRead: false,
      requestData: { name, mobile, relation }
    };
    setState(prev => ({ ...prev, notifications: [newNotif, ...prev.notifications] }));
  };

  const handleFamilyRequest = (notificationId: string, accepted: boolean) => {
    setState(prev => {
      let newState = { ...prev };
      const notif = prev.notifications.find(n => n.id === notificationId);
      newState.notifications = prev.notifications.filter(n => n.id !== notificationId);
      if (accepted && notif && notif.requestData) {
        const newMember: FamilyMember = {
          id: `mem_${Date.now()}`,
          name: notif.requestData.name,
          mobileNumber: notif.requestData.mobile,
          relation: notif.requestData.relation,
          status: 'verified',
          permissions: DEFAULT_PERMISSIONS
        };
        if (!prev.profile.familyMembers.some(m => m.mobileNumber === newMember.mobileNumber)) {
          newState.profile.familyMembers = [...prev.profile.familyMembers, newMember];
        } else {
          newState.profile.familyMembers = prev.profile.familyMembers.map(m => m.mobileNumber === newMember.mobileNumber ? { ...m, status: 'verified' } : m);
        }
      }
      return newState;
    });
  };

  const addTransactionNature = (nature: string) => {
    setState(prev => {
      if (prev.transactionNatures.includes(nature)) return prev;
      return { ...prev, transactionNatures: [...prev.transactionNatures, nature] };
    });
  };

  const deleteTransactionNature = (nature: string) => {
    setState(prev => ({ ...prev, transactionNatures: prev.transactionNatures.filter(n => n !== nature) }));
  };

  const addStaff = (staff: Staff) => {
    setState(prev => {
      const updatedNatures = [...prev.transactionNatures];
      if (!updatedNatures.includes(staff.name)) updatedNatures.push(staff.name);

      const updatedLiabilities = [...(prev.liabilities || [])];
      const ledgerName = `Wages Payable - ${staff.name}`;
      if (!updatedLiabilities.some(l => l.name === ledgerName)) {
        updatedLiabilities.push({
          id: `staff_ledger_${staff.id}`,
          name: ledgerName,
          amount: 0,
          type: 'Payable',
          classification: 'Current Liability'
        });
      }

      return { 
        ...prev, 
        staff: [...(prev.staff || []), staff], 
        transactionNatures: updatedNatures,
        liabilities: updatedLiabilities
      };
    });
  };

  const updateStaff = (staff: Staff) => {
    setState(prev => {
      const oldStaff = prev.staff.find(s => s.id === staff.id);
      const updatedNatures = prev.transactionNatures.map(n => n === oldStaff?.name ? staff.name : n);
      if (!updatedNatures.includes(staff.name)) updatedNatures.push(staff.name);

      const oldLedgerName = `Wages Payable - ${oldStaff?.name}`;
      const newLedgerName = `Wages Payable - ${staff.name}`;
      const updatedLiabilities = prev.liabilities.map(l => l.name === oldLedgerName ? { ...l, name: newLedgerName } : l);

      return { 
        ...prev, 
        staff: (prev.staff || []).map(s => s.id === staff.id ? staff : s),
        transactionNatures: updatedNatures,
        liabilities: updatedLiabilities
      };
    });
  };

  const deleteStaff = (id: string) => {
    setState(prev => {
      const staff = prev.staff.find(s => s.id === id);
      const ledgerName = `Wages Payable - ${staff?.name}`;
      return { 
        ...prev, 
        staff: (prev.staff || []).filter(s => s.id !== id),
        liabilities: prev.liabilities.filter(l => l.name !== ledgerName)
      };
    });
  };

  const logStaffAttendance = (staffId: string, entry: StaffAttendance | { date: string, status: 'None' }) => {
    setState(prev => ({
      ...prev,
      staff: (prev.staff || []).map(s => {
        if (s.id !== staffId) return s;
        const newAttendance = (s.attendance || []).filter(a => a.date !== entry.date);
        if (entry.status !== 'None') {
          newAttendance.push(entry as StaffAttendance);
        }
        return { ...s, attendance: newAttendance };
      })
    }));
  };

  const filteredState = useMemo(() => {
    if (activeMemberIds.includes('all')) return state;
    const filterIds = activeMemberIds.length > 0 ? activeMemberIds : [undefined, ''];
    const filterFn = (item: any) => filterIds.includes(item.ownerId || '');
    return {
      ...state,
      banks: state.banks.filter(filterFn),
      cards: state.cards.filter(filterFn),
      wallets: state.wallets.filter(filterFn),
      transactions: state.transactions.filter(filterFn),
    };
  }, [state, activeMemberIds]);

  return (
    <FinanceContext.Provider value={{ 
      state, filteredState, isAuthenticated, activeMemberIds, isCloudSyncing, connectionStatus, isNavHidden, setIsNavHidden, setActiveMemberIds, setAuthenticated, updateProfile: (p) => setState(prev => ({...prev, profile: {...p, isBoarded: true}})), 
      addFamilyMember, removeFamilyMember: (id) => setState(prev => ({...prev, profile: {...prev.profile, familyMembers: prev.profile.familyMembers.filter(m => m.id !== id)}})), 
      updateMemberPermissions, verifyFamilyMember, approveTransaction, approveTransactions, rejectTransaction, rejectTransactions,
      addBank: (b) => setState(prev => ({...prev, banks: [...prev.banks, b]})), updateBank: (b) => setState(prev => ({...prev, banks: prev.banks.map(x => x.id === b.id ? b : x)})), deleteBank: (id) => setState(prev => ({...prev, banks: prev.banks.filter(b => b.id !== id)})),
      addCard: (c) => setState(prev => ({...prev, cards: [...prev.cards, c]})), updateCard: (c) => setState(prev => ({...prev, cards: prev.cards.map(x => x.id === c.id ? c : x)})), deleteCard: (id) => setState(prev => ({...prev, cards: prev.cards.filter(c => c.id !== id)})),
      addWallet: (w) => setState(prev => ({...prev, wallets: [...prev.wallets, w]})), updateWallet: (w) => setState(prev => ({...prev, wallets: prev.wallets.map(x => x.id === w.id ? w : x)})), deleteWallet: (id) => setState(prev => ({...prev, wallets: prev.wallets.filter(w => w.id !== id)})),
      addIncome: () => {}, addExpense: () => {}, addAsset: (a) => setState(prev => ({...prev, assets: [...prev.assets, a]})), updateAsset: (a) => setState(prev => ({...prev, assets: prev.assets.map(x => x.id === a.id ? a : x)})), deleteAsset: (id) => setState(prev => ({...prev, assets: prev.assets.filter(a => a.id !== id)})),
      addLiability: (l) => setState(prev => ({...prev, liabilities: [...prev.liabilities, l]})), updateLiability: (l) => setState(prev => ({...prev, liabilities: prev.liabilities.map(x => x.id === l.id ? l : x)})), deleteLiability: (id) => setState(prev => ({...prev, liabilities: prev.liabilities.filter(l => l.id !== id)})),
      addTransaction, updateTransaction: () => {}, deleteTransaction: (id) => setState(prev => ({...prev, transactions: prev.transactions.filter(t => t.id !== id)})),
      addBudget: (b) => {
        setState(prev => ({ ...prev, budgets: [...prev.budgets, b] }));
        addTransactionNature(b.category);
      }, 
      updateBudget: (b) => setState(prev => ({...prev, budgets: prev.budgets.map(x => x.id === b.id ? b : x)})), 
      deleteBudget: (id) => setState(prev => ({...prev, budgets: prev.budgets.filter(b => b.id !== id)})),
      addTransactionNature, deleteTransactionNature, 
      addStaff, updateStaff, deleteStaff, logStaffAttendance,
      clearNotifications: () => {}, markNotificationRead: () => {}, 
      simulateSync, resetBoarding, loadStateFromCloud, verifyConnection, importState: () => {}, updateMonitoredApps: () => {}, simulateIncomingRequest, handleFamilyRequest, uploadToDrive
    }}>
      {children}
    </FinanceContext.Provider>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';
import { MonitoredApp, MemberPermissions } from '../types';

// Declare Google Types for TypeScript
declare global {
  interface Window {
    google: any;
    gapi: any;
  }
}

// Configuration Constants - Using Vite's define replacement
const GOOGLE_CLIENT_ID = process.env.GOOGLE_CLIENT_ID || ''; 
const GOOGLE_API_KEY = process.env.GOOGLE_API_KEY || '';

const Profile: React.FC = () => {
  const { state, updateProfile, addFamilyMember, removeFamilyMember, updateMemberPermissions, verifyFamilyMember, simulateIncomingRequest, connectionStatus, verifyConnection } = useFinance();
  const profile = state.profile;
  const [showAddMember, setShowAddMember] = useState(false);
  const [showPermissions, setShowPermissions] = useState<string | null>(null);
  const [newMember, setNewMember] = useState({ name: '', relation: 'Spouse', mobile: '' });

  // Google Drive State
  const [isConnecting, setIsConnecting] = useState(false);
  const [showFolderSelection, setShowFolderSelection] = useState(false);
  const [availableFolders, setAvailableFolders] = useState<any[]>([]);
  const [tokenClient, setTokenClient] = useState<any>(null);
  const [scriptsLoaded, setScriptsLoaded] = useState(false);

  // Initialize Google Scripts with polling to ensure they are loaded
  useEffect(() => {
    const checkScripts = () => {
      if (window.gapi && window.google) {
        setScriptsLoaded(true);
        if (GOOGLE_CLIENT_ID && GOOGLE_API_KEY) {
          initializeGapiClient();
        }
        return true;
      }
      return false;
    };

    if (!checkScripts()) {
      const intervalId = setInterval(() => {
        if (checkScripts()) {
          clearInterval(intervalId);
        }
      }, 500);
      return () => clearInterval(intervalId);
    }
  }, []);

  const initializeGapiClient = () => {
    if (!window.gapi || !window.google) return;

    try {
      // Load GAPI Client
      window.gapi.load('client', async () => {
        await window.gapi.client.init({
          apiKey: GOOGLE_API_KEY,
          discoveryDocs: ['https://www.googleapis.com/discovery/v1/apis/drive/v3/rest'],
        });
      });

      // Init Token Client
      const client = window.google.accounts.oauth2.initTokenClient({
        client_id: GOOGLE_CLIENT_ID,
        scope: 'https://www.googleapis.com/auth/drive.file https://www.googleapis.com/auth/drive.readonly',
        callback: async (response: any) => {
          if (response.error !== undefined) {
            console.error(response);
            return;
          }
          await listDriveFolders();
        },
      });
      setTokenClient(client);
    } catch (e) {
      console.error("Error initializing Google API:", e);
    }
  };

  const listDriveFolders = async () => {
    try {
      setIsConnecting(true);
      const response = await window.gapi.client.drive.files.list({
        'pageSize': 10,
        'fields': "nextPageToken, files(id, name)",
        'q': "mimeType = 'application/vnd.google-apps.folder' and trashed = false"
      });
      const files = response.result.files;
      if (files && files.length > 0) {
         setAvailableFolders(files);
         setShowFolderSelection(true);
      } else {
         alert('No folders found in Drive. Please create one.');
      }
    } catch (err) {
      console.error('Error listing folders', err);
      alert('Failed to fetch Drive folders. Ensure API Key restrictions allow Drive API and OAuth consent is configured.');
    } finally {
      setIsConnecting(false);
    }
  };

  const handleAddMember = async (e: React.FormEvent) => {
    e.preventDefault();
    if (newMember.name && newMember.mobile) {
      await addFamilyMember({
        id: Math.random().toString(36).substr(2, 9),
        name: newMember.name,
        relation: newMember.relation,
        mobileNumber: newMember.mobile,
        status: 'pending_invitation',
        permissions: { viewDashboard: true, viewStatements: true, viewBudget: true, viewTransactions: true, viewCalendar: true, viewAccounts: true, canCreateTransactions: true }
      });
      setNewMember({ name: '', relation: 'Spouse', mobile: '' });
      setShowAddMember(false);
    }
  };

  const handleDeleteMember = (id: string, name: string) => {
    if (confirm(`Are you sure you want to remove ${name} from your family vault? This will revoke all their access.`)) {
      removeFamilyMember(id);
    }
  };

  const handleGoogleLogin = () => {
    if (!GOOGLE_CLIENT_ID || !GOOGLE_API_KEY) {
      alert("Configuration Missing: Please set GOOGLE_CLIENT_ID and GOOGLE_API_KEY in your environment variables (.env).");
      return;
    }

    if (!scriptsLoaded) {
      alert("Google Services are still loading. Please try again in a moment.");
      return;
    }

    if (!tokenClient) {
      initializeGapiClient();
      setTimeout(() => {
         if (tokenClient) tokenClient.requestAccessToken({ prompt: 'consent' });
      }, 1000);
    } else {
      tokenClient.requestAccessToken({ prompt: 'consent' });
    }
  };

  const confirmFolderSelection = (folderId: string, folderName: string) => {
    updateProfile({
      ...profile,
      googleDriveConfig: {
        ...profile.googleDriveConfig!,
        isConnected: true,
        linkedEmail: 'Connected Account',
        folderId: folderId,
        folderName: folderName,
        clientId: GOOGLE_CLIENT_ID,
        apiKey: GOOGLE_API_KEY
      }
    });
    setShowFolderSelection(false);
  };

  const handleDisconnect = () => {
    if (window.confirm("Disconnect Google Drive? This will stop evidence synchronization.")) {
      updateProfile({
        ...profile,
        googleDriveConfig: {
          isConnected: false,
          linkedEmail: '',
          folderId: '',
          folderName: '',
        }
      });
    }
  };

  const togglePermission = (id: string, key: keyof MemberPermissions) => {
    const member = profile.familyMembers.find(m => m.id === id);
    if (member) {
      updateMemberPermissions(id, { ...member.permissions, [key]: !member.permissions[key] });
    }
  };

  return (
    <div className="space-y-6 md:space-y-10 max-w-4xl animate-in fade-in duration-500 pb-20 px-3 md:px-0 mx-auto">
      <div className="bg-white md:rounded-[3rem] border border-slate-200 shadow-sm overflow-hidden">
        <div className="h-40 bg-indigo-600 p-8 flex items-end relative">
           <div className="absolute top-0 right-0 p-8 text-8xl font-black text-white/10 tracking-tighter uppercase">MF</div>
           <div className="w-24 h-24 bg-white p-1 translate-y-12 z-10 shadow-xl rounded-[2rem]">
               <div className="w-full h-full bg-slate-100 flex items-center justify-center text-4xl font-black text-indigo-600 rounded-2xl uppercase">{profile?.name?.charAt(0) || '?'}</div>
           </div>
        </div>
        <div className="px-8 pt-16 pb-10">
          <div className="flex justify-between items-start mb-8">
            <div>
              <h3 className="text-3xl font-black text-slate-800 tracking-tight uppercase">{profile?.name}</h3>
              <p className="text-xs font-black text-indigo-500 uppercase tracking-widest mt-1">{profile?.designation}</p>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-4 p-6 bg-slate-50 border border-slate-100 rounded-[2rem]">
             <div><p className="text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">Local Identity</p><p className="text-xs font-black text-slate-800 uppercase">{profile?.city}, {profile?.country}</p></div>
             <div><p className="text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">Audit Currency</p><p className="text-xs font-black text-indigo-600 uppercase">{profile?.currency}</p></div>
          </div>
        </div>
      </div>

      {/* Cloud Vault Diagnostics */}
      <div className="bg-white p-8 rounded-[3rem] border border-slate-200 shadow-sm relative overflow-hidden">
         <div className="absolute top-0 right-0 p-4 text-6xl opacity-5 font-black text-indigo-600">CLOUD</div>
         <div className="flex justify-between items-center mb-6 relative z-10">
           <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-[0.2em]">Cloud Vault Connectivity</h4>
           <div className="flex items-center gap-2">
             {connectionStatus === 'online' && <span className="px-3 py-1 bg-emerald-50 text-emerald-600 rounded-lg text-[8px] font-black uppercase tracking-widest border border-emerald-100">● Database Live</span>}
             {connectionStatus === 'offline' && <span className="px-3 py-1 bg-rose-50 text-rose-600 rounded-lg text-[8px] font-black uppercase tracking-widest border border-rose-100 animate-pulse">● Database Paused</span>}
             {connectionStatus === 'checking' && <span className="px-3 py-1 bg-slate-50 text-slate-400 rounded-lg text-[8px] font-black uppercase tracking-widest border border-slate-100 animate-pulse">● Checking...</span>}
           </div>
         </div>

         <div className="relative z-10 space-y-4">
            {connectionStatus === 'offline' ? (
              <div className="p-6 bg-rose-50 border border-rose-100 rounded-2xl space-y-4">
                 <p className="text-[10px] font-black text-rose-900 uppercase tracking-tight">Sync Failure Detected</p>
                 <p className="text-[9px] font-medium text-rose-700/80 leading-relaxed uppercase">
                    Your Supabase project may have been automatically paused due to inactivity. 
                    Please log in to your <strong>Supabase Dashboard</strong> and click <strong>"Restore Project"</strong> to resume syncing.
                 </p>
                 <div className="flex gap-2">
                   <a href="https://supabase.com/dashboard" target="_blank" rel="noreferrer" className="px-4 py-2 bg-rose-600 text-white text-[8px] font-black uppercase rounded-xl shadow-lg">Open Dashboard</a>
                   <button onClick={() => verifyConnection()} className="px-4 py-2 bg-white text-rose-600 border border-rose-200 text-[8px] font-black uppercase rounded-xl">Ping Again</button>
                 </div>
              </div>
            ) : (
              <div className="flex items-center justify-between">
                <p className="text-[10px] text-slate-500 uppercase tracking-widest">Global Vault Synchronization is Active.</p>
                <button onClick={() => verifyConnection()} className="px-4 py-2 bg-slate-50 border border-slate-100 text-[8px] font-black uppercase rounded-xl hover:bg-slate-100 transition-colors">Test Link</button>
              </div>
            )}
         </div>
      </div>

      {/* Google Drive Configuration Card (Standard Login) */}
      <div className="bg-white p-8 rounded-[3rem] border border-slate-200 shadow-sm relative overflow-hidden group">
         <div className="absolute top-0 right-0 p-4 text-6xl opacity-5 font-black text-indigo-600">DRIVE</div>

         <div className="flex justify-between items-center mb-6 relative z-10">
           <div className="flex items-center gap-2">
              <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-[0.2em]">Google Drive Integration</h4>
           </div>
           {profile.googleDriveConfig?.isConnected ? (
             <span className="px-3 py-1 bg-emerald-50 text-emerald-600 rounded-lg text-[8px] font-black uppercase tracking-widest border border-emerald-100">● Logged In</span>
           ) : (
             <span className="px-3 py-1 bg-slate-100 text-slate-500 rounded-lg text-[8px] font-black uppercase tracking-widest">○ Not Connected</span>
           )}
         </div>

         <div className="relative z-10">
            {!profile.googleDriveConfig?.isConnected ? (
               <div className="flex flex-col items-start gap-6">
                 <p className="text-[10px] font-medium text-slate-500 leading-relaxed max-w-lg">
                    Login to authorize MyFin to save transaction receipts and evidence to your personal Google Drive vault.
                 </p>
                 <button 
                   onClick={handleGoogleLogin} 
                   disabled={isConnecting}
                   className="flex items-center gap-3 px-6 py-4 bg-white border border-slate-200 rounded-2xl shadow-lg hover:shadow-xl hover:bg-slate-50 transition-all active:scale-95 disabled:opacity-70 disabled:pointer-events-none"
                 >
                    {isConnecting ? (
                      <>
                        <div className="w-5 h-5 border-2 border-slate-300 border-t-indigo-600 rounded-full animate-spin"></div>
                        <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest">Contacting Google...</span>
                      </>
                    ) : (
                      <>
                        <img src="https://upload.wikimedia.org/wikipedia/commons/1/12/Google_Drive_icon_%282020%29.svg" alt="Drive" className="w-5 h-5" />
                        <span className="text-[10px] font-black text-slate-700 uppercase tracking-widest">Login with Google</span>
                      </>
                    )}
                 </button>
               </div>
            ) : (
               <div className="space-y-6">
                 <div className="p-6 bg-slate-50 border border-slate-100 rounded-[2rem] flex items-center justify-between">
                    <div className="flex items-center gap-4">
                       <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center shadow-sm">
                          <img src="https://lh3.googleusercontent.com/a/default-user=s100" alt="User" className="w-8 h-8 rounded-full" />
                       </div>
                       <div>
                          <p className="text-xs font-black text-slate-800 uppercase tracking-tight">{profile.googleDriveConfig.linkedEmail}</p>
                          <p className="text-[8px] font-bold text-emerald-500 uppercase tracking-widest mt-0.5">● Session Active</p>
                       </div>
                    </div>
                    <button 
                      onClick={handleDisconnect}
                      className="px-4 py-2 bg-white border border-slate-200 text-rose-500 text-[8px] font-black uppercase rounded-xl hover:bg-rose-50 hover:border-rose-100 transition-colors"
                    >
                      Logout
                    </button>
                 </div>

                 <div className="flex items-center gap-4 px-2">
                    <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center text-lg">📂</div>
                    <div>
                       <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Target Folder</p>
                       <p className="text-[10px] font-black text-slate-800 uppercase">{profile.googleDriveConfig.folderName}</p>
                    </div>
                 </div>
               </div>
            )}
         </div>
      </div>

      <div className="bg-white p-8 rounded-[3rem] border border-slate-200 shadow-sm">
        <div className="flex justify-between items-center mb-8">
          <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-[0.2em]">Family Vault Access</h4>
          <button onClick={() => setShowAddMember(true)} className="px-6 py-3 bg-indigo-600 text-white rounded-2xl text-[9px] font-black uppercase tracking-widest shadow-xl">+ Invite Member</button>
        </div>
        <div className="space-y-4">
          {profile?.familyMembers.map(member => (
            <div key={member.id} className="p-6 bg-slate-50 border border-slate-100 rounded-[2rem] flex flex-col md:flex-row md:items-center justify-between gap-6 group">
              <div className="flex items-center gap-5">
                <div className={`w-12 h-12 flex items-center justify-center font-black rounded-2xl border border-slate-200 uppercase text-xl ${member.status === 'verified' ? 'bg-indigo-600 text-white' : 'bg-white text-slate-300'}`}>
                   {member.status === 'verified' ? '✓' : '⏳'}
                </div>
                <div>
                  <p className="text-sm font-black text-slate-800 uppercase">{member.name}</p>
                  <p className="text-[8px] text-slate-400 font-bold uppercase tracking-widest">{member.relation} • {member.status === 'verified' ? 'Verified Session' : 'Pending Verification'}</p>
                </div>
              </div>
              <div className="flex items-center gap-3">
                 {member.status === 'pending_invitation' && (
                   <button onClick={() => verifyFamilyMember(member.id)} className="px-4 py-2 bg-emerald-50 text-emerald-600 border border-emerald-100 text-[8px] font-black uppercase rounded-xl">Simulate Accept</button>
                 )}
                 <button onClick={() => setShowPermissions(member.id)} className="px-4 py-2 bg-white border border-slate-200 text-slate-600 text-[8px] font-black uppercase rounded-xl hover:bg-slate-100">Manage Access</button>
                 <button onClick={() => handleDeleteMember(member.id, member.name)} className="px-4 py-2 bg-white border border-slate-200 text-rose-500 text-[8px] font-black uppercase rounded-xl hover:bg-rose-50 hover:border-rose-100">Remove</button>
              </div>
            </div>
          ))}
          {profile?.familyMembers.length === 0 && <p className="py-12 text-center text-slate-300 italic text-[10px] uppercase tracking-widest">No participant links active</p>}
        </div>
      </div>

      {/* Developer / Demo Tools for Request Simulation */}
      <div className="bg-slate-900 text-white p-8 rounded-[3rem] shadow-xl relative overflow-hidden">
         <div className="relative z-10">
           <h4 className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.2em] mb-4">Simulation Zone</h4>
           <div className="flex flex-col md:flex-row justify-between items-center gap-6">
             <div className="space-y-1">
               <p className="text-lg font-black uppercase tracking-tight">Test Incoming Requests</p>
               <p className="text-[9px] text-slate-400 uppercase tracking-widest">Simulate another user requesting to link with your vault.</p>
             </div>
             <button 
               onClick={() => simulateIncomingRequest('Demo User', '9999999999', 'Partner')}
               className="px-6 py-4 bg-white/10 hover:bg-white/20 rounded-2xl text-[9px] font-black uppercase tracking-widest border border-white/10 transition-colors"
             >
               Trigger Remote Request
             </button>
           </div>
         </div>
      </div>

      {/* Folder Selection Modal (Real Data) */}
      {showFolderSelection && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4">
           <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 shadow-2xl animate-in zoom-in-95 duration-200">
              <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight mb-2">Select Destination Folder</h3>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mb-6">Choose a folder to store receipts</p>

              <div className="space-y-3 mb-8 max-h-[300px] overflow-y-auto custom-scrollbar">
                 {availableFolders.map(folder => (
                   <button 
                     key={folder.id}
                     onClick={() => confirmFolderSelection(folder.id, folder.name)}
                     className="w-full flex items-center gap-4 p-4 bg-slate-50 border border-slate-100 rounded-2xl hover:bg-indigo-50 hover:border-indigo-100 transition-all group text-left"
                   >
                      <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center shadow-sm text-lg">📂</div>
                      <div>
                         <p className="text-xs font-black text-slate-700 uppercase group-hover:text-indigo-600 truncate max-w-[200px]">{folder.name}</p>
                         <p className="text-[8px] font-bold text-slate-400 uppercase">ID: {folder.id.substr(0, 8)}...</p>
                      </div>
                   </button>
                 ))}
                 {availableFolders.length === 0 && <p className="text-center text-xs p-4">No folders found.</p>}
              </div>

              <button onClick={() => setShowFolderSelection(false)} className="w-full py-4 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-2xl">Cancel</button>
           </div>
        </div>
      )}

      {showPermissions && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4">
           <div className="bg-white w-full max-lg rounded-[3rem] p-10 shadow-2xl animate-in zoom-in-95 duration-200">
              <div className="flex justify-between items-center mb-10">
                 <div>
                   <h4 className="text-xl font-black text-slate-800 uppercase tracking-tighter">Permission Matrix</h4>
                   <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest mt-1">Audit Constraints for {profile.familyMembers.find(m => m.id === showPermissions)?.name}</p>
                 </div>
                 <button onClick={() => setShowPermissions(null)} className="text-slate-200 hover:text-slate-800 text-2xl font-black transition-colors">✕</button>
              </div>

              <div className="space-y-3">
                {[
                  { key: 'viewDashboard', label: 'Dashboard Access', desc: 'Summary metrics & live burn rates' },
                  { key: 'viewStatements', label: 'Audit Statements', desc: 'P&L and Balance Sheet details' },
                  { key: 'viewTransactions', label: 'History Ledger', desc: 'Full transaction timeline' },
                  { key: 'viewBudget', label: 'Budget Architect', desc: 'Target allocation controls' },
                  { key: 'viewCalendar', label: 'Fiscal Sentinel', desc: 'Due date pressure analysis' },
                  { key: 'viewAccounts', label: 'Instrument Vault', desc: 'Bank & Credit Card configurations' },
                  { key: 'canCreateTransactions', label: 'Write Access', desc: 'Ability to record new transactions' }
                ].map((perm) => (
                  <div key={perm.key} className="flex items-center justify-between p-4 bg-slate-50 border border-slate-100 rounded-2xl group hover:border-indigo-200 transition-all cursor-pointer" onClick={() => togglePermission(showPermissions, perm.key as keyof MemberPermissions)}>
                    <div>
                      <p className="text-[10px] font-black text-slate-800 uppercase tracking-tight">{perm.label}</p>
                      <p className="text-[8px] text-slate-400 font-medium">{perm.desc}</p>
                    </div>
                    <div className={`w-12 h-7 rounded-full relative transition-all ${profile.familyMembers.find(m => m.id === showPermissions)?.permissions[perm.key as keyof MemberPermissions] ? 'bg-indigo-600' : 'bg-slate-200'}`}>
                      <div className={`absolute top-1 w-5 h-5 bg-white rounded-full shadow-sm transition-all ${profile.familyMembers.find(m => m.id === showPermissions)?.permissions[perm.key as keyof MemberPermissions] ? 'left-6' : 'left-1'}`}></div>
                    </div>
                  </div>
                ))}
              </div>

              <button onClick={() => setShowPermissions(null)} className="w-full mt-10 py-5 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-slate-200 active:scale-95 transition-all">Apply Constraints</button>
           </div>
        </div>
      )}

      {showAddMember && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
           <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-10 shadow-2xl animate-in zoom-in duration-200">
             <h4 className="text-xl font-black text-slate-800 uppercase tracking-tight mb-10">Link Participant</h4>
             <form onSubmit={handleAddMember} className="space-y-6">
                <input required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs uppercase" value={newMember.name} onChange={e => setNewMember({...newMember, name: e.target.value})} placeholder="Legal Name" />
                <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-black text-xs outline-none cursor-pointer" value={newMember.relation} onChange={e => setNewMember({...newMember, relation: e.target.value})}>
                  <option>Spouse</option><option>Child</option><option>Parent</option><option>Partner</option>
                </select>
                <input required type="tel" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs" value={newMember.mobile} onChange={e => setNewMember({...newMember, mobile: e.target.value.replace(/\D/g, '')})} placeholder="Identification Key (Mobile)" />
                <div className="flex gap-4 pt-6">
                  <button type="button" onClick={() => setShowAddMember(false)} className="flex-1 px-4 py-4 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-2xl">Abort</button>
                  <button type="submit" className="flex-[2] px-4 py-4 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl">Send Invite</button>
                </div>
             </form>
           </div>
        </div>
      )}
    </div>
  );
};

export default Profile;
